/* ─────────────── REAL REPOST PERSISTENCE ───────────────
   Repost used to be a fake toast — it never wrote anything anywhere, so a
   reposted video never showed up on the reposting user's profile and the
   repost count never moved. This is the real, toggleable version:
   - `repostedBy` (array on the video doc) — who has reposted it, used both to
     render the reposted post inside that user's own profile grid and to know
     whether to show "Repost" or "Remove repost" next time.
   - `reposts` (counter) — public repost count.
   - `repostsMeta.{uid}` (per-user timestamp) — lets the profile sort a user's
     reposts by when *they* reposted it, not by the original post date.
   Reposting also counts as a share, same as TikTok/Twitter. */
const toggleRepost = async (video, currentUser) => {
  if (!video?.id || !currentUser?.id) return { reposted: false };
  const alreadyReposted = (video.repostedBy || []).includes(currentUser.id);
  const ref = doc(db, 'videos', video.id);
  if (alreadyReposted) {
    await updateDoc(ref, {
      repostedBy: arrayRemove(currentUser.id),
      reposts: increment(-1),
      [`repostsMeta.${currentUser.id}`]: deleteField(),
    });
    return { reposted: false };
  }
  await updateDoc(ref, {
    repostedBy: arrayUnion(currentUser.id),
    reposts: increment(1),
    shares: increment(1),
    [`repostsMeta.${currentUser.id}`]: serverTimestamp(),
  });
  return { reposted: true };
};

/* ─────────── UNIVERSAL SHARE (single source of truth, used everywhere) ───────────
   Previously every share entry point in the app — the video ShareSheet, a post's
   "…" options menu, your own profile header, someone else's profile modal, and the
   QR code page — each hand-rolled its own slightly different version of "try
   navigator.share, else copy the link", and one of them (QR page) had no fallback
   at all, so it silently did nothing on desktop browsers. They all now call this
   one function, so sharing behaves identically everywhere in the app.
   It also goes one step further than a bare link, the way Instagram/TikTok/WhatsApp
   do: when the browser supports the Web Share API's file-attachment (Level 2) and
   real media is available, it fetches the actual photo/video and attaches it to the
   native share sheet, instead of only ever sharing a URL. */
const shareToDevice = async ({ url, title, text, mediaUrl, mediaType, showToast, onShared, copiedMessage = 'Link copied!' }) => {
  const canNativeShare = typeof navigator !== 'undefined' && !!navigator.share;
  if (canNativeShare) {
    if (mediaUrl && navigator.canShare) {
      try {
        const res = await fetch(mediaUrl, { mode: 'cors' });
        const blob = await res.blob();
        const isVideo = (mediaType || '').startsWith('video');
        const file = new File([blob], `infinity-share.${isVideo ? 'mp4' : 'jpg'}`, { type: blob.type || (isVideo ? 'video/mp4' : 'image/jpeg') });
        if (navigator.canShare({ files: [file] })) {
          await navigator.share({ title, text, files: [file] });
          onShared?.();
          return true;
        }
      } catch {
        // Cross-origin media without CORS headers, or an unsupported file type —
        // fall through to a link-only native share below instead of failing outright.
      }
    }
    try {
      await navigator.share({ title, text, url });
      onShared?.();
      return true;
    } catch (e) {
      if (e?.name === 'AbortError') return false; // user closed the native sheet — not an error
      // Any other failure (e.g. share() rejected for an unsupported combination of
      // fields) falls through to the clipboard fallback below.
    }
  }
  try {
    await navigator.clipboard.writeText(url);
    showToast?.(copiedMessage, 'success');
    onShared?.();
    return true;
  } catch {
    showToast?.('Could not share', 'error');
    return false;
  }
};

const ShareIconBtn = ({ bg, fg='#fff', label, onClick, children }) => (
  <button onClick={onClick} style={{ background:'none', border:'none', cursor:'pointer', display:'flex', flexDirection:'column', alignItems:'center', gap:7, width:60 }}>
    <div style={{ width:52, height:52, borderRadius:'50%', background:bg, display:'flex', alignItems:'center', justifyContent:'center', color:fg, flexShrink:0 }}>{children}</div>
    <span style={{ color:COLORS.textSecondary, fontSize:11, fontWeight:600, textAlign:'center' }}>{label}</span>
  </button>
);

const ShareSheet = ({ video, currentUser, onClose, showToast }) => {
  const shareUrl = `https://infinity-now.vercel.app/video/${video?.id}`;
  const shareText = video?.description || `Check out @${video?.username || 'this'} on Infinity`;
  const [reposted, setReposted] = useState((video?.repostedBy || []).includes(currentUser?.id));
  const [saved, setSaved] = useState((video?.savedBy || []).includes(currentUser?.id));
  const [showReportSheet, setShowReportSheet] = useState(false);

  // Every share action below writes to the post's actual share count — the
  // "shares" number shown in the feed now really moves.
  const recordShare = () => {
    if (!video?.id) return;
    updateDoc(doc(db, 'videos', video.id), { shares: increment(1) }).catch(() => {});
  };
  const copyLink = async () => { try { await navigator.clipboard.writeText(shareUrl); recordShare(); showToast?.('Link copied!', 'success'); } catch { showToast?.('Copy failed', 'error'); } };

  // ── REAL SHARE, NOT A PRE-CODED APP LIST ────────────────────────────────
  // The old grid hard-coded 10 specific apps (WhatsApp, Telegram, Facebook…)
  // regardless of what's actually installed on the device. This instead hands
  // off to the browser/OS's own native share sheet (Web Share API), which
  // lists whatever the user genuinely has installed — Instagram, Messages,
  // AirDrop, WhatsApp, or anything else — and lets the OS attach the link.
  // navigator.share isn't available on every browser (mainly desktop), so we
  // fall back to copying the link when it's missing. When the post has real
  // media, the actual photo/video is attached to the share (see shareToDevice),
  // not just a link — matching how other apps' share sheets behave.
  const nativeShareSupported = typeof navigator !== 'undefined' && !!navigator.share;
  const shareViaDevice = () => shareToDevice({
    url: shareUrl,
    title: 'Infinity',
    text: shareText,
    mediaUrl: video?.videoUrl || video?.images?.[0],
    mediaType: video?.mediaType,
    showToast,
    onShared: recordShare,
  });

  const doToggleRepost = async () => {
    if (!currentUser?.id) { showToast?.('Log in to repost', 'error'); return; }
    const next = !reposted;
    setReposted(next); // optimistic
    try {
      const { reposted: confirmed } = await toggleRepost(video, currentUser);
      setReposted(confirmed);
      showToast?.(confirmed ? 'Reposted to your profile' : 'Repost removed', 'success');
    } catch (e) {
      setReposted(!next); // revert on failure
      showToast?.('Could not update repost', 'error');
    }
  };

  const doToggleSave = async () => {
    if (!video?.id || !currentUser?.id) return;
    const next = !saved;
    setSaved(next);
    try {
      await updateDoc(doc(db, 'videos', video.id), { savedBy: next ? arrayUnion(currentUser.id) : arrayRemove(currentUser.id) });
      showToast?.(next ? 'Saved' : 'Removed from saved', 'success');
    } catch {
      setSaved(!next);
      showToast?.('Could not update save', 'error');
    }
  };

  const doDownload = async () => {
    if (!video?.videoUrl) { showToast?.('Nothing to download', 'error'); return; }
    try {
      showToast?.('Downloading…', 'info');
      const res = await fetch(video.videoUrl, { mode: 'cors' });
      const blob = await res.blob();
      const blobUrl = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = blobUrl;
      a.download = `infinity-${video.id || 'post'}`;
      document.body.appendChild(a); a.click(); a.remove();
      URL.revokeObjectURL(blobUrl);
      recordShare();
    } catch {
      // Cross-origin media without CORS headers can't be fetched into a blob —
      // opening it directly still lets the user save it manually.
      window.open(video.videoUrl, '_blank');
    }
  };

  const doNotInterested = async () => {
    if (!currentUser?.id || !video?.id) return;
    try {
      await updateDoc(doc(db, 'users', currentUser.id), { notInterested: arrayUnion(video.id) });
      showToast?.("Got it — we'll show you less like this", 'success');
    } catch {
      showToast?.('Could not save your preference', 'error');
    }
  };

  const submitVideoReport = async (reason) => {
    try {
      await submitReport('video', video?.id, currentUser.id, {
        videoId: video?.id || null,
        reporterUsername: currentUser?.username || currentUser?.fullName || null,
        reason,
        videoUsername: video?.username || null,
        videoUserId: video?.userId || null,
        videoCaption: video?.description || video?.caption || null,
        videoThumbUrl: video?.thumbUrl || video?.thumbnailUrl || video?.url || null,
      });
      showToast?.('Post reported — thanks for letting us know', 'success');
    } catch (e) {
      showToast?.(e.message || 'Could not submit report', e.duplicate ? 'info' : 'error');
    }
    setShowReportSheet(false);
    onClose();
  };

  // Real in-app actions — everything here actually persists to Firestore.
  // Duet/Stitch were removed rather than faked: there's no real video-editing
  // pipeline in this codebase to back them, and a toast that lies about
  // "opening an editor" that doesn't exist isn't an improvement over nothing.
  const moreActions = [
    { label: reposted ? 'Remove repost' : 'Repost', action: doToggleRepost,
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={reposted?COLORS.brand:'currentColor'} strokeWidth="2"><path d="M17 1l4 4-4 4"/><path d="M3 11V9a4 4 0 014-4h14"/><path d="M7 23l-4-4 4-4"/><path d="M21 13v2a4 4 0 01-4 4H3"/></svg>) },
    { label: saved ? 'Saved' : 'Save', action: doToggleSave,
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill={saved?COLORS.brand:'none'} stroke={saved?COLORS.brand:'currentColor'} strokeWidth="2"><path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/></svg>) },
    { label:'Download', action:doDownload,
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>) },
    { label:'Not interested', action:doNotInterested,
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17.94 17.94A10.94 10.94 0 0112 20c-7 0-11-8-11-8a21.6 21.6 0 015.06-6.06M9.9 4.24A10.4 10.4 0 0112 4c7 0 11 8 11 8a21.6 21.6 0 01-2.16 3.19"/><path d="M14.12 14.12a3 3 0 11-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>) },
    { label:'Copy link', action:copyLink,
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10 13a5 5 0 007.07 0l2.83-2.83a5 5 0 00-7.07-7.07l-1.5 1.5"/><path d="M14 11a5 5 0 00-7.07 0L4.1 13.83a5 5 0 007.07 7.07l1.5-1.5"/></svg>) },
    { label:'Report', action:()=>setShowReportSheet(true),
      icon:(<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 9v4M12 17h.01"/><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/></svg>) },
  ];

  return (
    <motion.div
      variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
      style={{ position:'fixed', inset:0, zIndex:Z.modal, background:'rgba(20,15,35,0.45)', display:'flex', alignItems:'flex-end' }} onClick={onClose}>
      <motion.div
        variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
        onClick={e=>e.stopPropagation()} style={{ width:'100%', maxHeight:'70vh', overflowY:'auto', background:COLORS.surface, borderTopLeftRadius:20, borderTopRightRadius:20, paddingBottom:'max(16px, env(safe-area-inset-bottom))' }}>
        {/* Drag handle + centered title, no back-arrow — matches TikTok's actual share sheet chrome */}
        <div style={{ display:'flex', justifyContent:'center', paddingTop:10 }}>
          <div style={{ width:36, height:4, borderRadius:2, background:COLORS.border }} />
        </div>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'center', position:'relative', padding:'10px 16px 4px' }}>
          <div style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:15 }}>Share</div>
          <button onClick={onClose} aria-label="Close" style={{ position:'absolute', right:12, top:6, background:'none', border:'none', color:COLORS.textTertiary, cursor:'pointer', padding:6, display:'flex' }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>

        {/* Real share — hands off to the device's own share sheet (whatever apps
            are actually installed), instead of a fixed, fake app roster. */}
        <div style={{ padding:'12px 16px 4px' }}>
          <motion.button whileTap={tapScale} onClick={shareViaDevice} style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:9, background:COLORS.gradient, border:'none', borderRadius:16, padding:'14px', color:'#fff', fontWeight:700, fontSize:14.5, cursor:'pointer' }}>
            <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>
            {nativeShareSupported ? 'Share via…' : 'Copy link to share'}
          </motion.button>
          {!nativeShareSupported && (
            <div style={{ color:COLORS.textTertiary, fontSize:11.5, textAlign:'center', marginTop:8 }}>
              Your browser doesn't support the native share sheet, so this copies the link instead.
            </div>
          )}
        </div>

        <div style={{ height:1, background:COLORS.border, margin:'14px 16px 16px' }} />

        <div style={{ display:'grid', gridTemplateColumns:'repeat(5, 1fr)', rowGap:18, padding:'0 10px 8px', justifyItems:'center' }}>
          {moreActions.map(o => <ShareIconBtn key={o.label} bg={COLORS.surfaceAlt} fg={COLORS.textPrimary} label={o.label} onClick={o.action}>{o.icon}</ShareIconBtn>)}
        </div>
      </motion.div>
      <AnimatePresence>{showReportSheet && (
        <ReportReasonSheet
          title="Report Post"
          onClose={()=>{ setShowReportSheet(false); onClose(); }}
          onSubmit={submitVideoReport}
        />
      )}</AnimatePresence>
    </motion.div>
  );
};

/* ─────────────── STICKER PICKER (v4) ─────────────── */
const StickerPicker = ({ onSelect, onClose }) => {
  const [activePack, setActivePack] = useState(0);
  return (
    <div style={{ background: '#1C1C24', borderRadius: 20, padding: 14, border: '1px solid rgba(255,255,255,0.08)' }}>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10, overflowX: 'auto' }}>
        {STICKER_PACKS.map((pack, i) => (
          <button key={pack.id} onClick={() => setActivePack(i)} style={{ background: i === activePack ? 'rgba(11,95,255,0.2)' : 'transparent', border: i === activePack ? '1px solid rgba(11,95,255,0.4)' : '1px solid transparent', borderRadius: 20, padding: '4px 12px', color: i === activePack ? COLORS.brand : 'rgba(255,255,255,0.4)', fontSize: 12, cursor: 'pointer', flexShrink: 0 }}>
            {pack.name}
          </button>
        ))}
      </div>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
        {STICKER_PACKS[activePack].stickers.map(s => (
          <button key={s} onClick={() => onSelect(s)} aria-label="Send sticker" style={{ background: 'none', border: 'none', fontSize: 28, cursor: 'pointer', padding: 4, borderRadius: 8, transition: 'transform 0.1s' }}
            onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.3)'}
            onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
          >{s}</button>
        ))}
      </div>
    </div>
  );
};

/* ─────────────── TRENDING HASHTAGS COMPONENT (v4) ─────────────── */
const TrendingHashtags = ({ onSearch }) => (
  <div style={{ padding: '10px 0', overflowX: 'auto', display: 'flex', gap: 8 }}>
    {TRENDING_HASHTAGS.map(tag => (
      <button key={tag} onClick={() => onSearch?.(tag)} style={{ background: 'rgba(11,95,255,0.1)', border: '1px solid rgba(11,95,255,0.2)', borderRadius: 20, padding: '6px 14px', color: COLORS.brand, fontSize: 12, fontWeight: 700, cursor: 'pointer', flexShrink: 0 }}>
        {tag}
      </button>
    ))}
  </div>
);

/* ─────────────── GROUP CALL (real WebRTC mesh — replaces the old call UI mockup) ───────────────
   Previously "Group Call" just opened an overlay with static avatars and buttons that only fired
   showToast('Muted') / showToast('Camera toggled') — there was never any getUserMedia, any
   RTCPeerConnection, any signaling at all, so nobody was ever actually connected to anyone.
   This is a real N-way mesh call: every participant holds one RTCPeerConnection per other
   participant, signaled through Firestore under groups/{groupId}/call/state.

   Role assignment per pair is deterministic so both sides agree on who offers without a
   handshake: whoever's participant doc has the earlier (server-resolved) joinedAt is the
   offerer for that pair. That covers both "everyone joins a fresh call" and "someone joins a
   call already in progress" with the same logic. */
const CALL_ICE_SERVERS = [
  { urls: 'stun:stun.relay.metered.ca:80' },
  { urls: 'turn:global.relay.metered.ca:80', username: 'f5e29fd91b8ea2fc485c24ac', credential: 'FZlzkJ5GJJUyYocD' },
  { urls: 'turn:global.relay.metered.ca:80?transport=tcp', username: 'f5e29fd91b8ea2fc485c24ac', credential: 'FZlzkJ5GJJUyYocD' },
  { urls: 'turn:global.relay.metered.ca:443', username: 'f5e29fd91b8ea2fc485c24ac', credential: 'FZlzkJ5GJJUyYocD' },
  { urls: 'turns:global.relay.metered.ca:443?transport=tcp', username: 'f5e29fd91b8ea2fc485c24ac', credential: 'FZlzkJ5GJJUyYocD' },
];

const GroupCallOverlay = ({ groupId, groupName, callType, currentUser, users, showToast, onClose }) => {
  const [roster, setRoster] = useState([]); // [{uid, username, avatar, avatarColor, joinedAt}]
  const [remoteStreams, setRemoteStreams] = useState({}); // uid -> MediaStream
  const [connectedIds, setConnectedIds] = useState({}); // uid -> bool
  const [micOn, setMicOn] = useState(true);
  const [camOn, setCamOn] = useState(callType === 'video');
  const [joining, setJoining] = useState(true);

  const localStreamRef = useRef(null);
  const localVideoRef = useRef(null);
  const myJoinedAtRef = useRef(null);
  const peersRef = useRef({}); // uid -> { pc, role, processedCallerCands, processedCalleeCands, signalUnsub }
  const rosterUnsubRef = useRef(null);
  const myParticipantUnsubRef = useRef(null);
  const leavingRef = useRef(false);

  const callStateRef = () => doc(db, 'groups', groupId, 'call', 'state');
  const participantsCol = () => collection(db, 'groups', groupId, 'call', 'state', 'participants');
  const participantRef = (uid) => doc(db, 'groups', groupId, 'call', 'state', 'participants', uid);
  const signalRef = (pairId) => doc(db, 'groups', groupId, 'call', 'state', 'signals', pairId);

  const closePeer = (uid) => {
    const p = peersRef.current[uid];
    if (!p) return;
    try { p.signalUnsub?.(); } catch {}
    try { p.pc?.close(); } catch {}
    delete peersRef.current[uid];
    setRemoteStreams(prev => { const n = { ...prev }; delete n[uid]; return n; });
    setConnectedIds(prev => { const n = { ...prev }; delete n[uid]; return n; });
  };

  const setupPeer = (uid, role) => {
    if (peersRef.current[uid]) return; // already connecting/connected to this peer
    const pc = new RTCPeerConnection({ iceServers: CALL_ICE_SERVERS });
    const pairId = groupCallPairId(currentUser.id, uid);
    const myRole = role; // 'caller' | 'callee'
    peersRef.current[uid] = { pc, role: myRole, processedCallerCands: 0, processedCalleeCands: 0, signalUnsub: null };

    localStreamRef.current?.getTracks().forEach(track => pc.addTrack(track, localStreamRef.current));

    pc.ontrack = (e) => {
      setRemoteStreams(prev => ({ ...prev, [uid]: e.streams[0] }));
      setConnectedIds(prev => ({ ...prev, [uid]: true }));
    };
    pc.onconnectionstatechange = () => {
      if (pc.connectionState === 'failed' || pc.connectionState === 'disconnected' || pc.connectionState === 'closed') {
        setConnectedIds(prev => ({ ...prev, [uid]: false }));
      }
    };
    pc.onicecandidate = (e) => {
      if (!e.candidate) return;
      const field = myRole === 'caller' ? 'callerCandidates' : 'calleeCandidates';
      updateDoc(signalRef(pairId), { [field]: arrayUnion(e.candidate.toJSON()) }).catch(() => {
        setDoc(signalRef(pairId), { [field]: [e.candidate.toJSON()] }, { merge: true }).catch(() => {});
      });
    };

    const unsub = onSnapshot(signalRef(pairId), async (snap) => {
      const data = snap.data();
      if (!data) return;
      try {
        if (myRole === 'caller') {
          if (data.answer && pc.signalingState === 'have-local-offer') {
            await pc.setRemoteDescription(new RTCSessionDescription(data.answer));
          }
          const cands = data.calleeCandidates || [];
          const p = peersRef.current[uid];
          if (p) {
            for (let i = p.processedCalleeCands; i < cands.length; i++) {
              try { await pc.addIceCandidate(new RTCIceCandidate(cands[i])); } catch {}
            }
            p.processedCalleeCands = cands.length;
          }
        } else {
          if (data.offer && pc.signalingState === 'stable' && !pc.currentRemoteDescription) {
            await pc.setRemoteDescription(new RTCSessionDescription(data.offer));
            const answer = await pc.createAnswer();
            await pc.setLocalDescription(answer);
            await updateDoc(signalRef(pairId), { answer: { type: answer.type, sdp: answer.sdp } });
          }
          const cands = data.callerCandidates || [];
          const p = peersRef.current[uid];
          if (p) {
            for (let i = p.processedCallerCands; i < cands.length; i++) {
              try { await pc.addIceCandidate(new RTCIceCandidate(cands[i])); } catch {}
            }
            p.processedCallerCands = cands.length;
          }
        }
      } catch (e) { console.error('group call signal handling error:', e); }
    });
    peersRef.current[uid].signalUnsub = unsub;

    if (myRole === 'caller') {
      (async () => {
        try {
          const offer = await pc.createOffer();
          await pc.setLocalDescription(offer);
          await setDoc(signalRef(pairId), {
            callerId: currentUser.id, calleeId: uid,
            offer: { type: offer.type, sdp: offer.sdp },
            callerCandidates: [], calleeCandidates: [],
          }, { merge: true });
        } catch (e) { console.error('group call offer error:', e); }
      })();
    }
  };

  useEffect(() => {
    let cancelled = false;
    const start = async () => {
      try {
        const constraints = callType === 'video' ? { audio: true, video: { facingMode: 'user' } } : { audio: true, video: false };
        let stream;
        try {
          stream = await navigator.mediaDevices.getUserMedia(constraints);
        } catch (e) {
          if (callType === 'video') {
            stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
            setCamOn(false);
            showToast?.('Camera unavailable — joined with audio only', 'info');
          } else throw e;
        }
        if (cancelled) { stream.getTracks().forEach(t => t.stop()); return; }
        localStreamRef.current = stream;
        if (localVideoRef.current) { localVideoRef.current.srcObject = stream; localVideoRef.current.play().catch(() => {}); }

        // Ensure a call-state doc exists (first joiner starts it; later joiners just join).
        await setDoc(callStateRef(), { active: true, type: callType, groupId, updatedAt: serverTimestamp() }, { merge: true });

        // Announce myself, then wait for the server to resolve my own joinedAt before
        // negotiating with anyone — otherwise the caller/callee comparison below could
        // race against a still-pending local timestamp estimate.
        await setDoc(participantRef(currentUser.id), {
          uid: currentUser.id, username: currentUser.username || '', avatar: currentUser.avatar || '?',
          avatarColor: currentUser.avatarColor || COLORS.brand, joinedAt: serverTimestamp(),
        });

        myParticipantUnsubRef.current = onSnapshot(participantRef(currentUser.id), (snap) => {
          const d = snap.data();
          if (d?.joinedAt && !snap.metadata.hasPendingWrites) {
            myJoinedAtRef.current = d.joinedAt.toMillis ? d.joinedAt.toMillis() : Date.now();
          }
        });

        rosterUnsubRef.current = onSnapshot(participantsCol(), (snap) => {
          const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
          const others = list.filter(p => p.id !== currentUser.id);
          setRoster(others);
          setJoining(false);

          // Anyone who left: tear down their connection.
          const currentIds = new Set(others.map(p => p.id));
          Object.keys(peersRef.current).forEach(uid => { if (!currentIds.has(uid)) closePeer(uid); });

          // Re-scanning the full roster (rather than only reacting to docChanges) on every
          // snapshot deliberately covers the case where this snapshot fires before my own
          // joinedAt has resolved from the server — my own doc updating from pending to
          // confirmed is itself a change within this same collection, so this listener
          // re-fires naturally once myJoinedAtRef is ready, and nobody gets silently skipped.
          if (myJoinedAtRef.current == null) return;
          others.forEach(p => {
            if (peersRef.current[p.id] || !p.joinedAt) return;
            const theirMillis = p.joinedAt.toMillis ? p.joinedAt.toMillis() : Date.now();
            const role = myJoinedAtRef.current <= theirMillis ? 'caller' : 'callee';
            setupPeer(p.id, role);
          });
        });
      } catch (e) {
        console.error('Group call start error:', e);
        if (e?.name === 'NotAllowedError') showToast?.('Camera/mic access was denied', 'error');
        else if (e?.name === 'NotFoundError') showToast?.('No camera or microphone found on this device', 'error');
        else showToast?.('Could not start the group call', 'error');
        onClose?.();
      }
    };
    start();

    return () => {
      cancelled = true;
      leavingRef.current = true;
      rosterUnsubRef.current?.();
      myParticipantUnsubRef.current?.();
      Object.keys(peersRef.current).forEach(closePeer);
      localStreamRef.current?.getTracks().forEach(t => t.stop());
      const cleanup = async () => {
        try {
          await deleteDoc(participantRef(currentUser.id));
          const remaining = await getDocs(participantsCol());
          if (remaining.empty) {
            const signals = await getDocs(collection(db, 'groups', groupId, 'call', 'state', 'signals'));
            await Promise.all(signals.docs.map(d => deleteDoc(d.ref)));
            await updateDoc(callStateRef(), { active: false }).catch(() => {});
          }
        } catch {}
      };
      cleanup();
    };
  }, []);

  const toggleMic = () => {
    const next = !micOn;
    localStreamRef.current?.getAudioTracks().forEach(t => { t.enabled = next; });
    setMicOn(next);
  };
  const toggleCam = () => {
    if (callType !== 'video') return;
    const next = !camOn;
    localStreamRef.current?.getVideoTracks().forEach(t => { t.enabled = next; });
    setCamOn(next);
  };

  const tileFor = (uid, name, avatar, avatarColor, isMe) => {
    const stream = isMe ? localStreamRef.current : remoteStreams[uid];
    const connected = isMe ? true : !!connectedIds[uid];
    const showVideo = callType === 'video' && stream && stream.getVideoTracks().length > 0 && (isMe ? camOn : true);
    return (
      <div key={uid} style={{ width: 'calc(50% - 6px)', aspectRatio: '1/1', background: COLORS.overlaySubtle, borderRadius: 20, position: 'relative', overflow: 'hidden', border: `1px solid ${COLORS.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {showVideo ? (
          <video autoPlay playsInline muted={isMe} ref={el => { if (el && el.srcObject !== stream) el.srcObject = stream; }} style={{ width: '100%', height: '100%', objectFit: 'cover', transform: isMe ? 'scaleX(-1)' : 'none' }} />
        ) : (
          <div style={{ width: 64, height: 64, borderRadius: '50%', background: avatarColor || COLORS.brand, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: 24 }}>{avatar || '?'}</div>
        )}
        {!isMe && callType === 'audio' && stream && (
          <audio autoPlay ref={el => { if (el && el.srcObject !== stream) el.srcObject = stream; }} />
        )}
        <div style={{ position: 'absolute', bottom: 8, left: 10, right: 10, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <span style={{ color: 'white', fontSize: 12, fontWeight: 700, textShadow: '0 1px 3px rgba(0,0,0,0.6)' }}>{isMe ? 'You' : `@${name}`}</span>
          <span style={{ width: 8, height: 8, borderRadius: '50%', background: connected ? COLORS.success : COLORS.warning }} />
        </div>
      </div>
    );
  };

  return (
    <div style={{ position: 'absolute', inset: 0, background: COLORS.bg, zIndex: 60, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '20px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
        <div>
          <div style={{ color: COLORS.textPrimary, fontWeight: 800, fontSize: 18 }}>{callType === 'video' ? '📹' : '📞'} {groupName}</div>
          <div style={{ color: COLORS.textTertiary, fontSize: 12 }}>{joining ? 'Joining…' : `${roster.length + 1} in call`}</div>
        </div>
        <button onClick={onClose} aria-label="Close" style={{ background: 'rgba(11,95,255,0.15)', border: '1px solid rgba(11,95,255,0.3)', borderRadius: '50%', width: 36, height: 36, color: COLORS.brand, cursor: 'pointer', fontSize: 18 }}>✕</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: 16, display: 'flex', flexWrap: 'wrap', gap: 12, alignContent: 'flex-start', justifyContent: 'center' }}>
        {tileFor(currentUser.id, currentUser.username, currentUser.avatar, currentUser.avatarColor, true)}
        {roster.map(p => tileFor(p.id, p.username, p.avatar, p.avatarColor, false))}
      </div>
      <div style={{ padding: '16px 20px 32px', display: 'flex', justifyContent: 'center', gap: 20, borderTop: `1px solid ${COLORS.overlaySubtle}` }}>
        <button onClick={toggleMic} style={{ width: 56, height: 56, borderRadius: '50%', background: micOn ? COLORS.border : COLORS.danger, border: 'none', color: micOn ? COLORS.textPrimary : 'white', fontSize: 22, cursor: 'pointer' }}>{micOn ? '🎤' : '🔇'}</button>
        {callType === 'video' && <button onClick={toggleCam} style={{ width: 56, height: 56, borderRadius: '50%', background: camOn ? COLORS.border : COLORS.danger, border: 'none', color: camOn ? COLORS.textPrimary : 'white', fontSize: 22, cursor: 'pointer' }}>{camOn ? '📷' : '🚫'}</button>}
        <button onClick={onClose} aria-label="End call" style={{ width: 56, height: 56, borderRadius: '50%', background: COLORS.danger, border: 'none', color: 'white', fontSize: 22, cursor: 'pointer' }}>📵</button>
      </div>
    </div>
  );
};

/* ─────────────── GROUP CHAT (v4 — like WhatsApp/Telegram groups) ─────────────── */
// `embedded` lets InboxPage host this component directly inside its own unified
// Chats list instead of only via GroupChatPage's own internal group-list screen.
// When embedded, this component never renders its internal list — it either shows
// a specific group (openGroupId) or the create-group flow (startInCreate), and any
// "back" action hands control back to the caller via onBack instead of falling
// back to the internal list.
const GroupChatPage = ({ currentUser, users, showToast, onBack, embedded=false, openGroupId=null, startInCreate=false }) => {
  const [groups, setGroups] = useState([]);
  const [groupsLoaded, setGroupsLoaded] = useState(false);
  const [showCreate, setShowCreate] = useState(startInCreate);
  const [groupName, setGroupName] = useState('');
  const [selectedMembers, setSelectedMembers] = useState([]);
  const [activeGroup, setActiveGroup] = useState(null);
  const [groupMessages, setGroupMessages] = useState([]);
  const [msgText, setMsgText] = useState('');
  // Tracks the VoiceRecorderButton's internal state so the composer row can stop
  // forcing it into a fixed 42px circle once it expands — see comment composer for
  // the full explanation of why that clipped the waveform/send UI off-screen.
  const [groupVoiceState, setGroupVoiceState] = useState('idle');
  const [showGroupInfo, setShowGroupInfo] = useState(false);
  const [groupCallOpen, setGroupCallOpen] = useState(null); // 'audio' | 'video' | null
  // "Catch Me Up" — same mechanic as the 1:1 conversation view, using each member's
  // own lastOpenedAt_{uid} field on the group doc.
  const [lastOpenedAt, setLastOpenedAt] = useState(undefined);
  const [catchUpDismissed, setCatchUpDismissed] = useState(false);
  const bottomRef = useRef(null);
  // Composer attachments — same photo/camera/voice pattern as the 1:1
  // ConversationView composer, so group chat isn't a stripped-down text-only
  // version of the same feature.
  const [previewFile, setPreviewFile] = useState(null);
  const fileInputRef = useRef(null);
  const cameraInputRef = useRef(null);
  const pickFile = e => { const f = e.target.files[0]; if (f) { setPreviewFile({ url: URL.createObjectURL(f), file: f, type: f.type }); } e.target.value = ''; };
  const clearAttach = () => setPreviewFile(null);
  // Real in-app camera capture (getUserMedia live preview + shutter) so "Take
  // photo" always opens an actual camera instead of silently depending on
  // <input capture> only working in some mobile browsers. Falls back to the
  // hidden file input if getUserMedia isn't available/permitted.
  const [showCameraCapture, setShowCameraCapture] = useState(false);
  const groupCameraVideoRef = useRef(null);
  const groupCameraStreamRef = useRef(null);
  const openGroupCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      groupCameraStreamRef.current = stream;
      setShowCameraCapture(true);
    } catch {
      cameraInputRef.current?.click();
    }
  };
  const closeGroupCamera = () => {
    groupCameraStreamRef.current?.getTracks().forEach(t => t.stop());
    groupCameraStreamRef.current = null;
    setShowCameraCapture(false);
  };
  useEffect(() => {
    if (showCameraCapture && groupCameraVideoRef.current && groupCameraStreamRef.current) {
      groupCameraVideoRef.current.srcObject = groupCameraStreamRef.current;
    }
  }, [showCameraCapture]);
  const captureGroupPhoto = () => {
    const video = groupCameraVideoRef.current;
    if (!video) return;
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    canvas.getContext('2d').drawImage(video, 0, 0);
    canvas.toBlob(blob => {
      if (blob) setPreviewFile({ url: URL.createObjectURL(blob), file: blob, type: 'image/jpeg' });
      closeGroupCamera();
    }, 'image/jpeg', 0.92);
  };

  useEffect(() => {
    if (!currentUser?.id) return;
    // NOTE: avoid combining array-contains with orderBy on a different field —
    // that requires a Firestore composite index, and without it onSnapshot
    // silently errors and `groups` stays empty (new groups appear "not found").
    // Sort client-side instead.
    const q = query(collection(db, 'groups'), where('members', 'array-contains', currentUser.id));
    const unsub = onSnapshot(q, snap => {
      const list = snap.docs.map(d => {
        const data = d.data();
        return { id: d.id, ...data, avatarColor: resolveAvatarColor(data.avatarColor, d.id) };
      });
      list.sort((a, b) => (b.lastMessageAt?.toMillis?.() || 0) - (a.lastMessageAt?.toMillis?.() || 0));
      setGroups(list);
      setGroupsLoaded(true);
    }, (err) => {
      console.error('groups query error:', err);
      showToast?.('Failed to load groups: ' + err.message, 'error');
      setGroupsLoaded(true);
    });
    return () => unsub();
  }, [currentUser?.id]);

  // Embedded mode: resolve openGroupId into an activeGroup once the groups snapshot
  // has loaded. If it's genuinely missing (deleted, left, or no target given at all),
  // hand back to the caller rather than falling through to the internal list screen.
  useEffect(() => {
    if (!embedded || startInCreate || activeGroup || !groupsLoaded) return;
    const found = openGroupId ? groups.find(g => g.id === openGroupId) : null;
    if (found) setActiveGroup(found);
    else onBack?.();
  }, [embedded, startInCreate, activeGroup, groupsLoaded, groups, openGroupId]);

  // Keep the open group's local copy in sync as the underlying doc changes
  // (e.g. another member's edits, or this user's own read-state reset below).
  useEffect(() => {
    if (!activeGroup?.id) return;
    const fresh = groups.find(g => g.id === activeGroup.id);
    if (fresh && fresh !== activeGroup) setActiveGroup(fresh);
  }, [groups]);

  useEffect(() => {
    if (!activeGroup) return;
    const q = query(collection(db, 'groups', activeGroup.id, 'msgs'), orderBy('createdAt', 'asc'), limit(100));
    const unsub = onSnapshot(q, snap => {
      setGroupMessages(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 80);
    });
    return () => unsub();
  }, [activeGroup?.id]);

  // Reset this viewer's unread counter the moment a group is opened — mirrors the
  // unread_{uid} pattern already used for 1:1 conversations. Also captures the
  // *previous* lastOpenedAt_{uid} before overwriting it, so Catch Me Up knows the
  // cutoff for "what did I miss".
  useEffect(() => {
    if (!activeGroup?.id || !currentUser?.id) return;
    setLastOpenedAt(undefined);
    setCatchUpDismissed(false);
    (async () => {
      try {
        const snap = await getDoc(doc(db, 'groups', activeGroup.id));
        setLastOpenedAt(snap.data()?.[`lastOpenedAt_${currentUser.id}`]?.toMillis?.() || 0);
      } catch { setLastOpenedAt(0); }
      updateDoc(doc(db, 'groups', activeGroup.id), {
        [`unread_${currentUser.id}`]: 0,
        [`lastOpenedAt_${currentUser.id}`]: serverTimestamp(),
      }).catch(() => {});
    })();
  }, [activeGroup?.id]);

  useEffect(() => {
    setShowGroupInfo(false);
    setGroupCallOpen(null);
  }, [activeGroup?.id]);

  // Exit a group conversation: in embedded mode this always hands control back to
  // the caller's unified list (which owns navigation); standalone mode falls back
  // to this component's own internal group-list screen.
  const exitGroup = () => { if (embedded) onBack?.(); else setActiveGroup(null); };

  const createGroup = async () => {
    if (!groupName.trim() || selectedMembers.length === 0) { showToast?.('Add a name and at least one member', 'error'); return; }
    const members = [currentUser.id, ...selectedMembers];
    const avatar = groupName.trim()[0].toUpperCase();
    const avatarColor = pickAvatarColor(groupName.trim() + Date.now());
    // Seed unread_{uid}:0 for every member up front so the field exists from
    // creation — mirrors 1:1 conversations, and lets the unified Chats list and
    // Unread filter treat groups exactly like DMs from the very first render.
    const unreadFields = {};
    members.forEach(uid => { unreadFields[`unread_${uid}`] = 0; });
    try {
      const ref = await addDoc(collection(db, 'groups'), {
        name: groupName.trim(), members, admin: currentUser.id,
        createdAt: serverTimestamp(), lastMessageAt: serverTimestamp(),
        avatar, avatarColor, ...unreadFields
      });
      showToast?.('Group created! 🎉', 'success');
      setShowCreate(false); setGroupName(''); setSelectedMembers([]);
      setActiveGroup({ id: ref.id, name: groupName.trim(), members, avatar, avatarColor, admin: currentUser.id });
    } catch (err) {
      console.error('createGroup error:', err);
      showToast?.('Failed to create group: ' + err.message, 'error');
    }
  };


  const sendGroupMsg = async () => {
    if ((!msgText.trim() && !previewFile) || !activeGroup) return;
    const txt = msgText;
    let mediaUrl = null, mediaType = null;
    if (previewFile?.file) {
      try { mediaUrl = await uploadToCloudinary(previewFile.file); mediaType = previewFile.type; }
      catch { showToast?.('Upload failed', 'error'); return; }
    }
    // AI content check — group messages have multiple witnesses, so this gap
    // matters at least as much as 1:1 DMs. Fail open on a moderation-service
    // hiccup so a network blip never blocks a legitimate message.
    if (txt.trim()) {
      try {
        const modResult = await apiFetch('/api/moderation/check', { method: 'POST', body: JSON.stringify({ text: txt }) });
        if (modResult?.blocked) {
          showToast?.('This message looks like it may violate our community guidelines and was not sent.', 'error');
          return;
        }
      } catch (e) {}
    }
    setMsgText('');
    clearAttach();
    await addDoc(collection(db, 'groups', activeGroup.id, 'msgs'), {
      text: txt, mediaUrl: mediaUrl || null, mediaType: mediaType || null,
      senderId: currentUser.id, senderName: currentUser.username,
      senderAvatar: currentUser.avatar, senderAvatarColor: currentUser.avatarColor,
      senderAvatarUrl: currentUser.avatarUrl || null,
      createdAt: serverTimestamp(),
    });
    // Increment every other member's unread_{uid} (never the sender's own), and
    // record who sent it so the unified Chats list can show "Name: message" —
    // matching the DM inbox's unread badge + preview behavior.
    const unreadIncrements = {};
    (activeGroup.members || []).forEach(uid => {
      if (uid !== currentUser.id) unreadIncrements[`unread_${uid}`] = increment(1);
    });
    await updateDoc(doc(db, 'groups', activeGroup.id), {
      lastMessage: mediaUrl ? (mediaType?.startsWith('video') ? '🎥 Video' : mediaType?.startsWith('image') ? '📷 Photo' : '📎 Attachment') : txt,
      lastMessageAt: serverTimestamp(),
      lastSenderId: currentUser.id, lastSenderName: currentUser.username,
      ...unreadIncrements,
    });
  };

  // Voice notes reuse the same VoiceRecorderButton used in 1:1 chat.
  const sendGroupVoice = async (voiceMsg) => {
    if (!activeGroup) return;
    try {
      await addDoc(collection(db, 'groups', activeGroup.id, 'msgs'), {
        text: '', mediaUrl: voiceMsg.url, mediaType: 'audio', duration: voiceMsg.duration,
        senderId: currentUser.id, senderName: currentUser.username,
        senderAvatar: currentUser.avatar, senderAvatarColor: currentUser.avatarColor,
        senderAvatarUrl: currentUser.avatarUrl || null,
        createdAt: serverTimestamp(),
      });
      const unreadIncrements = {};
      (activeGroup.members || []).forEach(uid => {
        if (uid !== currentUser.id) unreadIncrements[`unread_${uid}`] = increment(1);
      });
      await updateDoc(doc(db, 'groups', activeGroup.id), {
        lastMessage: '🎙️ Voice message', lastMessageAt: serverTimestamp(),
        lastSenderId: currentUser.id, lastSenderName: currentUser.username,
        ...unreadIncrements,
      });
    } catch (e) {
      showToast?.('Failed to send voice message: ' + e.message, 'error');
    }
  };

  if (activeGroup) {
    const groupMembers = users.filter(u => (activeGroup.members||[]).includes(u.id));
    const GROUP_CATCH_UP_THRESHOLD = 8;
    const groupUnreadSinceOpen = (lastOpenedAt !== undefined)
      ? groupMessages.filter(m => m.senderId !== currentUser.id && (m.createdAt?.toMillis?.() || 0) > lastOpenedAt)
      : [];
    const showGroupCatchUp = !catchUpDismissed && groupUnreadSinceOpen.length >= GROUP_CATCH_UP_THRESHOLD;
    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column', background: COLORS.bg }}>
        <div style={{ padding: '14px 16px', borderBottom: `1px solid ${COLORS.overlaySubtle}`, display: 'flex', alignItems: 'center', gap: 12, background: COLORS.overlaySubtle }}>
          <button onClick={exitGroup} aria-label="Back" style={{ background: 'none', border: 'none', color: COLORS.textPrimary, cursor: 'pointer', fontSize: 18 }}>←</button>
          <div onClick={()=>setShowGroupInfo(true)} style={{ display:'flex', alignItems:'center', gap:10, flex:1, cursor:'pointer' }}>
            <div style={{ width: 38, height: 38, borderRadius: '50%', background: activeGroup.avatarColor || COLORS.brand, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: 16 }}>{activeGroup.avatar || '👥'}</div>
            <div>
              <div style={{ color: COLORS.textPrimary, fontWeight: 700, fontSize: 15 }}>{activeGroup.name}</div>
              <div style={{ color: COLORS.textTertiary, fontSize: 11 }}>{(activeGroup.members || []).length} members · tap for info</div>
            </div>
          </div>
          <button onClick={()=>setGroupCallOpen('audio')} aria-label="Start audio call" style={{ background:'rgba(52,199,89,0.15)', border:'1px solid rgba(52,199,89,0.25)', borderRadius:'50%', width:36, height:36, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer' }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.success} strokeWidth="2"><path d="M22 16.92v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07 19.5 19.5 0 01-5.99-5.99 19.79 19.79 0 01-3.07-8.67A2 2 0 014 2h3a2 2 0 012 1.72c.127.96.361 1.903.7 2.81a2 2 0 01-.45 2.11L8.09 9.91a16 16 0 006 6l1.27-1.27a2 2 0 012.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0122 14.92z"/></svg>
          </button>
          <button onClick={()=>setGroupCallOpen('video')} aria-label="Start video call" style={{ background:'rgba(175,82,222,0.15)', border:'1px solid rgba(175,82,222,0.25)', borderRadius:'50%', width:36, height:36, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer' }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.brandSecondary} strokeWidth="2"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>
          </button>
        </div>
        {/* Group Info Panel */}
        {showGroupInfo && (
          <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.85)', zIndex:50, display:'flex', alignItems:'flex-end' }} onClick={()=>setShowGroupInfo(false)}>
            <div onClick={e=>e.stopPropagation()} style={{ width:'100%', background:COLORS.surface2, borderTopLeftRadius:28, borderTopRightRadius:28, padding:'20px 20px 40px', maxHeight:'70%', overflowY:'auto' }}>
              <div style={{ width:36, height:4, background:COLORS.border, borderRadius:2, margin:'0 auto 20px' }} />
              <div style={{ display:'flex', alignItems:'center', gap:14, marginBottom:20 }}>
                <div style={{ width:52, height:52, borderRadius:'50%', background:activeGroup.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:'bold', fontSize:22 }}>{activeGroup.avatar||'👥'}</div>
                <div>
                  <div style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:18 }}>{activeGroup.name}</div>
                  <div style={{ color:COLORS.textTertiary, fontSize:12 }}>Created by group admin</div>
                </div>
              </div>
              <div style={{ color:COLORS.textTertiary, fontSize:11, fontWeight:700, textTransform:'uppercase', letterSpacing:1, marginBottom:12 }}>Members ({groupMembers.length})</div>
              {groupMembers.map(u=>(
                <div key={u.id} style={{ display:'flex', alignItems:'center', gap:12, padding:'11px 0', borderBottom:`1px solid ${COLORS.overlaySubtle}` }}>
                  <div style={{ width:44, height:44, borderRadius:'50%', background:u.avatarColor, display:'flex', alignItems:'center', justifyContent:'center', color:COLORS.textPrimary, fontWeight:'bold', fontSize:18, overflow:'hidden', flexShrink:0 }}>
                    {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt="" /> : u.avatar}
                  </div>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ color:COLORS.textPrimary, fontSize:14, fontWeight:700, display:'flex', alignItems:'center', gap:6, flexWrap:'wrap' }}>
                      @{u.username}
                      {u.id===currentUser?.id && <span style={{ color:COLORS.successText, fontSize:10 }}>You</span>}
                      {activeGroup.admin===u.id && <span style={{ background:'rgba(255,204,0,0.15)', border:'1px solid rgba(255,204,0,0.3)', borderRadius:10, padding:'1px 7px', color:COLORS.warningAlt, fontSize:9, fontWeight:800 }}>ADMIN</span>}
                    </div>
                    {u.bio && <div style={{ color:COLORS.textTertiary, fontSize:11, marginTop:2, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{u.bio}</div>}
                    <div style={{ color:COLORS.borderStrong, fontSize:10, marginTop:1 }}>{u.followers?.length||0} followers</div>
                  </div>
                  {currentUser?.id===activeGroup?.admin && u.id!==currentUser?.id && (
                    <button onClick={e=>{e.stopPropagation(); const nm=(activeGroup.members||[]).filter(id=>id!==u.id); updateDoc(doc(db,'groups',activeGroup.id),{members:nm}).then(()=>{setActiveGroup(g=>({...g,members:nm})); showToast?.('Member removed','info');}).catch(()=>{});}} style={{ background:'rgba(255,59,48,0.1)', border:'1px solid rgba(255,59,48,0.2)', borderRadius:10, padding:'5px 10px', color:COLORS.dangerText, fontSize:11, cursor:'pointer', flexShrink:0 }}>Remove</button>
                  )}
                </div>
              ))}

              {/* Group Actions — scoped to this group's own info panel (its "home"),
                  never shown on the account-level Settings page. Mirrors the shape of
                  Settings' Account Actions (Leave = Log Out equivalent, Delete Group
                  = Delete Account equivalent, admin-only). */}
              <div style={{ color:COLORS.textTertiary, fontSize:11, fontWeight:700, textTransform:'uppercase', letterSpacing:1, margin:'20px 0 12px' }}>Group Actions</div>
              <div
                onClick={async()=>{
                  const isLast = (activeGroup.members||[]).length <= 1;
                  if(!(await confirmDialog(isLast ? 'Leave and delete this group?' : 'Leave this group?', { danger:true, confirmLabel:'Leave' }))) return;
                  try {
                    if(isLast){
                      const msgsSnap = await getDocs(collection(db,'groups',activeGroup.id,'msgs'));
                      await Promise.all(msgsSnap.docs.map(d=>deleteDoc(doc(db,'groups',activeGroup.id,'msgs',d.id))));
                      await deleteDoc(doc(db,'groups',activeGroup.id));
                    } else {
                      const nm = (activeGroup.members||[]).filter(id=>id!==currentUser.id);
                      const patch = { members: nm };
                      if(activeGroup.admin === currentUser.id) patch.admin = nm[0];
                      await updateDoc(doc(db,'groups',activeGroup.id), patch);
                    }
                    setShowGroupInfo(false);
                    exitGroup();
                    showToast?.('Left the group','info');
                  } catch(e) {
                    showToast?.('Could not leave group: '+e.message,'error');
                  }
                }}
                style={{ padding:'13px 14px', borderRadius:14, background:COLORS.surface, marginBottom:8, display:'flex', alignItems:'center', gap:12, cursor:'pointer' }}>
                <div style={{ width:32, height:32, borderRadius:10, background:COLORS.overlaySubtle, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.warning} strokeWidth="2"><path d="M9 21H5a2 2 0 01-2-2V5a2 2 0 012-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
                </div>
                <span style={{ color:COLORS.warningText, fontSize:14, fontWeight:600 }}>Leave Group</span>
              </div>

              {currentUser?.id===activeGroup?.admin && (
                <div
                  onClick={async()=>{
                    if(!(await confirmDialog('Delete this group for everyone? This cannot be undone.', { danger:true, confirmLabel:'Delete' }))) return;
                    try {
                      const msgsSnap = await getDocs(collection(db,'groups',activeGroup.id,'msgs'));
                      await Promise.all(msgsSnap.docs.map(d=>deleteDoc(doc(db,'groups',activeGroup.id,'msgs',d.id))));
                      await deleteDoc(doc(db,'groups',activeGroup.id));
                      setShowGroupInfo(false);
                      exitGroup();
                      showToast?.('Group deleted','info');
                    } catch(e) {
                      showToast?.('Could not delete group: '+e.message,'error');
                    }
                  }}
                  style={{ padding:'13px 14px', borderRadius:14, background:COLORS.surface, display:'flex', alignItems:'center', gap:12, cursor:'pointer' }}>
                  <div style={{ width:32, height:32, borderRadius:10, background:COLORS.overlaySubtle, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.danger} strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a1 1 0 011-1h4a1 1 0 011 1v2"/></svg>
                  </div>
                  <span style={{ color:COLORS.dangerText, fontSize:14, fontWeight:600 }}>Delete Group</span>
                </div>
              )}
            </div>
          </div>
        )}
        {/* Group Call Overlay — real WebRTC mesh call, see GroupCallOverlay above */}
        {groupCallOpen && (
          <GroupCallOverlay
            groupId={activeGroup.id}
            groupName={activeGroup.name}
            callType={groupCallOpen}
            currentUser={currentUser}
            users={groupMembers}
            showToast={showToast}
            onClose={() => setGroupCallOpen(null)}
          />
        )}
        <AnimatePresence>
          {showGroupCatchUp && (
            <CatchUpBanner
              unreadMessages={groupUnreadSinceOpen.map(m => ({ from: m.senderName || 'someone', text: m.text }))}
              isGroup={true}
              onDismiss={() => setCatchUpDismissed(true)}
            />
          )}
        </AnimatePresence>
        <div style={{ flex: 1, overflowY: 'auto', padding: '10px 14px' }}>
          {groupMessages.map(msg => {
            const isMine = msg.senderId === currentUser.id;
            const ts = msg.createdAt?.toDate?.();
            return (
              <motion.div
                key={msg.id}
                initial={{ opacity:0, y:6 }}
                animate={{ opacity:1, y:0 }}
                transition={{ duration:0.18 }}
                style={{ display: 'flex', justifyContent: isMine ? 'flex-end' : 'flex-start', marginBottom: 10 }}
              >
                {!isMine && (
                  <div style={{ width: 28, height: 28, borderRadius: '50%', background: msg.senderAvatarColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: COLORS.textPrimary, fontSize: 11, fontWeight: 'bold', marginRight: 8, flexShrink: 0, overflow: 'hidden' }}>
                    {msg.senderAvatarUrl ? <img loading="lazy" decoding="async" src={msg.senderAvatarUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" /> : msg.senderAvatar}
                  </div>
                )}
                <div style={{ maxWidth: '72%' }}>
                  {!isMine && <div style={{ color: COLORS.textTertiary, fontSize: 10, marginBottom: 3, fontWeight:600 }}>@{msg.senderName}</div>}
                  {msg.mediaUrl && msg.mediaType?.startsWith('image') && (
                    <img loading="lazy" decoding="async" src={msg.mediaUrl} alt="" style={{ maxWidth: 220, borderRadius: 14, marginBottom: msg.text ? 4 : 0, display: 'block' }} />
                  )}
                  {msg.mediaUrl && msg.mediaType?.startsWith('video') && (
                    <video src={msg.mediaUrl} controls style={{ maxWidth: 220, borderRadius: 14, marginBottom: msg.text ? 4 : 0, display: 'block' }} />
                  )}
                  {msg.mediaUrl && msg.mediaType?.startsWith('audio') && (
                    <div style={{ marginBottom: msg.text ? 4 : 0 }}>
                      <VoiceMessagePro src={msg.mediaUrl} duration={msg.duration} seed={msg.id || msg.mediaUrl}
                        accentBg={isMine ? 'rgba(255,255,255,0.16)' : COLORS.audioSurface}
                        accentColor={isMine ? '#fff' : COLORS.audio}
                        msg={msg} msgRef={doc(db,'groups',activeGroup.id,'msgs',msg.id)} showToast={showToast} />
                    </div>
                  )}
                  {msg.text && (
                    <div style={{ background: isMine ? `linear-gradient(135deg,${COLORS.brand},${COLORS.brandSecondary})` : COLORS.surfaceAlt, borderRadius: isMine ? '18px 18px 4px 18px' : '18px 18px 18px 4px', padding: '10px 14px', color: isMine ? 'white' : COLORS.textPrimary, fontSize: 14, boxShadow: isMine ? SHADOW.xs : 'none' }}>
                      {msg.text}
                      {!isMine && <MessageTranslate text={msg.text} targetLang={currentUser?.language || 'en'} isMine={isMine} />}
                    </div>
                  )}
                  {ts && (
                    <div style={{ fontSize:9.5, color:COLORS.textTertiary, marginTop:3, textAlign: isMine ? 'right' : 'left' }}>
                      {ts.toLocaleTimeString([], { hour:'2-digit', minute:'2-digit' })}
                    </div>
                  )}
                </div>
              </motion.div>
            );
          })}
          <div ref={bottomRef} />
        </div>
        {previewFile && (
          <div style={{ padding: '0 14px 6px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, background: COLORS.surface, border: `1px solid ${COLORS.border}`, borderRadius: 14, padding: '8px 12px', boxShadow: SHADOW.xs }}>
              {previewFile.type?.startsWith('image') && <img loading="lazy" decoding="async" src={previewFile.url} alt="" style={{ height: 44, width: 44, objectFit: 'cover', borderRadius: 8 }} />}
              {previewFile.type?.startsWith('video') && <video src={previewFile.url} style={{ height: 44, width: 60, objectFit: 'cover', borderRadius: 8 }} />}
              <button onClick={clearAttach} aria-label="Remove attachment" style={{ marginLeft: 'auto', background: COLORS.surfaceAlt, border: 'none', borderRadius: '50%', width: 22, height: 22, color: COLORS.brand, cursor: 'pointer', fontSize: 13 }}>✕</button>
            </div>
          </div>
        )}
        <div style={{ padding: '10px 14px', paddingBottom: 'max(28px, env(safe-area-inset-bottom))', background: COLORS.surface, borderTop: `1px solid ${COLORS.border}`, display: 'flex', gap: 8, alignItems: 'center' }}>
          {groupVoiceState === 'idle' && (
            <div style={{ flex: 1, minWidth: 0, display: 'flex', alignItems: 'center', gap: 2, background: COLORS.surfaceAlt, borderRadius: 26, padding: '4px 6px 4px 12px' }}>
              <input value={msgText} onChange={e => setMsgText(e.target.value)} onKeyDown={e => e.key === 'Enter' && sendGroupMsg()} placeholder="Message group..." style={{ flex: 1, minWidth: 0, background: 'none', border: 'none', outline: 'none', color: COLORS.textPrimary, fontSize: 13.5, padding: '9px 4px' }} />
              <button onClick={() => fileInputRef.current?.click()} aria-label="Attach photo" style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, padding: 6 }}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" /></svg>
              </button>
              <button onClick={openGroupCamera} aria-label="Take photo" style={{ background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, padding: 6 }}>
                <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z" /><circle cx="12" cy="13" r="4" /></svg>
              </button>
            </div>
          )}
          <input ref={fileInputRef} type="file" accept="image/*,video/*" onChange={pickFile} style={{ display: 'none' }} />
          <input ref={cameraInputRef} type="file" accept="image/*" capture="environment" onChange={pickFile} style={{ display: 'none' }} />
          <AnimatePresence initial={false}>
            {(msgText.trim() || previewFile) ? (
              <motion.button key="send" initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.5, opacity: 0 }} transition={springs.snappy} whileTap={tapScale} onClick={sendGroupMsg} aria-label="Send message" style={{ background: COLORS.gradient, border: 'none', borderRadius: '50%', width: 42, height: 42, color: 'white', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="white" stroke="white" strokeWidth="1"><polygon points="22 2 15 22 11 13 2 9 22 2" /></svg>
              </motion.button>
            ) : (
              // Same key stays mounted across idle → recording → preview so the active
              // recording is never unmounted; only style changes (circle vs full-width).
              <motion.div key="voice" initial={{ scale: 0.5, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.5, opacity: 0 }} transition={springs.snappy}
                style={ groupVoiceState === 'idle'
                  ? { background: COLORS.gradient, borderRadius: '50%', width: 42, height: 42, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }
                  : { flex: 1, minWidth: 0, display: 'flex', alignItems: 'center' } }>
                <VoiceRecorderButton showToast={showToast} size="small" onSend={sendGroupVoice} onStateChange={setGroupVoiceState} />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
        <AnimatePresence>{showCameraCapture && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} style={{ position: 'fixed', inset: 0, background: '#000', zIndex: Z.modal, display: 'flex', flexDirection: 'column' }}>
            <div style={{ padding: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <button onClick={closeGroupCamera} style={{ background: 'rgba(255,255,255,0.12)', border: 'none', borderRadius: 20, padding: '8px 16px', color: 'white', cursor: 'pointer', fontSize: 13 }}>Cancel</button>
              <span style={{ color: 'white', fontWeight: 700, fontSize: 15 }}>Camera</span>
              <div style={{ width: 70 }} />
            </div>
            <div style={{ flex: 1, position: 'relative', overflow: 'hidden' }}>
              <video ref={groupCameraVideoRef} autoPlay playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover', transform: 'scaleX(-1)' }} />
              <button onClick={captureGroupPhoto} aria-label="Capture photo" style={{ position: 'absolute', bottom: 30, left: '50%', transform: 'translateX(-50%)', background: 'white', border: '4px solid rgba(255,255,255,0.4)', borderRadius: '50%', width: 72, height: 72, cursor: 'pointer' }} />
            </div>
          </motion.div>
        )}</AnimatePresence>
      </div>
    );
  }

  if (showCreate) return (
    <div style={{ height: '100%', overflow: 'auto', background: COLORS.bg, padding: 16 }}>
      <button onClick={() => embedded ? onBack?.() : setShowCreate(false)} style={{ background: COLORS.overlaySubtle, border: 'none', borderRadius: 20, padding: '8px 16px', color: COLORS.textPrimary, cursor: 'pointer', fontSize: 13, marginBottom: 20, display: 'flex', alignItems: 'center', gap: 6 }}>← Back</button>
      <div style={{ color: COLORS.textPrimary, fontWeight: 800, fontSize: 22, marginBottom: 20 }}>New Group</div>
      <input value={groupName} onChange={e => setGroupName(e.target.value)} placeholder="Group name" style={{ width: '100%', background: COLORS.overlaySubtle, border: `1px solid ${COLORS.border}`, borderRadius: 16, padding: '13px 16px', color: COLORS.textPrimary, outline: 'none', fontSize: 14, boxSizing: 'border-box', marginBottom: 16 }} />
      <div style={{ color: COLORS.textTertiary, fontSize: 12, marginBottom: 10, fontWeight: 600, textTransform: 'uppercase' }}>Add Members</div>
      {users.filter(u => u.id !== currentUser?.id).map(u => (
        <div key={u.id} onClick={() => setSelectedMembers(p => p.includes(u.id) ? p.filter(id => id !== u.id) : [...p, u.id])} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 0', borderBottom: `1px solid ${COLORS.overlaySubtle}`, cursor: 'pointer' }}>
          <div style={{ width: 40, height: 40, borderRadius: '50%', background: u.avatarColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: COLORS.textPrimary, fontWeight: 'bold', fontSize: 16, overflow: 'hidden', flexShrink: 0 }}>
            {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" /> : u.avatar}
          </div>
          <div style={{ flex: 1 }}><div style={{ color: COLORS.textPrimary, fontSize: 14, fontWeight: 600 }}>@{u.username}</div></div>
          <div style={{ width: 22, height: 22, borderRadius: '50%', background: selectedMembers.includes(u.id) ? COLORS.brand : COLORS.border, border: selectedMembers.includes(u.id) ? 'none' : `2px solid ${COLORS.borderStrong}`, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.15s' }}>
            {selectedMembers.includes(u.id) && <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="3"><polyline points="20 6 9 17 4 12" /></svg>}
          </div>
        </div>
      ))}
      <button onClick={createGroup} style={{ width: '100%', background: `linear-gradient(135deg,${COLORS.brand},${COLORS.brandSecondary})`, border: 'none', borderRadius: 24, padding: 15, color: 'white', fontWeight: 700, cursor: 'pointer', fontSize: 15, marginTop: 20 }}>Create Group ({selectedMembers.length} members)</button>
    </div>
  );

  // Embedded mode never owns the group list itself (InboxPage's unified Chats list
  // does) — this is only a brief loading state while openGroupId resolves; the
  // effect above hands back to the caller as soon as it's clear the group isn't found.
  if (embedded) return (
    <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', background: COLORS.bg, padding: 16 }}>
      <SkeletonLoader count={3} />
    </div>
  );

  return (
    <div style={{ height: '100%', overflow: 'auto', background: COLORS.bg }}>
      <div style={{ padding: '16px 16px 12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <button onClick={onBack} aria-label="Back" style={{ background: 'none', border: 'none', color: COLORS.textPrimary, cursor: 'pointer', fontSize: 18 }}>←</button>
          <div style={{ color: COLORS.textPrimary, fontWeight: 800, fontSize: 18 }}>Groups</div>
        </div>
        <button onClick={() => setShowCreate(true)} style={{ background: `linear-gradient(135deg,${COLORS.brand},${COLORS.brandSecondary})`, border: 'none', borderRadius: 20, padding: '8px 16px', color: 'white', fontWeight: 700, fontSize: 13, cursor: 'pointer' }}>+ New</button>
      </div>
      <div style={{ padding: 12 }}>
        {groups.length === 0 && (
          <div style={{ textAlign: 'center', padding: 60, color: COLORS.borderStrong }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>👥</div>
            <div style={{ fontSize: 14, marginBottom: 8 }}>No groups yet</div>
            <div style={{ fontSize: 12 }}>Create a group to chat with multiple friends</div>
          </div>
        )}
        {groups.map(g => (
          <div key={g.id} onClick={() => setActiveGroup(g)} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', background: COLORS.overlaySubtle, borderRadius: 18, marginBottom: 8, cursor: 'pointer', border: `1px solid ${COLORS.overlaySubtle}` }}>
            <div style={{ width: 48, height: 48, borderRadius: '50%', background: g.avatarColor || COLORS.brand, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: 20, flexShrink: 0 }}>{g.avatar || '👥'}</div>
            <div style={{ flex: 1 }}>
              <div style={{ color: COLORS.textPrimary, fontWeight: 700, fontSize: 14 }}>{g.name}</div>
              <div style={{ color: COLORS.textTertiary, fontSize: 12, marginTop: 2 }}>{g.lastMessage || 'No messages yet'} · {(g.members || []).length} members</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

/* ─────────────── SAVED POSTS PAGE (v4 — like Instagram Collections) ─────────────── */
const SavedPostsPage = ({ currentUser, onClose, showToast }) => {
  const [saved, setSaved] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!currentUser?.id) return;
    const q = query(collection(db, 'videos'), where('savedBy', 'array-contains', currentUser.id), orderBy('createdAt', 'desc'));
    const unsub = onSnapshot(q, snap => {
      setSaved(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      setLoading(false);
    }, () => setLoading(false));
    return () => unsub();
  }, [currentUser?.id]);

  return (
    <div style={{ position: 'fixed', inset: 0, background: COLORS.bg, zIndex:Z.page, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
        <div style={{ color: COLORS.textPrimary, fontWeight: 800, fontSize: 20 }}>Saved</div>
        <button onClick={onClose} aria-label="Close" style={{ background: COLORS.border, border: 'none', borderRadius: '50%', width: 32, height: 32, color: COLORS.textPrimary, cursor: 'pointer', fontSize: 16 }}>✕</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: 12 }}>
        {loading && <div style={{ textAlign: 'center', padding: 40 }}><div style={{ width: 28, height: 28, border: '3px solid rgba(11,95,255,0.3)', borderTop: `3px solid ${COLORS.brand}`, borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto' }} /></div>}
        {!loading && saved.length === 0 && (
          <div style={{ textAlign: 'center', padding: 60, color: COLORS.borderStrong }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>🔖</div>
            <div style={{ fontSize: 14 }}>No saved posts yet</div>
            <div style={{ fontSize: 12, marginTop: 6 }}>Tap the bookmark icon on any post to save it</div>
          </div>
        )}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 3 }}>
          {saved.map(v => (
            <div key={v.id} style={{ aspectRatio: '9/16', position: 'relative', overflow: 'hidden', borderRadius: 8, background: COLORS.surface4 }}>
              {v.videoUrl?.match(/\.(jpg|jpeg|png|gif|webp)/i) || v.mediaType?.startsWith('image')
                ? <ProgressiveImage src={v.videoUrl} alt="" style={{ width: '100%', height: '100%' }} />
                : <video src={v.videoUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} muted />}
              {Array.isArray(v.images) && v.images.length > 1 && (
                <svg width="16" height="16" viewBox="0 0 24 24" fill="white" style={{ position:'absolute', top:6, right:6, filter:'drop-shadow(0 1px 2px rgba(0,0,0,0.6))' }}><path d="M4 3h13a2 2 0 012 2v13h-2V5H4V3zm3 4h11a2 2 0 012 2v11a2 2 0 01-2 2H7a2 2 0 01-2-2V9a2 2 0 012-2z"/></svg>
              )}
              <div style={{ position: 'absolute', bottom: 4, left: 4, color: COLORS.textPrimary, fontSize: 10, fontWeight: 700, textShadow: '0 1px 3px rgba(0,0,0,0.8)' }}>{v.likes || 0} ❤️</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

/* TranslateButton removed — dead code, superseded by MessageTranslate (used in
   ConversationView/GroupChatPage), never rendered itself. */

/* ─────────────── INLINE MESSAGE TRANSLATE TOGGLE (chat & group messages) ─────────────── */
const MessageTranslate = ({ text, targetLang, isMine }) => {
  const [translated, setTranslated] = useState(null);
  const [showOriginal, setShowOriginal] = useState(false);
  const [loading, setLoading] = useState(false);
  if (!text || text.length < 2 || !targetLang || targetLang === 'en') return null;
  const toggle = async () => {
    if (translated) { setShowOriginal(s=>!s); return; }
    setLoading(true);
    const result = await liveTranslate(text, targetLang);
    setTranslated(result);
    setLoading(false);
  };
  return (
    <>
      {translated && !showOriginal && (
        <div style={{ fontSize:13, lineHeight:1.4, color: isMine?'rgba(255,255,255,0.9)':'rgba(255,255,255,0.85)', marginTop:4, paddingTop:4, borderTop:'1px solid rgba(255,255,255,0.12)' }}>{translated}</div>
      )}
      <button onClick={toggle} disabled={loading} style={{ background:'none', border:'none', color:'#2F9BFF', fontSize:10, cursor:'pointer', padding:0, marginTop:4, display:'block' }}>
        {loading ? '...' : translated ? (showOriginal ? '🌐 See translation' : '🌐 See original') : '🌐 Translate'}
      </button>
    </>
  );
};

/* ─────────────── STATUS / BROADCAST (v4 — like WhatsApp Status) ─────────────── */
const BroadcastPage = ({ currentUser, users, showToast, onClose }) => {
  const [text, setText] = useState('');
  const [bgColor, setBgColor] = useState(COLORS.brand);
  const [posting, setPosting] = useState(false);
  const colors = ['#0B5FFF','#2E7BFF','#083FB0','#FFB100','#2ED573','#00A9D6','#FF453A'];

  const postStatus = async () => {
    if (!text.trim()) { showToast?.('Write something first', 'error'); return; }
    setPosting(true);
    await addDoc(collection(db, 'broadcasts'), {
      userId: currentUser.id, username: currentUser.username, text: text.trim(),
      bgColor, createdAt: serverTimestamp(), expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000),
      seenBy: [], avatarUrl: currentUser.avatarUrl || null, avatarColor: currentUser.avatarColor
    });
    showToast?.('Status posted! 📡', 'success');
    setPosting(false);
    onClose();
  };

  return (
    <div style={{ position: 'fixed', inset: 0, zIndex:Z.page, background: bgColor, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <button onClick={onClose} style={{ background: 'rgba(0,0,0,0.3)', border: 'none', borderRadius: 20, padding: '8px 16px', color: 'white', cursor: 'pointer', fontSize: 13 }}>Cancel</button>
        <span style={{ color: 'white', fontWeight: 800, fontSize: 16 }}>Status</span>
        <button onClick={postStatus} disabled={posting} style={{ background: 'rgba(255,255,255,0.2)', border: 'none', borderRadius: 20, padding: '8px 16px', color: 'white', fontWeight: 700, cursor: 'pointer', fontSize: 13 }}>{posting ? '...' : 'Post'}</button>
      </div>
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 32 }}>
        <textarea value={text} onChange={e => setText(e.target.value)} placeholder="Write your status..." autoFocus style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: 28, fontWeight: 700, textAlign: 'center', width: '100%', resize: 'none', caretColor: 'white' }} rows={4} />
      </div>
      <div style={{ padding: '0 20px 40px', display: 'flex', justifyContent: 'center', gap: 12 }}>
        {colors.map(c => <div key={c} onClick={() => setBgColor(c)} style={{ width: 32, height: 32, borderRadius: '50%', background: c, border: c === bgColor ? '3px solid white' : '3px solid transparent', cursor: 'pointer' }} />)}
      </div>
    </div>
  );
};

/* ─────────────── DISCOVER / EXPLORE PAGE (v4 — like TikTok Discover) ─────────────── */
const DiscoverPage = ({ videos, users, onViewProfile, showToast, onClose, currentUser, onFollow, followed }) => {
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('all');
  const filters = [['all','All'],['video','Videos'],['people','People'],['hashtag','Tags']];
  const searchLower = search.toLowerCase();
  const filteredVideos = videos.filter(v =>
    (!search || v.description?.toLowerCase().includes(searchLower) || v.username?.toLowerCase().includes(searchLower))
    && (activeFilter === 'all' || activeFilter === 'video')
  );
  const filteredUsers = users.filter(u =>
    search && (u.username?.toLowerCase().includes(searchLower) || u.fullName?.toLowerCase().includes(searchLower))
    && (activeFilter === 'all' || activeFilter === 'people')
  );
  const filteredTags = TRENDING_HASHTAGS.filter(t =>
    (!search || t.toLowerCase().includes(searchLower))
    && (activeFilter === 'all' || activeFilter === 'hashtag')
  );

  return (
    <div style={{ position: 'fixed', inset: 0, background: COLORS.bg, zIndex:Z.page, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: '14px 16px', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
        <div style={{ display: 'flex', gap: 10, alignItems: 'center', marginBottom: 12 }}>
          <div style={{ flex: 1, background: COLORS.overlaySubtle, borderRadius: 24, display: 'flex', alignItems: 'center', padding: '10px 14px', gap: 8 }}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
            <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search Infinity..." autoFocus style={{ flex: 1, background: 'none', border: 'none', color: COLORS.textPrimary, outline: 'none', fontSize: 14 }} />
            {search && <button onClick={() => setSearch('')} aria-label="Clear search" style={{ background: 'none', border: 'none', color: COLORS.textTertiary, cursor: 'pointer', fontSize: 16 }}>✕</button>}
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', color: COLORS.textTertiary, cursor: 'pointer', fontSize: 14, padding: 4 }}>Cancel</button>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          {filters.map(([id, label]) => (
            <button key={id} onClick={() => setActiveFilter(id)} style={{ background: activeFilter === id ? 'rgba(11,95,255,0.15)' : COLORS.overlaySubtle, border: `1px solid ${activeFilter === id ? 'rgba(11,95,255,0.4)' : COLORS.border}`, borderRadius: 20, padding: '6px 14px', color: activeFilter === id ? COLORS.brand : COLORS.textTertiary, fontSize: 12, fontWeight: activeFilter === id ? 700 : 400, cursor: 'pointer' }}>{label}</button>
          ))}
        </div>
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: 12 }}>
        {!search && (
          <>
            <div style={{ color: COLORS.textTertiary, fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 10 }}>Trending</div>
            <TrendingHashtags onSearch={t => setSearch(t)} />
            <div style={{ color: COLORS.textTertiary, fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, margin: '20px 0 10px' }}>Suggested Creators</div>
            {users.slice(0, 6).map(u => (
              <div key={u.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 0', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
                <div onClick={() => { onViewProfile?.(u.id); onClose(); }} style={{ width: 44, height: 44, borderRadius: '50%', background: u.avatarColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: COLORS.textPrimary, fontWeight: 'bold', fontSize: 18, overflow: 'hidden', flexShrink: 0, cursor: 'pointer' }}>
                  {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" /> : u.avatar}
                </div>
                <div onClick={() => { onViewProfile?.(u.id); onClose(); }} style={{ flex: 1, cursor: 'pointer' }}>
                  <div style={{ color: COLORS.textPrimary, fontWeight: 700, fontSize: 14 }}>@{u.username}</div>
                  <div style={{ color: COLORS.textTertiary, fontSize: 12 }}>{formatNumber(u.followers?.length || 0)} followers</div>
                </div>
                {u.id !== currentUser?.id && (
                  <button onClick={e => { e.stopPropagation(); onFollow?.(u.id); }} style={{ flexShrink: 0, background: (followed || []).includes(u.id) ? COLORS.surfaceAlt : COLORS.gradient, color: (followed || []).includes(u.id) ? COLORS.textSecondary : '#fff', border: (followed || []).includes(u.id) ? `1px solid ${COLORS.border}` : 'none', borderRadius: 14, padding: '7px 16px', fontSize: 12.5, fontWeight: 700, cursor: 'pointer' }}>
                    {(followed || []).includes(u.id) ? 'Following' : 'Follow'}
                  </button>
                )}
              </div>
            ))}
          </>
        )}
        {search && filteredUsers.length > 0 && (
          <>
            <div style={{ color: COLORS.textTertiary, fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 10 }}>People</div>
            {filteredUsers.map(u => (
              <div key={u.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 0', borderBottom: `1px solid ${COLORS.overlaySubtle}` }}>
                <div onClick={() => { onViewProfile?.(u.id); onClose(); }} style={{ width: 44, height: 44, borderRadius: '50%', background: u.avatarColor, display: 'flex', alignItems: 'center', justifyContent: 'center', color: COLORS.textPrimary, fontWeight: 'bold', fontSize: 18, overflow: 'hidden', flexShrink: 0, cursor: 'pointer' }}>
                  {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" /> : u.avatar}
                </div>
                <div onClick={() => { onViewProfile?.(u.id); onClose(); }} style={{ flex: 1, cursor: 'pointer' }}>
                  <div style={{ color: COLORS.textPrimary, fontWeight: 700, fontSize: 14 }}>@{u.username}</div>
                  {u.verified && <span style={{ color: COLORS.info, fontSize: 11 }}>✓ Verified</span>}
                </div>
                {u.id !== currentUser?.id && (
                  <button onClick={e => { e.stopPropagation(); onFollow?.(u.id); }} style={{ flexShrink: 0, background: (followed || []).includes(u.id) ? COLORS.surfaceAlt : COLORS.gradient, color: (followed || []).includes(u.id) ? COLORS.textSecondary : '#fff', border: (followed || []).includes(u.id) ? `1px solid ${COLORS.border}` : 'none', borderRadius: 14, padding: '7px 16px', fontSize: 12.5, fontWeight: 700, cursor: 'pointer' }}>
                    {(followed || []).includes(u.id) ? 'Following' : 'Follow'}
                  </button>
                )}
              </div>
            ))}
          </>
        )}
        {search && filteredTags.length > 0 && (activeFilter === 'all' || activeFilter === 'hashtag') && (
          <>
            <div style={{ color: COLORS.textTertiary, fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, margin: '16px 0 10px' }}>Hashtags</div>
            {filteredTags.map(tag => (
              <div key={tag} style={{ padding: '10px 14px', background: COLORS.overlaySubtle, borderRadius: 14, marginBottom: 6, cursor: 'pointer', color: COLORS.brand, fontWeight: 700, fontSize: 14 }}>{tag}</div>
            ))}
          </>
        )}
        {search && (activeFilter === 'all' || activeFilter === 'video') && filteredVideos.length > 0 && (
          <>
            <div style={{ color: COLORS.textTertiary, fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 0.5, margin: '16px 0 10px' }}>Videos</div>
            <motion.div variants={listContainerVariants} initial="hidden" animate="visible" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              {filteredVideos.slice(0, 8).map(v => (
                <motion.div key={v.id} variants={listItemVariants} style={{ aspectRatio: '9/16', position: 'relative', borderRadius: 14, overflow: 'hidden', background: COLORS.surface4 }}>
                  {v.videoUrl?.match(/\.(jpg|jpeg|png|gif|webp)/i) || v.mediaType?.startsWith('image')
                    ? <img loading="lazy" decoding="async" src={v.videoUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    : <video src={v.videoUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} muted />}
                  <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, background: 'linear-gradient(transparent,rgba(0,0,0,0.7))', padding: '20px 8px 8px' }}>
                    <div style={{ color: COLORS.textPrimary, fontSize: 11, fontWeight: 600 }}>@{v.username}</div>
                  </div>
                </motion.div>
              ))}
            </motion.div>
          </>
        )}
      </div>
    </div>
  );
};

/* ─────────────── DARK/LIGHT MODE ─────────────── */
// (Previously an unfinished useTheme() hook lived here — it computed its own isDark/colors
// object but nothing ever read them, and its toggleTheme wrote to Firestore but never fed
// back into the actual COLORS tokens the rest of the app renders with. Removed in favor of
// the applyTheme()/COLORS_DARK system in src/lib/theme.js, wired up in InfinityV1app below.)

/* ─────────────── SEND NOTIFICATION HELPER (v4 — already defined below, re-export alias) ─────────────── */
// Title shown by the OS notification (lock screen / notification tray) per type — kept
// short since some platforms truncate aggressively. `message` is the existing in-app
// copy (e.g. "sent you a message") and becomes the push body, prefixed with @username
// by the caller where that context is available.
const sendNotification = async (toUserId, fromUserId, type, message, extra = {}) => {
  if (!toUserId || toUserId === fromUserId) return;
  const { fromUsername, ...docExtra } = extra; // fromUsername is push-only, never stored
  try {
    await addDoc(collection(db, 'notifications'), {
      toUserId, fromUserId, type, message,
      read: false, createdAt: serverTimestamp(), ...docExtra,
    });
  } catch (e) { console.log('Notification error:', e); }
  // Fire-and-forget the actual push — this is what reaches the device when the
  // app is backgrounded/closed. In-app Firestore doc above still drives the
  // in-app toast/badge regardless of whether this succeeds.
  try {
    const pushBody = fromUsername ? `@${fromUsername} ${message}` : message;
    await apiFetch('/api/notifications/send', {
      method: 'POST',
      body: JSON.stringify({ toUserId, title: pushTitleForType(type), body: pushBody, type, data: docExtra?.link ? { link: docExtra.link } : undefined }),
    });
  } catch (e) { /* push is best-effort; in-app notification already landed */ }
};

/* ─────────────── CLOUDINARY UPLOAD ─────────────── */
/* ─────────────── CLOUDINARY UPLOAD (SIGNED) ─────────────── */
// Signed uploads keep the API secret server-side (never shipped to the browser) and
// gate every upload behind requireAuth + rate limiting in /api/cloudinary-sign.
// Deliberately signs *only* `timestamp` — no upload_preset — since a preset is one
// more thing that has to exist, match "signed" mode, and be spelled identically on
// both ends; dropping it removes that whole class of "Invalid Signature"/"preset not
// found" failures. The upload itself goes to the bare `/upload` endpoint (no
// resource_type segment), which auto-detects image vs video.
const uploadToCloudinary = async (file, onProgress) => {
  const { signature, timestamp, apiKey, cloudName } = await apiFetch('/api/cloudinary-sign', { method: 'POST' });

  const formData = new FormData();
  formData.append('file', file);
  formData.append('api_key', apiKey);
  formData.append('timestamp', timestamp);
  formData.append('signature', signature);

  // Must include the resource_type segment (Cloudinary requires it — a bare
  // `/upload` with nothing before it is not a valid endpoint path). `auto` lets
  // Cloudinary detect image vs video vs raw itself, so this one endpoint handles
  // every upload type used in this app (photos, videos, audio notes).
  const uploadUrl = `https://api.cloudinary.com/v1_1/${cloudName}/auto/upload`;

  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.upload.onprogress = (e) => {
      if (e.lengthComputable && onProgress) {
        onProgress(Math.round((e.loaded / e.total) * 100));
      }
    };
    xhr.onload = () => {
      if (xhr.status === 200) {
        const data = JSON.parse(xhr.responseText);
        resolve(data.secure_url);
      } else {
        console.error('Cloudinary response:', xhr.responseText);
        let message = `Upload failed (${xhr.status})`;
        try {
          const parsed = JSON.parse(xhr.responseText);
          if (parsed?.error?.message) message = parsed.error.message;
        } catch {}
        reject(new Error(message));
      }
    };
    xhr.onerror = () => reject(new Error('Upload error — check your connection and try again'));
    xhr.open('POST', uploadUrl);
    xhr.send(formData);
  });
};
// Turns a list of {file,type} media items plus their already-uploaded Cloudinary URLs
// into the correct {videoUrl, images, mediaType} shape the feed renderer expects.
// Mirrors the working camera-upload flow's convention: mediaType is the real MIME
// type (or 'image/multi' for a multi-photo post), and videoUrl is always populated
// so `mediaSrc = images[0] || videoUrl` resolves correctly no matter the media type.
// (Previously CreateScreen/QuickComposer hardcoded mediaType to the literal string
// 'image' any time media existed and never set videoUrl at all — so an uploaded
// video landed in `images` labeled as an image, which the feed then tried to render
// with an <img> tag instead of <video>, silently failing to display.)
/* ─────────────── EMAILJS SEND ─────────────── */
const sendEmailJS = async (templateParams) => {
  try {
    const res = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        service_id: EMAILJS_SERVICE,
        template_id: EMAILJS_TEMPLATE,
        user_id: EMAILJS_PUBLIC_KEY,
        template_params: templateParams,
      }),
    });
    return res.status === 200;
  } catch { return false; }
};

/* ─────────────── FIREBASE HELPERS ─────────────── */
// Shared defaults for a brand-new user profile. Used by createUserProfile (Firestore)
// and by the local/in-memory fallback profiles used when a Firestore write hasn't
// propagated yet. Keeping this in one place avoids the 3-way drift that existed
// between createUserProfile and the two inline fallback objects in <AuthScreen>
// and the onAuthStateChanged handler.
// PUBLIC doc (users/{uid}) — readable by any authenticated user (the app has no backend,
// so the feed/search/comments/follow-lists all read this collection directly). Never put
// anything here you wouldn't want any logged-in user to see.
const buildDefaultProfile = (uid, data = {}) => ({
  id: uid,
  username: data.username || '',
  usernameLower: (data.username || '').toLowerCase(),
  fullName: data.fullName || '',
  email: data.email || '', // kept public/queryable — Google sign-in account-linking looks
                            // up existing users by email and there's no backend to proxy that
  avatar: (data.username || data.fullName || data.email || 'U')[0].toUpperCase(),
  avatarColor: data.avatarColor || pickAvatarColor(uid),
  avatarUrl: data.avatarUrl || null,
  bio: data.bio || 'New to Infinity! 🎬',
  link: '',
  gender: '',
  publicPhone: '', // opt-in mirror of the private phone number; see PrivacyToggles
  verified: false,
  followers: [],
  following: [],
  friends: [], // mutual, accepted friend connections — separate from the one-way follow graph
  friendRequestsSent: [],
  friendRequestsReceived: [],
  closeFriends: [], // starred subset of `friends`, surfaced at the top of the Friends tab
  blockedUsers: [],
  coins: 500,
  walletBalance: 500,
  level: 1,
  streak: 1,
  subscription: 'free',
});

// PRIVATE doc (users/{uid}/private/contact) — owner-read-only per firestore.rules.
// email is intentionally kept OUT of this (see note in signup/Google-auth flows): the app
// looks up existing accounts by email with no backend, which requires it to stay queryable
// on the public collection. Only phone and birthdate — which have no such requirement — are
// isolated here.
const buildPrivateContact = (data = {}) => ({
  phone: data.phone || '',
  birthdate: data.birthdate || '',
});

// Fields that must never be silently overwritten by a later merge — either because they're
// balances that should only ever change via increment()/explicit transactions (coins,
// walletBalance), or because they're relationship data owned by toggleFollow, not profile
// edits (followers, following). Re-including these on a merge-update also used to trip the
// Firestore rule that blocks coins/walletBalance writes outside dedicated flows, which was
// the root cause of the repeated-Google-signin bug.
const PROTECTED_PROFILE_FIELDS = ['coins', 'walletBalance', 'followers', 'following', 'friends', 'friendRequestsSent', 'friendRequestsReceived', 'closeFriends'];

const createUserProfile = async (uid, data) => {
  const userRef = doc(db, 'users', uid);
  const existing = await getDoc(userRef);

  if (!existing.exists()) {
    // First-time creation: write the full public default profile (including starting
    // coins/walletBalance) plus the private contact doc alongside it.
    await setDoc(userRef, {
      ...buildDefaultProfile(uid, data),
      createdAt: serverTimestamp(),
    });
  } else {
    // Re-invocation (e.g. Google sign-in firing again before propagation, or a profile
    // check on an existing account): only merge safe public fields, never the protected
    // ones, so we can't reset coins/walletBalance or violate the update rule.
    const publicDefaults = buildDefaultProfile(uid, data);
    PROTECTED_PROFILE_FIELDS.forEach(f => delete publicDefaults[f]);
    await setDoc(userRef, publicDefaults, { merge: true });
  }

  const privateRef = doc(db, 'users', uid, 'private', 'contact');
  await setDoc(privateRef, buildPrivateContact(data), { merge: true });
};

// Only ever called with the caller's own uid (audited across the codebase), so it's safe to
// also read the owner-only private subcollection here and merge it into the returned object.
const getUserProfile = async (uid) => {
  const snap = await getDoc(doc(db, 'users', uid));
  if (!snap.exists()) return null;
  const publicData = snap.data();
  try {
    const privateSnap = await getDoc(doc(db, 'users', uid, 'private', 'contact'));
    if (privateSnap.exists()) return { ...publicData, ...privateSnap.data() };
  } catch (e) {
    console.log('Private profile fetch failed (rules should prevent this only for non-owners):', e);
  }
  return publicData;
};

