/* ─────────────── LIKES MODAL (image 8) ─────────────── */
const LikesModal = ({ video, currentUser, users, onClose, onFollow, followed, onViewProfile }) => {
  const [tab, setTab] = useState('all');
  const likers = useMemo(() => {
    const ids = video?.likedBy || [];
    return ids.map(id => users?.find(u => u.id === id)).filter(Boolean);
  }, [video, users]);
  const count = video?.likes || likers.length;
  return (
    <motion.div
      variants={pageVariants} initial="hidden" animate="visible" exit="exit"
      style={{ position:'fixed', inset:0, zIndex:Z.modal, background:COLORS.surface, display:'flex', flexDirection:'column' }}>
      <SheetBackHeader title="Likes" onClose={onClose} />
      <div style={{ textAlign:'center', padding:'22px 16px 6px' }}>
        <div style={{ width:52, height:52, borderRadius:'50%', background:COLORS.gradient, display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 10px' }}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="white"><path d="M12 21s-7.5-4.6-10-9.2C.4 8 2 4 6 4c2.2 0 3.7 1.2 4.5 2.4C11.3 5.2 12.8 4 15 4c4 0 5.6 4 4 7.8-2.5 4.6-10 9.2-10 9.2z"/></svg>
        </div>
        <div style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:19 }}>{formatNumber(count)} Likes</div>
      </div>
      <div style={{ display:'flex', gap:26, padding:'16px 16px 0', borderBottom:`1px solid ${COLORS.border}` }}>
        {[{id:'all',label:'All'},{id:'people',label:'People'}].map(tb => (
          <button key={tb.id} onClick={()=>setTab(tb.id)} style={{ background:'none', border:'none', cursor:'pointer', padding:'0 0 12px', color:tab===tb.id?COLORS.brand:COLORS.textTertiary, fontWeight:700, fontSize:14, borderBottom:tab===tb.id?`2.5px solid ${COLORS.brand}`:'2.5px solid transparent' }}>{tb.label}</button>
        ))}
      </div>
      <div style={{ flex:1, overflowY:'auto', padding:'8px 16px' }}>
        {!likers.length && <div style={{ textAlign:'center', color:COLORS.textTertiary, padding:'40px 0', fontSize:13 }}>No likes yet</div>}
        {likers.map(u => (
          <div key={u.id} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0' }}>
            <div onClick={()=>onViewProfile?.(u.id)} style={{ width:46, height:46, borderRadius:'50%', background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, overflow:'hidden', flexShrink:0, cursor:'pointer' }}>
              {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt="" /> : (u.username||'?')[0]?.toUpperCase()}
            </div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:14 }}>{u.fullName || u.username}</div>
              <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}</div>
            </div>
            <button onClick={()=>onFollow?.(u.id)} style={{ background:followed?.includes(u.id)?COLORS.surfaceAlt:COLORS.gradient, color:followed?.includes(u.id)?COLORS.textSecondary:'#fff', border:'none', borderRadius:14, padding:'7px 16px', fontSize:12.5, fontWeight:700, cursor:'pointer' }}>{followed?.includes(u.id)?'Following':'Follow'}</button>
          </div>
        ))}
      </div>
    </motion.div>
  );
};

/* ─────────────── COMMENTS MODAL (image 9) ─────────────── */
const CommentsModal = ({ video, currentUser, onClose, showToast, onViewProfile }) => {
  const [comments, setComments] = useState([]);
  const [commentText, setCommentText] = useState('');
  // Tracks the VoiceRecorderButton's internal state (idle/recording/paused/preview)
  // so the composer row can stop forcing it into a fixed 42px circle once it expands
  // — that fixed circle was clipping the waveform/timer/send UI off the right edge.
  const [cmVoiceState, setCmVoiceState] = useState('idle');
  const commentInputRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState(false);
  const cmFileInputRef = useRef(null);
  const cmCameraInputRef = useRef(null);
  const [cmAttachment, setCmAttachment] = useState(null);
  const cmPickFile = e => { const f=e.target.files[0]; if(f){setCmAttachment({url:URL.createObjectURL(f),file:f,type:f.type}); e.target.value='';} };
  // Real in-app camera capture, matching the composer's live getUserMedia flow
  // elsewhere — "Take photo" always opens an actual camera instead of relying
  // on <input capture>, which many desktop/browser contexts silently ignore.
  const [showCameraCapture, setShowCameraCapture] = useState(false);
  const cmCameraVideoRef = useRef(null);
  const cmCameraStreamRef = useRef(null);
  const openCmCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      cmCameraStreamRef.current = stream;
      setShowCameraCapture(true);
    } catch {
      cmCameraInputRef.current?.click();
    }
  };
  const closeCmCamera = () => {
    cmCameraStreamRef.current?.getTracks().forEach(t => t.stop());
    cmCameraStreamRef.current = null;
    setShowCameraCapture(false);
  };
  useEffect(() => {
    if (showCameraCapture && cmCameraVideoRef.current && cmCameraStreamRef.current) {
      cmCameraVideoRef.current.srcObject = cmCameraStreamRef.current;
    }
  }, [showCameraCapture]);
  const captureCmPhoto = () => {
    const video = cmCameraVideoRef.current;
    if (!video) return;
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    canvas.getContext('2d').drawImage(video, 0, 0);
    canvas.toBlob(blob => {
      if (blob) setCmAttachment({ url: URL.createObjectURL(blob), file: blob, type: 'image/jpeg' });
      closeCmCamera();
    }, 'image/jpeg', 0.92);
  };
  const sendCommentVoice = async (voiceMsg) => {
    try {
      await addDoc(collection(db, 'comments'), { videoId: video.id, userId: currentUser.id, username: currentUser.username, avatar: currentUser.avatar || (currentUser.username||'U')[0].toUpperCase(), avatarColor: currentUser.avatarColor || COLORS.brand, avatarUrl: currentUser.avatarUrl || null, text: '', mediaUrl: voiceMsg.url, mediaType: 'audio', duration: voiceMsg.duration, likes: 0, createdAt: serverTimestamp() });
      await updateDoc(doc(db, 'videos', video.id), { comments: increment(1) });
    } catch { showToast?.('Failed to post voice comment', 'error'); }
  };

  useEffect(() => {
    if (!video?.id) return;
    setLoading(true);
    setLoadError(false);
    // The compound query (where + orderBy on different fields) needs a Firestore
    // composite index. If that index hasn't been created yet, onSnapshot's error
    // callback fires and — since there wasn't one before — the list just silently
    // stayed empty forever with no indication anything had gone wrong. Falling back
    // to the where-only query (sorted client-side) means comments still show even
    // before/without that index, matching the same fallback pattern already used
    // for stories.
    const primaryQ = query(collection(db, 'comments'), where('videoId', '==', video.id), orderBy('createdAt', 'desc'));
    let fallbackUnsub = null;
    const unsub = onSnapshot(primaryQ, snap => {
      setComments(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      setLoading(false);
    }, () => {
      const fallbackQ = query(collection(db, 'comments'), where('videoId', '==', video.id));
      fallbackUnsub = onSnapshot(fallbackQ, snap => {
        const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
        list.sort((a, b) => (b.createdAt?.toMillis?.() || 0) - (a.createdAt?.toMillis?.() || 0));
        setComments(list);
        setLoading(false);
      }, () => { setLoading(false); setLoadError(true); });
    });
    return () => { unsub(); fallbackUnsub?.(); };
  }, [video?.id]);

  const likeComment = async (id) => {
    try { await updateDoc(doc(db, 'comments', id), { likes: increment(1) }); } catch {}
  };

  // Comment moderation: report (anyone but the author) or delete (author or admin).
  // Comments previously had zero moderation surface — no way to flag one, and no
  // way for the person who wrote it (or an admin) to take it down.
  const [reportTarget, setReportTarget] = useState(null); // comment being reported
  const [openMenuFor, setOpenMenuFor] = useState(null); // comment id with the ⋯ menu open

  const submitCommentReport = async (reason) => {
    const c = reportTarget;
    if (!c) return;
    try {
      await submitReport('comment', c.id, currentUser.id, {
        commentId: c.id,
        commentText: c.text || '',
        commentUserId: c.userId || null,
        commentUsername: c.username || null,
        videoId: video?.id || null,
        videoThumbUrl: video?.thumbUrl || video?.thumbnailUrl || video?.url || null,
        reporterUsername: currentUser?.username || currentUser?.fullName || null,
        reason,
      });
      showToast?.('Comment reported — thanks for letting us know', 'success');
    } catch (e) {
      showToast?.(e.message || 'Could not submit report', e.duplicate ? 'info' : 'error');
    }
    setReportTarget(null);
  };

  const deleteComment = async (c) => {
    if (!(await confirmDialog('Delete this comment? This cannot be undone.'))) return;
    try {
      await deleteDoc(doc(db, 'comments', c.id));
      await updateDoc(doc(db, 'videos', video.id), { comments: increment(-1) }).catch(()=>{});
      setComments(prev => prev.filter(x => x.id !== c.id));
      showToast?.('Comment deleted', 'success');
    } catch (e) {
      showToast?.('Could not delete comment', 'error');
    }
    setOpenMenuFor(null);
  };

  const send = async () => {
    if (!commentText.trim() && !cmAttachment) return;
    try {
      // AI content check — the only moderation that previously existed anywhere in the
      // app was on video-post captions; comments (the most common place for one user to
      // harass another) went straight to Firestore unchecked. Same OpenAI moderation
      // model as post creation; requires OPENAI_API_KEY to be set to actually run.
      if (commentText.trim()) {
        try {
          const modResult = await apiFetch('/api/moderation/check', { method: 'POST', body: JSON.stringify({ text: commentText }) });
          if (modResult?.blocked) {
            showToast?.('This comment looks like it may violate our community guidelines and was not posted.', 'error');
            return;
          }
        } catch (e) {
          // Fail open on a moderation-service hiccup — don't block a legitimate comment
          // just because the check itself errored (network blip, rate limit, etc.).
        }
      }
      let mediaUrl = null, mediaType = null;
      if (cmAttachment?.file) {
        try { mediaUrl = await uploadToCloudinary(cmAttachment.file); mediaType = cmAttachment.type; }
        catch { showToast?.('Upload failed', 'error'); return; }
      }
      await addDoc(collection(db, 'comments'), { videoId: video.id, userId: currentUser.id, username: currentUser.username, avatar: currentUser.avatar || (currentUser.username||'U')[0].toUpperCase(), avatarColor: currentUser.avatarColor || COLORS.brand, avatarUrl: currentUser.avatarUrl || null, text: commentText, mediaUrl, mediaType, likes: 0, createdAt: serverTimestamp() });
      await updateDoc(doc(db, 'videos', video.id), { comments: increment(1) });
    } catch { showToast?.('Failed to post comment', 'error'); }
    setCommentText(''); setCmAttachment(null);
  };

  return (
    <motion.div
      variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
      onClick={onClose} style={{ position:'fixed', inset:0, zIndex:Z.modal, background:'rgba(15,10,25,0.5)', display:'flex', alignItems:'flex-end', maxWidth:430, margin:'0 auto' }}>
      <motion.div
        variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
        onClick={e=>e.stopPropagation()} style={{ width:'100%', height:'58vh', maxHeight:520, background:COLORS.surface, borderTopLeftRadius:24, borderTopRightRadius:24, display:'flex', flexDirection:'column' }}>
      <div style={{ display:'flex', justifyContent:'center', paddingTop:8 }}>
        <div style={{ width:36, height:4, borderRadius:2, background:COLORS.border }} />
      </div>
      <div style={{ display:'flex', alignItems:'center', gap:14, padding:'10px 16px 14px', borderBottom:`1px solid ${COLORS.border}` }}>
        <div style={{ flex:1, color:COLORS.textPrimary, fontWeight:800, fontSize:16, textAlign:'center' }}>{comments.length} Comments</div>
        <button onClick={onClose} aria-label="Close" style={{ position:'absolute', right:16, background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, padding:4, display:'flex' }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div style={{ flex:1, overflowY:'auto', padding:'14px 16px' }}>
        {loading && <div style={{ textAlign:'center', color:COLORS.textTertiary, padding:'40px 0', fontSize:13 }}>Loading comments…</div>}
        {!loading && loadError && <div style={{ textAlign:'center', color:COLORS.textTertiary, padding:'40px 0', fontSize:13 }}>Couldn't load comments. Pull down to try again.</div>}
        {!loading && !loadError && !comments.length && <div style={{ textAlign:'center', color:COLORS.textTertiary, padding:'40px 0', fontSize:13 }}>Be the first to comment</div>}
        {comments.map(c => {
          const isOwn = c.userId === currentUser?.id;
          const canModerate = isOwn || currentUser?.isAdmin;
          return (
          <div key={c.id} style={{ display:'flex', gap:10, marginBottom:18 }}>
            <div onClick={()=>onViewProfile?.(c.userId)} style={{ width:38, height:38, borderRadius:'50%', background:c.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:13, overflow:'hidden', flexShrink:0, cursor:'pointer' }}>
              {c.avatarUrl ? <img loading="lazy" decoding="async" src={c.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt="" /> : (c.avatar||'U')}
            </div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ display:'flex', alignItems:'baseline', gap:8 }}>
                <span style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{c.username}</span>
                <span style={{ color:COLORS.textTertiary, fontSize:11.5, marginLeft:'auto' }}>{c.createdAt?.toDate ? timeAgo(c.createdAt.toDate()) : 'now'}</span>
                <div style={{ position:'relative' }}>
                  <button onClick={()=>setOpenMenuFor(m=>m===c.id?null:c.id)} aria-label="More options" style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, padding:'2px 4px', display:'flex' }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><circle cx="5" cy="12" r="1.8"/><circle cx="12" cy="12" r="1.8"/><circle cx="19" cy="12" r="1.8"/></svg>
                  </button>
                  {openMenuFor === c.id && (
                    <div style={{ position:'absolute', top:'calc(100% + 4px)', right:0, background:COLORS.surface3, border:`1px solid ${COLORS.border}`, borderRadius:12, padding:4, zIndex:10, minWidth:120, boxShadow:'0 8px 24px rgba(0,0,0,0.3)' }}>
                      {!isOwn && (
                        <div onClick={()=>{ setReportTarget(c); setOpenMenuFor(null); }} style={{ padding:'8px 10px', borderRadius:8, color:COLORS.textPrimary, fontSize:12.5, cursor:'pointer' }}>Report</div>
                      )}
                      {canModerate && (
                        <div onClick={()=>deleteComment(c)} style={{ padding:'8px 10px', borderRadius:8, color:COLORS.dangerText, fontSize:12.5, cursor:'pointer' }}>Delete</div>
                      )}
                    </div>
                  )}
                </div>
              </div>
              {c.mediaUrl && c.mediaType?.startsWith('image') && (
                <img loading="lazy" decoding="async" src={c.mediaUrl} alt="" style={{ maxWidth:200, borderRadius:12, marginTop:6, display:'block' }} />
              )}
              {c.mediaUrl && c.mediaType?.startsWith('video') && (
                <video src={c.mediaUrl} controls style={{ maxWidth:200, borderRadius:12, marginTop:6, display:'block' }} />
              )}
              {c.mediaUrl && c.mediaType?.startsWith('audio') && (
                <div style={{ marginTop: 6 }}>
                  <VoiceMessagePro src={c.mediaUrl} duration={c.duration} seed={c.id || c.mediaUrl} compact
                    msg={c} msgRef={doc(db,'comments',c.id)} showToast={showToast} />
                </div>
              )}
              {c.text && <div style={{ color:COLORS.textSecondary, fontSize:13.5, lineHeight:1.45, marginTop:2 }}>{c.text}</div>}
              <div style={{ display:'flex', alignItems:'center', gap:16, marginTop:6 }}>
                <button onClick={()=>likeComment(c.id)} style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, fontSize:12, fontWeight:600 }}>Like</button>
                <button onClick={()=>{ setCommentText(txt => txt.startsWith(`@${c.username} `) ? txt : `@${c.username} `); commentInputRef.current?.focus(); }} style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, fontSize:12, fontWeight:600 }}>Reply</button>
              </div>
            </div>
            <button onClick={()=>likeComment(c.id)} style={{ background:'none', border:'none', cursor:'pointer', display:'flex', flexDirection:'column', alignItems:'center', gap:3, color:COLORS.textTertiary, flexShrink:0 }}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg>
              <span style={{ fontSize:11 }}>{c.likes||0}</span>
            </button>
          </div>
          );
        })}
      </div>
      <AnimatePresence>{reportTarget && (
        <ReportReasonSheet
          title="Report Comment"
          onClose={()=>setReportTarget(null)}
          onSubmit={submitCommentReport}
        />
      )}</AnimatePresence>
      {cmAttachment && (
        <div style={{ padding:'0 16px 6px' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10, background:COLORS.overlaySubtle, borderRadius:14, padding:'8px 12px' }}>
            {cmAttachment.type?.startsWith('image') && <img loading="lazy" decoding="async" src={cmAttachment.url} alt="" style={{ height:44, width:44, objectFit:'cover', borderRadius:8 }}/>}
            {cmAttachment.type?.startsWith('video') && <video src={cmAttachment.url} style={{ height:44, width:60, objectFit:'cover', borderRadius:8 }}/>}
            <button onClick={()=>setCmAttachment(null)} aria-label="Remove attachment" style={{ marginLeft:'auto', background:'rgba(11,95,255,0.2)', border:'none', borderRadius:'50%', width:22, height:22, color:COLORS.brand, cursor:'pointer', fontSize:13 }}>✕</button>
          </div>
        </div>
      )}
      <div style={{ display:'flex', alignItems:'center', gap:8, padding:'10px 16px max(16px, env(safe-area-inset-bottom))', background:COLORS.surface, borderTop:`1px solid ${COLORS.border}` }}>
        {cmVoiceState === 'idle' && (
          <div style={{ flex:1, minWidth:0, display:'flex', alignItems:'center', gap:2, background:COLORS.surfaceAlt, borderRadius:26, padding:'4px 6px 4px 12px' }}>
            <input ref={commentInputRef} value={commentText} onChange={e=>setCommentText(e.target.value)} onKeyDown={e=>e.key==='Enter'&&send()} placeholder="Add a comment..." style={{ flex:1, minWidth:0, background:'none', border:'none', outline:'none', color:COLORS.textPrimary, fontSize:13.5, padding:'9px 4px' }} />
            <button onClick={()=>cmFileInputRef.current?.click()} aria-label="Attach photo" style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, flexShrink:0, display:'flex', padding:5 }}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/></svg>
            </button>
            <button onClick={openCmCamera} aria-label="Take photo" style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, flexShrink:0, display:'flex', padding:5 }}>
              <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/><circle cx="12" cy="13" r="4"/></svg>
            </button>
          </div>
        )}
        <input ref={cmFileInputRef} type="file" accept="image/*,video/*" onChange={cmPickFile} style={{ display:'none' }} />
        <input ref={cmCameraInputRef} type="file" accept="image/*" capture="environment" onChange={cmPickFile} style={{ display:'none' }} />
        <AnimatePresence initial={false}>
          {(commentText.trim() || cmAttachment) ? (
            <motion.button key="send" initial={{ scale:0.5, opacity:0 }} animate={{ scale:1, opacity:1 }} exit={{ scale:0.5, opacity:0 }} transition={springs.snappy} whileTap={tapScale} onClick={send} aria-label="Send comment" style={{ background:COLORS.gradient, border:'none', borderRadius:'50%', width:42, height:42, color:'white', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="white" stroke="white" strokeWidth="1"><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            </motion.button>
          ) : (
            // Wrapper stays mounted (same key) across idle → recording → preview so the
            // in-progress recording is never torn down mid-flow. Only its *style* changes:
            // a fixed 42px circle while idle (just the mic glyph), but flex:1 with no fixed
            // width once recording/paused/preview so the waveform, timer, cancel and send
            // controls have the full row to render in — previously the fixed circle clipped
            // this content and pushed Send off the visible screen edge.
            <motion.div key="voice" initial={{ scale:0.5, opacity:0 }} animate={{ scale:1, opacity:1 }} exit={{ scale:0.5, opacity:0 }} transition={springs.snappy}
              style={ cmVoiceState === 'idle'
                ? { background:COLORS.gradient, borderRadius:'50%', width:42, height:42, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }
                : { flex:1, minWidth:0, display:'flex', alignItems:'center' } }>
              <VoiceRecorderButton showToast={showToast} size="small" onSend={sendCommentVoice} onStateChange={setCmVoiceState} />
            </motion.div>
          )}
        </AnimatePresence>
      </div>
      <AnimatePresence>{showCameraCapture && (
        <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }} style={{ position:'fixed', inset:0, background:'#000', zIndex:Z.modal, display:'flex', flexDirection:'column' }}>
          <div style={{ padding:16, display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <button onClick={closeCmCamera} style={{ background:'rgba(255,255,255,0.12)', border:'none', borderRadius:20, padding:'8px 16px', color:'white', cursor:'pointer', fontSize:13 }}>Cancel</button>
            <span style={{ color:'white', fontWeight:700, fontSize:15 }}>Camera</span>
            <div style={{ width:70 }} />
          </div>
          <div style={{ flex:1, position:'relative', overflow:'hidden' }}>
            <video ref={cmCameraVideoRef} autoPlay playsInline muted style={{ width:'100%', height:'100%', objectFit:'cover', transform:'scaleX(-1)' }} />
            <button onClick={captureCmPhoto} aria-label="Capture photo" style={{ position:'absolute', bottom:30, left:'50%', transform:'translateX(-50%)', background:'white', border:'4px solid rgba(255,255,255,0.4)', borderRadius:'50%', width:72, height:72, cursor:'pointer' }} />
          </div>
        </motion.div>
      )}</AnimatePresence>
      </motion.div>
    </motion.div>
  );
};

/* ─────────────── SAVE CONFIRM SHEET (image 11) ─────────────── */
const SaveConfirmSheet = ({ onClose, onViewCollections }) => (
  <motion.div
    variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
    style={{ position:'fixed', inset:0, zIndex:Z.drawer, background:'rgba(20,15,35,0.45)', display:'flex', alignItems:'flex-end' }} onClick={onClose}>
    <motion.div
      variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
      onClick={e=>e.stopPropagation()} style={{ width:'100%', background:COLORS.surface, borderTopLeftRadius:26, borderTopRightRadius:26, paddingBottom:'max(24px, env(safe-area-inset-bottom))' }}>
      <SheetBackHeader title="Save" onClose={onClose} />
      <div style={{ textAlign:'center', padding:'34px 24px 8px' }}>
        <div style={{ width:64, height:64, borderRadius:20, background:COLORS.gradient, display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 18px' }}>
          <svg width="26" height="26" viewBox="0 0 24 24" fill="white"><path d="M6 2a2 2 0 00-2 2v18l8-6 8 6V4a2 2 0 00-2-2z"/></svg>
        </div>
        <div style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:19, marginBottom:8 }}>Saved!</div>
        <div style={{ color:COLORS.textTertiary, fontSize:13.5, lineHeight:1.5, marginBottom:26 }}>This post has been saved to your collection.</div>
        <button onClick={onViewCollections} style={{ width:'100%', background:COLORS.gradient, border:'none', borderRadius:16, padding:'14px', color:'#fff', fontWeight:700, fontSize:14.5, cursor:'pointer' }}>View Collections</button>
      </div>
    </motion.div>
  </motion.div>
);

/* ─────────────── POST OPTIONS MENU (image 12) ─────────────── */
const PostOptionsMenu = ({ video, currentUser, onClose, showToast, onDelete, onBlock }) => {
  const isMine = video?.userId === currentUser?.id;
  const name = video?.fullName || video?.username || 'User';
  const [showReportSheet, setShowReportSheet] = useState(false);
  const alreadyReposted = (video?.repostedBy || []).includes(currentUser?.id);
  const doRepost = async () => {
    if (!currentUser?.id) { showToast?.('Log in to repost', 'error'); return; }
    try {
      const { reposted } = await toggleRepost(video, currentUser);
      showToast?.(reposted ? 'Reposted to your profile' : 'Repost removed', 'success');
    } catch {
      showToast?.('Could not update repost', 'error');
    }
  };
  const doPin = async () => {
    if (!video?.id) return;
    const next = !video.pinned;
    try {
      await updateDoc(doc(db, 'videos', video.id), { pinned: next });
      showToast?.(next ? 'Pinned to profile' : 'Unpinned', 'success');
    } catch {
      showToast?.('Could not update pin', 'error');
    }
  };
  const alreadySaved = (video?.savedBy || []).includes(currentUser?.id);
  const doAddToCollection = async () => {
    if (!video?.id || !currentUser?.id) return;
    const next = !alreadySaved;
    try {
      await updateDoc(doc(db, 'videos', video.id), { savedBy: next ? arrayUnion(currentUser.id) : arrayRemove(currentUser.id) });
      showToast?.(next ? 'Added to your saved collection' : 'Removed from saved collection', 'success');
    } catch {
      showToast?.('Could not update collection', 'error');
    }
  };
  const submitPostReport = async (reason) => {
    try {
      await submitReport('video', video?.id, currentUser.id, {
        videoId: video?.id || null,
        reporterUsername: currentUser.username || currentUser.fullName || null,
        reason,
        // Denormalized snapshot so the moderation screen can show what was reported
        // even if the post is later edited or deleted.
        videoUsername: video?.username || null,
        videoUserId: video?.userId || null,
        videoCaption: video?.description || video?.caption || null,
        videoThumbUrl: video?.thumbUrl || video?.thumbnailUrl || video?.url || null,
      });
      showToast?.('Post reported — thanks for letting us know', 'success');
    } catch (e) {
      showToast?.(e.message || 'Could not submit report', e.duplicate ? 'info' : 'error');
    }
    setShowReportSheet(false);
    onClose();
  };
  const items = [
    { label: video?.pinned ? 'Unpin Post' : 'Pin Post', show:isMine, action:doPin, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={video?.pinned?COLORS.brand:'currentColor'} strokeWidth="2"><line x1="12" y1="17" x2="12" y2="22"/><path d="M5 17h14l-1.4-7.5A3 3 0 0014.66 7H9.34a3 3 0 00-2.94 2.5z"/></svg>) },
    { label:'Share', show:true, action:()=>shareToDevice({
        url:`https://infinity-now.vercel.app/video/${video?.id}`,
        title:'Infinity',
        text: video?.description || `Check out @${video?.username || 'this'} on Infinity`,
        mediaUrl: video?.videoUrl || video?.images?.[0],
        mediaType: video?.mediaType,
        showToast,
        onShared:()=>{ if (video?.id) updateDoc(doc(db,'videos',video.id), { shares: increment(1) }).catch(()=>{}); },
      }), icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>) },
    { label:'Copy Link', show:true, action:async()=>{ try{ await navigator.clipboard.writeText(`https://infinity-now.vercel.app/video/${video?.id}`); showToast?.('Link copied!','success'); }catch{ showToast?.('Could not copy link','error'); } }, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10 13a5 5 0 007.07 0l2.83-2.83a5 5 0 00-7.07-7.07l-1.5 1.5"/><path d="M14 11a5 5 0 00-7.07 0L4.1 13.83a5 5 0 007.07 7.07l1.5-1.5"/></svg>) },
    { label: alreadyReposted ? 'Remove repost' : 'Repost', show:!isMine, action:doRepost, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={alreadyReposted?COLORS.brand:'currentColor'} strokeWidth="2"><path d="M17 1l4 4-4 4"/><path d="M3 11V9a4 4 0 014-4h14"/><path d="M7 23l-4-4 4-4"/><path d="M21 13v2a4 4 0 01-4 4H3"/></svg>) },
    { label: alreadySaved ? 'Remove from Collection' : 'Add to Collection', show:true, action:doAddToCollection, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill={alreadySaved?COLORS.brand:'none'} stroke={alreadySaved?COLORS.brand:'currentColor'} strokeWidth="2"><path d="M6 2a2 2 0 00-2 2v18l8-6 8 6V4a2 2 0 00-2-2z"/></svg>) },
    { label:`Mute ${name}`, show:!isMine, action:()=>{ showToast?.(`Muted ${name}`,'info'); }, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/></svg>) },
    { label:`Block ${name}`, show:!isMine, action:()=>{ onBlock?.(video?.userId); showToast?.(`Blocked ${name} — their posts are now hidden`,'info'); }, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="4.9" y1="4.9" x2="19.1" y2="19.1"/></svg>) },
    { label:'Report', show:!isMine, danger:true, keepOpen:true, action:()=>{ setShowReportSheet(true); }, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 9v4M12 17h.01"/><path d="M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z"/></svg>) },
    { label:'Delete Post', show:isMine, danger:true, sep:true, action:async()=>{
        if(!(await confirmDialog('Delete this post? This cannot be undone.'))) return;
        try{ await deleteDoc(doc(db,'videos',video.id)); showToast?.('Post deleted','success'); }
        catch(e){ showToast?.('Could not delete post','error'); }
        onDelete?.(video?.id); onClose();
      }, icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/></svg>) },
  ].filter(i => i.show);
  return (
    <motion.div
      variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
      style={{ position:'fixed', inset:0, zIndex:Z.modal, background:'rgba(20,15,35,0.45)', display:'flex', alignItems:'flex-end' }} onClick={onClose}>
      <motion.div
        variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
        onClick={e=>e.stopPropagation()} style={{ width:'100%', maxHeight:'70vh', overflowY:'auto', background:COLORS.surface, borderTopLeftRadius:22, borderTopRightRadius:22, paddingBottom:'max(14px, env(safe-area-inset-bottom))' }}>
        <SheetBackHeader title="More Options" onClose={onClose} />
        <div style={{ padding:'4px 8px' }}>
          {items.map(item => (
            <button key={item.label} onClick={()=>{ item.action(); if(!item.label.startsWith('Delete') && !item.keepOpen) onClose(); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:12, background:'none', border:'none', borderTop:item.sep?`1px solid ${COLORS.border}`:'none', marginTop:item.sep?6:0, paddingTop:item.sep?12:9, padding:item.sep?'12px 10px 9px':'9px 10px', color:item.danger?COLORS.danger:COLORS.textPrimary, fontSize:13.5, fontWeight:600, cursor:'pointer', textAlign:'left', borderRadius:10 }}>
              {item.icon}{item.label}
            </button>
          ))}
        </div>
      </motion.div>
      <AnimatePresence>{showReportSheet && (
        <ReportReasonSheet
          title="Report Post"
          onClose={()=>{ setShowReportSheet(false); onClose(); }}
          onSubmit={submitPostReport}
        />
      )}</AnimatePresence>
    </motion.div>
  );
};

// Ensures only one FeedPostCard video autoplays at a time (TikTok-style single active playback)
let __activeFeedVideoEl = null;
// Whichever card currently owns __activeFeedVideoEl also registers its setVideoPaused
// setter here. This lets code OUTSIDE the card (browser tab hidden, or an in-app
// overlay like Live/Camera/Calls opening on top of the feed) pause the real <video>
// AND flip that card's own play/pause icon, instead of silently pausing the element
// while the card's UI still thinks it's playing.
let __activeFeedVideoSetPaused = null;
// ROOT CAUSE (background audio bug): feed post videos are always unmuted (`muted =
// false` below) and were only ever paused by the IntersectionObserver-driven
// "scrolled off-screen" effect. That observer tracks scroll position WITHIN the page —
// it has no idea whether the browser tab itself is in the background, or whether an
// in-app overlay (Live, a call, the camera, Stories) has been opened on top of the
// still-mounted feed. Result: switching browser tabs, or going live / watching someone
// else's live, left the underlying feed video playing with full sound underneath.
// Fix: a single, file-wide "pause whatever's currently playing" entry point that (a) a
// document 'visibilitychange' listener calls when the tab goes to the background, and
// (b) the top-level app calls whenever a full-screen overlay is opened over the feed.
function suspendActiveFeedVideo() {
  if (__activeFeedVideoEl) {
    try { __activeFeedVideoEl.pause(); } catch {}
    __activeFeedVideoSetPaused?.(true);
  }
}
// Tracks the stop() function of whichever post is currently being read aloud, so
// starting Read Aloud on a different post cancels the previous one — one voice at a
// time, same idea as __activeFeedVideoEl above for video playback.
let __activeReadingStop = null;
// speechSynthesis.getVoices() very often returns an empty array the first time it's
// called — voice lists load asynchronously and fire the 'voiceschanged' event once
// ready (Chrome in particular). Calling getVoices() synchronously on first tap, as
// before, meant an installed Amharic (or any non-default) voice was never found even
// when the device actually had one. This caches a promise that resolves once real
// voices are available, so Read Aloud can await it before picking a voice.
let __voicesReadyPromise = null;
const getSpeechVoicesReady = () => {
  if (__voicesReadyPromise) return __voicesReadyPromise;
  __voicesReadyPromise = new Promise((resolve) => {
    if (typeof window === 'undefined' || !('speechSynthesis' in window)) { resolve([]); return; }
    const existing = window.speechSynthesis.getVoices();
    if (existing && existing.length > 0) { resolve(existing); return; }
    const onChange = () => {
      const voices = window.speechSynthesis.getVoices();
      if (voices && voices.length > 0) {
        window.speechSynthesis.removeEventListener('voiceschanged', onChange);
        resolve(voices);
      }
    };
    window.speechSynthesis.addEventListener('voiceschanged', onChange);
    // Fallback in case voiceschanged never fires on this browser (some WebViews).
    setTimeout(() => resolve(window.speechSynthesis.getVoices() || []), 1500);
  });
  return __voicesReadyPromise;
};
// Maps a CAPTION_LANGUAGES code to a BCP47 locale tag SpeechSynthesis understands
// better than a bare two-letter code (helps the browser/OS pick the right voice —
// this is what was missing for Amharic, which needs 'am-ET' rather than just 'am').
const READ_ALOUD_LOCALE = {
  en:'en-US', am:'am-ET', ar:'ar-SA', fr:'fr-FR', es:'es-ES', pt:'pt-PT', hi:'hi-IN',
  zh:'zh-CN', 'zh-TW':'zh-TW', sw:'sw-KE', de:'de-DE', ru:'ru-RU', tr:'tr-TR', ja:'ja-JP',
  ko:'ko-KR', it:'it-IT', om:'om-ET', ti:'ti-ET', so:'so-SO', ur:'ur-PK', bn:'bn-BD',
  pa:'pa-IN', ta:'ta-IN', te:'te-IN', mr:'mr-IN', gu:'gu-IN', kn:'kn-IN', ml:'ml-IN',
  th:'th-TH', vi:'vi-VN', id:'id-ID', ms:'ms-MY', tl:'fil-PH', nl:'nl-NL', pl:'pl-PL',
  uk:'uk-UA', el:'el-GR', sv:'sv-SE', no:'nb-NO', da:'da-DK', fi:'fi-FI', cs:'cs-CZ',
  hu:'hu-HU', ro:'ro-RO', he:'he-IL', fa:'fa-IR', ha:'ha-NG', yo:'yo-NG', ig:'ig-NG',
  zu:'zu-ZA', rw:'rw-RW',
};

const FeedPostCard = ({ video, currentUser, onViewProfile, onOpenComments, onShare, users, onFollow, followed, showToast, onDelete, onBlock, isLive }) => {
  const [liked, setLiked] = useState((video.likedBy||[]).includes(currentUser?.id));
  const [likeCount, setLikeCount] = useState(video.likes||0);
  // Author lookup — the video doc doesn't carry a denormalized `verified` flag, so we
  // check the live users list (same one Home/Infinity already have in hand) to show a
  // verified badge next to the name, exactly like Instagram/Facebook/X do.
  const author = useMemo(()=> (users||[]).find(u=>u.id===video.userId), [users, video.userId]);
  const displayName = author?.fullName || video.fullName || author?.username || video.username || 'user';
  // Double-tap-to-like — Instagram's signature interaction. A double tap on the media
  // always likes (never unlikes) and shows a brief heart-burst overlay; burstKey forces
  // the CSS animation to restart on every tap instead of only playing once ever.
  const [burstKey, setBurstKey] = useState(0);
  const burstTimeoutRef = useRef(null);
  // Re-sync from the live Firestore snapshot whenever it changes (e.g. someone else
  // likes/unlikes this post) so the count updates in real time for every viewer,
  // TikTok-style, instead of freezing at whatever it was when this card first mounted.
  const likeActionPendingRef = useRef(false);
  useEffect(() => {
    if (likeActionPendingRef.current) return; // don't clobber our own optimistic update mid-flight
    setLiked((video.likedBy||[]).includes(currentUser?.id));
    setLikeCount(video.likes||0);
  }, [video.likes, video.likedBy, currentUser?.id]);
  const [saved, setSaved] = useState((video.savedBy||[]).includes(currentUser?.id));
  const [showLikes, setShowLikes] = useState(false);
  const [showComments, setShowComments] = useState(false);
  const [showShare, setShowShare] = useState(false);
  // Real share, the way every other app does it: tap → straight to the OS's own
  // native share sheet (whatever's actually installed — real contacts, real apps —
  // rendered by the device, not by us). Only opens our in-app ShareSheet as a
  // fallback when navigator.share isn't available at all (e.g. some desktop browsers).
  const handleShareTap = () => {
    if (typeof navigator !== 'undefined' && navigator.share) {
      shareToDevice({
        url: `https://infinity-now.vercel.app/video/${video?.id}`,
        title: 'Infinity',
        text: video?.description || `Check out @${video?.username || 'this'} on Infinity`,
        mediaUrl: video?.videoUrl || video?.images?.[0],
        mediaType: video?.mediaType,
        showToast,
        onShared: () => { if (video?.id) updateDoc(doc(db, 'videos', video.id), { shares: increment(1) }).catch(() => {}); },
      });
    } else {
      setShowShare(true);
    }
  };
  const [showSaveConfirm, setShowSaveConfirm] = useState(false);
  const [showOptions, setShowOptions] = useState(false);
  const [showMediaActions, setShowMediaActions] = useState(false);
  const mediaPressTimer = useRef(null);
  const mediaPressFired = useRef(false);
  const startMediaPress = () => {
    mediaPressFired.current = false;
    mediaPressTimer.current = setTimeout(() => {
      mediaPressFired.current = true;
      haptic('medium');
      setShowMediaActions(true);
    }, 480);
  };
  const cancelMediaPress = () => clearTimeout(mediaPressTimer.current);
  const [descExpanded, setDescExpanded] = useState(false);
  // ── Read Aloud — text-to-speech for post captions/text posts, via the browser's
  // built-in SpeechSynthesis API (no server cost, works offline). Only one post reads
  // at a time app-wide: starting a new one cancels whatever was already speaking,
  // mirroring the single-active-video pattern used for feed playback below.
  //
  // readLang lets the viewer pick the spoken language per post from the full
  // CAPTION_LANGUAGES list (same one used for video caption translation): 'auto'
  // reads the post as-written (Ethiopic script gets an am-ET voice hint, everything
  // else uses the device's language), while any other code always speaks it in that
  // language — translating the text first via liveTranslate() when the post isn't
  // already written in it, so e.g. an English caption is read out in Amharic rather
  // than an Amharic voice trying (and failing) to pronounce English words.
  const [isReading, setIsReading] = useState(false);
  const [isTranslatingRead, setIsTranslatingRead] = useState(false);
  const [readLang, setReadLang] = useState('auto'); // 'auto' | any CAPTION_LANGUAGES code
  const [showReadLangMenu, setShowReadLangMenu] = useState(false);
  const readUtteranceRef = useRef(null);
  const readRequestIdRef = useRef(0);
  const stopReading = () => {
    readRequestIdRef.current += 1; // invalidates any in-flight translation
    try { window.speechSynthesis?.cancel(); } catch {}
    if (__activeReadingStop === stopReading) __activeReadingStop = null;
    setIsReading(false);
    setIsTranslatingRead(false);
  };
  const isAmharicScript = (s) => /[\u1200-\u137F]/.test(s || '');
  const toggleReadAloud = async (e) => {
    e.stopPropagation();
    if (!('speechSynthesis' in window)) { showToast?.('Read aloud isn\'t supported on this device', 'error'); return; }
    if (isReading || isTranslatingRead) { stopReading(); return; }
    // Stop any other post currently being read before starting this one.
    __activeReadingStop?.();
    haptic('light');
    const myRequestId = (readRequestIdRef.current += 1);
    const original = video.description || '';
    let text = original;
    let lang = isAmharicScript(original) ? 'am-ET' : (navigator.language || 'en-US');
    if (readLang !== 'auto') {
      lang = READ_ALOUD_LOCALE[readLang] || readLang;
      const alreadyInTargetScript = readLang === 'am' ? isAmharicScript(original) : false;
      if (!alreadyInTargetScript) {
        setIsTranslatingRead(true);
        try { text = await liveTranslate(original, readLang); }
        catch { text = original; }
        setIsTranslatingRead(false);
        if (myRequestId !== readRequestIdRef.current) return; // user cancelled while translating
      }
    }
    // Wait for the real voice list before building the utterance — getVoices() is
    // frequently empty on the very first call (see getSpeechVoicesReady above),
    // which was why an installed Amharic voice was never picked up.
    const voices = await getSpeechVoicesReady();
    if (myRequestId !== readRequestIdRef.current) return; // cancelled while voices loaded
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = lang;
    const baseLang = lang.split('-')[0].toLowerCase();
    const exactVoice = voices.find(v => v.lang?.toLowerCase() === lang.toLowerCase());
    const baseVoice = voices.find(v => v.lang?.toLowerCase().startsWith(baseLang));
    if (exactVoice || baseVoice) utterance.voice = exactVoice || baseVoice;
    utterance.rate = 1;
    utterance.onend = () => { setIsReading(false); if (__activeReadingStop === stopReading) __activeReadingStop = null; };
    utterance.onerror = () => { setIsReading(false); if (__activeReadingStop === stopReading) __activeReadingStop = null; };
    readUtteranceRef.current = utterance;
    __activeReadingStop = stopReading;
    setIsReading(true);
    window.speechSynthesis.speak(utterance);
  };
  // Selecting a language always stops any in-progress reading (rather than silently
  // switching mid-sentence) — tap the play button again to hear it in the new language.
  const selectReadLang = (code, e) => {
    e?.stopPropagation();
    if (isReading || isTranslatingRead) stopReading();
    setReadLang(code);
    setShowReadLangMenu(false);
    haptic('light');
  };
  // Card-unmount cleanup for read-aloud; the "scrolled off-screen" stop is added
  // below once isVisible exists.
  useEffect(() => () => { if (isReading || isTranslatingRead) stopReading(); }, []);
  const isVideo = video?.mediaType?.startsWith('video') || /\.(mp4|webm|mov)(\?|$)/i.test(video?.videoUrl||'');
  const isAudioPost = video?.mediaType?.startsWith('audio');
  const galleryImages = Array.isArray(video.images) && video.images.length > 0 ? video.images : null;
  const mediaSrc = (galleryImages && galleryImages[0]) || video.videoUrl;
  const mediaWrapRef = useRef(null);
  const videoElRef = useRef(null);
  const [videoPaused, setVideoPaused] = useState(false);
  // Sound is always on and there's no per-video mute button anymore — matches
  // how the rest of the app (stories, calls, live) always plays with audio.
  const muted = false;
  const viewCountedRef = useRef(false);
  const isVisible = useIntersectionObserver(mediaWrapRef, { threshold: 0.6 });
  // Stop reading if the post scrolls off-screen, so speech doesn't keep narrating a
  // post the viewer has already scrolled past.
  useEffect(() => { if (!isVisible && (isReading || isTranslatingRead)) stopReading(); if (!isVisible) setShowReadLangMenu(false); }, [isVisible]);

  // ── Auto-translated video captions, TikTok/Facebook-style ──
  // No per-video button: whether captions show at all, and in which language, is a
  // single global choice made once in Settings → Video Captions (currentUser.captionsEnabled
  // / currentUser.captionLanguage). Turning it on here just makes captions appear
  // automatically on every video from then on, matching how TikTok's Accessibility
  // "Auto-captions" and Facebook's auto-translate settings behave.
  //
  // Storage: the video doc caches a `captions.source` transcript (original spoken
  // language, generated once via Gemini video transcription) plus a
  // `captions.translations.{langCode}` map, filled in lazily the first time *any*
  // viewer requests that language (cheap text-only Gemini translation of the cached
  // source — no re-fetching/re-sending the video). So the very first viewer of a
  // clip in each language pays a small one-time cost; everyone after gets the cached
  // track instantly, and effectively any language Gemini can translate to is supported.
  const captionsWanted = !!currentUser?.captionsEnabled;
  const captionLang = currentUser?.captionLanguage || 'en';
  const [localCaptionTrack, setLocalCaptionTrack] = useState(null); // fallback if snapshot hasn't caught up
  const [captionsLoading, setCaptionsLoading] = useState(false);
  const [activeCaptionText, setActiveCaptionText] = useState('');
  const captionTrack = video.captions?.translations?.[captionLang]
    || (video.captions?.source?.language === captionLang ? video.captions.source.segments : null)
    || localCaptionTrack;

  useEffect(() => {
    if (!isVideo || !captionsWanted || !isVisible || captionTrack || captionsLoading) return;
    let cancelled = false;
    (async () => {
      setCaptionsLoading(true);
      try {
        const data = await apiFetch('/api/ai/captions', {
          method: 'POST',
          body: JSON.stringify({ videoId: video.id, videoUrl: mediaSrc, targetLang: captionLang }),
        });
        if (!cancelled && data?.track) setLocalCaptionTrack(data.track);
      } catch (e) {
        // Fail quietly here — auto-captions shouldn't interrupt playback with an error toast
        // for every video in the feed; the CC-less overlay just stays empty.
        console.error('auto-captions failed:', e.message);
      } finally {
        if (!cancelled) setCaptionsLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, [isVideo, captionsWanted, isVisible, captionLang, captionTrack]);

  // Reset the local fallback when the viewer's chosen language changes, so a stale
  // track in the old language doesn't keep showing while the new one loads.
  useEffect(() => { setLocalCaptionTrack(null); }, [captionLang]);

  // Drive the on-screen caption text off the video's actual playback time so it stays
  // in sync even after the user scrubs the progress bar above.
  useEffect(() => {
    if (!captionsWanted || !captionTrack) { setActiveCaptionText(''); return; }
    const el = videoElRef.current;
    if (!el) return;
    const update = () => {
      const t = el.currentTime;
      const seg = captionTrack.find(s => t >= s.start && t <= s.end);
      setActiveCaptionText(seg?.text || '');
    };
    update();
    el.addEventListener('timeupdate', update);
    return () => el.removeEventListener('timeupdate', update);
  }, [captionsWanted, captionTrack]);


  // Count a view once per viewer per video, the first time the post is actually scrolled
  // into view. BUG FIX: this used to only guard with a per-mount ref, so the exact same
  // viewer inflated the count every time the card remounted — switching between the
  // Home and Infinity feed tabs, pull-to-refresh, scrolling a video off-screen and back,
  // etc. all silently added another view for one person. It also never had any real
  // per-user dedup, so "views" didn't mean "people who watched" — it meant "renders".
  // Now we check+record the viewer's id in `viewedBy` on the video doc itself, so a
  // repeat viewer (any tab, any remount, any session) is only ever counted once, and the
  // local ref just prevents a redundant write within the same mount.
  useEffect(() => {
    if (!isVisible || viewCountedRef.current || !video?.id || !currentUser?.id) return;
    viewCountedRef.current = true;
    if ((video.viewedBy || []).includes(currentUser.id)) return;
    updateDoc(doc(db, 'videos', video.id), {
      views: increment(1),
      viewedBy: arrayUnion(currentUser.id),
    }).catch(() => {});
  }, [isVisible, video?.id, currentUser?.id]);

  // TikTok-style single-active playback: autoplay when in view, pause when scrolled away,
  // and pause any other feed video that was already playing so only one plays at once.
  useEffect(() => {
    if (!isVideo) return;
    const el = videoElRef.current;
    if (!el) return;
    if (isVisible) {
      // Don't autoplay into a background tab or on top of an overlay (Live/Call/Camera/
      // Stories) — the intersection observer alone can't see either of those. See
      // suspendActiveFeedVideo() above for the full explanation.
      if (document.hidden) return;
      if (__activeFeedVideoEl && __activeFeedVideoEl !== el) {
        try { __activeFeedVideoEl.pause(); } catch {}
      }
      __activeFeedVideoEl = el;
      __activeFeedVideoSetPaused = setVideoPaused;
      el.play().then(()=>setVideoPaused(false)).catch(() => { setVideoPaused(true); });
    } else {
      el.pause();
      setVideoPaused(true);
      if (__activeFeedVideoEl === el) { __activeFeedVideoEl = null; __activeFeedVideoSetPaused = null; }
    }
  }, [isVisible, isVideo]);

  // Tab-away fix: pause immediately when the browser tab is backgrounded (covers the
  // case where the user switches tabs while a feed video is mid-play), and resume it
  // — only this exact card, and only if it's still the one actually in view — when the
  // tab comes back to the foreground. This is a per-card listener (not a single global
  // one) so resume can correctly re-check "is *this* card still visible/current" instead
  // of naively resuming whatever was last playing.
  useEffect(() => {
    if (!isVideo) return;
    const onVisibility = () => {
      const el = videoElRef.current;
      if (!el) return;
      if (document.hidden) {
        if (__activeFeedVideoEl === el) el.pause();
      } else if (isVisible && __activeFeedVideoEl === el) {
        el.play().then(()=>setVideoPaused(false)).catch(()=>setVideoPaused(true));
      }
    };
    document.addEventListener('visibilitychange', onVisibility);
    return () => document.removeEventListener('visibilitychange', onVisibility);
  }, [isVideo, isVisible]);

  useEffect(() => () => {
    if (__activeFeedVideoEl === videoElRef.current) { __activeFeedVideoEl = null; __activeFeedVideoSetPaused = null; }
  }, []);

  const toggleLike = async () => {
    const nowLiked = !liked;
    likeActionPendingRef.current = true;
    setLiked(nowLiked);
    setLikeCount(c => c + (nowLiked ? 1 : -1));
    haptic('light');
    try {
      await updateDoc(doc(db, 'videos', video.id), {
        likes: increment(nowLiked ? 1 : -1),
        likedBy: nowLiked ? arrayUnion(currentUser?.id) : arrayRemove(currentUser?.id),
      });
    } catch (e) { /* best-effort */ }
    finally { likeActionPendingRef.current = false; }
  };

  const handleMediaDoubleClick = () => {
    if (!liked) toggleLike();
    haptic('light');
    setBurstKey(k => k + 1);
    if (burstTimeoutRef.current) clearTimeout(burstTimeoutRef.current);
    burstTimeoutRef.current = setTimeout(() => setBurstKey(0), 800);
  };
  useEffect(() => () => { if (burstTimeoutRef.current) clearTimeout(burstTimeoutRef.current); }, []);

  const toggleSave = async () => {
    const nowSaved = !saved;
    setSaved(nowSaved);
    haptic('light');
    try {
      await updateDoc(doc(db, 'videos', video.id), {
        savedBy: nowSaved ? arrayUnion(currentUser?.id) : arrayRemove(currentUser?.id),
        saves: increment(nowSaved ? 1 : -1),
      });
    } catch (e) {}
    if (nowSaved) setShowSaveConfirm(true);
  };

  const handleDownload = async () => {
    if (!mediaSrc) { showToast?.('No media to download', 'error'); return; }
    haptic('light');
    try {
      const res = await fetch(mediaSrc);
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const ext = isVideo ? 'mp4' : 'jpg';
      const a = document.createElement('a');
      a.href = url; a.download = `infinity_post_${video.id || Date.now()}.${ext}`;
      document.body.appendChild(a); a.click(); a.remove();
      URL.revokeObjectURL(url);
      showToast?.('Post downloaded! 📥', 'success');
    } catch (e) {
      showToast?.('Download failed', 'error');
    }
  };

  return (
    <>
    <AnimatePresence>{showLikes && <LikesModal video={video} currentUser={currentUser} users={users} onClose={()=>setShowLikes(false)} onFollow={onFollow} followed={followed} onViewProfile={onViewProfile} />}</AnimatePresence>
    <AnimatePresence>{showComments && <CommentsModal video={video} currentUser={currentUser} onClose={()=>setShowComments(false)} showToast={showToast} onViewProfile={onViewProfile} />}</AnimatePresence>
    <AnimatePresence>{showShare && <ShareSheet video={video} currentUser={currentUser} onClose={()=>setShowShare(false)} showToast={showToast} />}</AnimatePresence>
    <AnimatePresence>{showSaveConfirm && <SaveConfirmSheet onClose={()=>setShowSaveConfirm(false)} onViewCollections={()=>{ setShowSaveConfirm(false); showToast?.('Opening collections…','info'); }} />}</AnimatePresence>
    <AnimatePresence>{showMediaActions && (
      <motion.div
        variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
        onClick={()=>setShowMediaActions(false)} style={{ position:'fixed', inset:0, zIndex:Z.modal, background:'rgba(15,10,25,0.5)', display:'flex', alignItems:'flex-end', maxWidth:430, margin:'0 auto' }}>
        <motion.div
          variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
          onClick={e=>e.stopPropagation()} style={{ width:'100%', background:COLORS.surface, borderTopLeftRadius:24, borderTopRightRadius:24, padding:'10px 8px 28px' }}>
          <div style={{ width:36, height:4, background:COLORS.border, borderRadius:2, margin:'0 auto 14px' }} />
          <button onClick={()=>{ toggleSave(); setShowMediaActions(false); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'14px 12px', background:'none', border:'none', cursor:'pointer', borderBottom:`1px solid ${COLORS.border}` }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill={saved?COLORS.brand:'none'} stroke={saved?COLORS.brand:COLORS.textPrimary} strokeWidth="2"><path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/></svg>
            <span style={{ color:COLORS.textPrimary, fontSize:15, fontWeight:600 }}>{saved ? 'Remove from Saved' : 'Save'}</span>
          </button>
          <button onClick={()=>{ handleDownload(); setShowMediaActions(false); }} style={{ width:'100%', display:'flex', alignItems:'center', gap:14, padding:'14px 12px', background:'none', border:'none', cursor:'pointer' }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={COLORS.textPrimary} strokeWidth="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            <span style={{ color:COLORS.textPrimary, fontSize:15, fontWeight:600 }}>Download</span>
          </button>
        </motion.div>
      </motion.div>
    )}</AnimatePresence>
    <AnimatePresence>{showOptions && <PostOptionsMenu video={video} currentUser={currentUser} onClose={()=>setShowOptions(false)} showToast={showToast} onDelete={onDelete} onBlock={onBlock} />}</AnimatePresence>
    <div style={{ background:COLORS.surface, borderRadius:RADIUS.lg, padding:14, marginBottom:0, boxShadow:SHADOW.card, border:`1px solid ${COLORS.border}`, transition:TRANSITION.base }}>
      <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:10 }}>
        <div onClick={()=>onViewProfile?.(video.userId)} style={{ width:44, height:44, borderRadius:'50%', background:video.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:17, overflow:'hidden', cursor:'pointer', flexShrink:0, position:'relative', border: isLive ? `2px solid ${COLORS.live}` : `2px solid ${COLORS.surface}`, boxShadow: isLive ? SHADOW.glow(COLORS.live) : SHADOW.xs, transition:TRANSITION.fast }}>
          {(author?.avatarUrl || video.avatarUrl) ? <img loading="lazy" decoding="async" src={author?.avatarUrl || video.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt="" /> : (displayName||'?')[0]?.toUpperCase()}
          {isLive && (
            <div style={{ position:'absolute', bottom:-3, left:'50%', transform:'translateX(-50%)', background:COLORS.live, borderRadius:6, padding:'1px 5px', fontSize:7, fontWeight:800, color:'white', letterSpacing:0.3, whiteSpace:'nowrap' }}>LIVE</div>
          )}
        </div>
        <div style={{ flex:1, minWidth:0, display:'flex', flexDirection:'column', overflow:'hidden', cursor:'pointer' }} onClick={()=>onViewProfile?.(video.userId)}>
          {/* Posts show only the person's current display name (full name), read live
              from `users` via `author` — not the username/fullName that was snapshotted
              onto the video doc at the moment it was posted. Using the snapshot meant the
              same person's older and newer posts could show two different names/handles
              after they ever changed their profile name. Falls back to the post's own
              snapshot only for the rare case the author's live profile hasn't loaded yet
              (e.g. they were removed), and to username only if no full name exists at all. */}
          <span style={{ display:'inline-flex', alignItems:'center', gap:4, whiteSpace:'nowrap', overflow:'hidden' }}>
            <span style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:14, overflow:'hidden', textOverflow:'ellipsis' }}>{displayName}</span>
            {author?.verified && <svg width="14" height="14" viewBox="0 0 24 24" fill={COLORS.info} style={{flexShrink:0}}><path d="M9 12l2 2 4-4M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>}
            {video.feeling && <span style={{ color:COLORS.textSecondary, fontWeight:500, fontSize:14 }}> is feeling {video.feeling.emoji} {video.feeling.text}</span>}
          </span>
          <span style={{ color:COLORS.textTertiary, fontSize:12, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{timeAgo(tsToDate(video.createdAt))}</span>
        </div>
        {video.userId !== currentUser?.id && (
          <button
            onClick={e=>{ e.stopPropagation(); onFollow?.(video.userId); }}
            aria-label={followed?.includes(video.userId) ? 'Unfollow' : 'Follow'}
            style={{ flexShrink:0, background: followed?.includes(video.userId) ? COLORS.surfaceAlt : COLORS.gradient, color: followed?.includes(video.userId) ? COLORS.textSecondary : '#fff', border: followed?.includes(video.userId) ? `1px solid ${COLORS.border}` : 'none', borderRadius:14, padding:'6px 14px', fontSize:12.5, fontWeight:700, cursor:'pointer', transition:TRANSITION.fast }}>
            {followed?.includes(video.userId) ? 'Following' : 'Follow'}
          </button>
        )}
        <button onClick={()=>setShowOptions(true)} aria-label="More options" style={{ background:'none', border:'none', cursor:'pointer', color:COLORS.textTertiary, fontSize:16, padding:4, flexShrink:0 }}>•••</button>
      </div>
      {(video.location || video.taggedUsers?.length > 0) && (
        <div style={{ display:'flex', flexWrap:'wrap', alignItems:'center', gap:6, marginTop:-6, marginBottom:10, color:COLORS.textSecondary, fontSize:12, fontWeight:600 }}>
          {video.location && (
            <span style={{ display:'inline-flex', alignItems:'center', gap:4 }}>
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z"/><circle cx="12" cy="9" r="2.5"/></svg>
              {video.location}
            </span>
          )}
          {video.taggedUsers?.length > 0 && (
            <span>with {video.taggedUsers.slice(0,3).map(u=>`@${u.username}`).join(', ')}{video.taggedUsers.length>3 ? ` +${video.taggedUsers.length-3}` : ''}</span>
          )}
        </div>
      )}
      {video.event?.title && (
        <div style={{ display:'flex', alignItems:'center', gap:10, background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, borderRadius:14, padding:'10px 12px', marginBottom:12 }}>
          <span style={{ fontSize:20 }}>📅</span>
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{video.event.title}</div>
            <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>
              {video.event.date}{video.event.location ? ` · ${video.event.location}` : ''}
            </div>
          </div>
        </div>
      )}
      {video.poll?.options?.length > 0 && (
        <PollWidget poll={video.poll} currentUser={currentUser} videoId={video.id} showToast={showToast} />
      )}
      {video.description && (()=>{
        const DESC_LIMIT = 140;
        const isLong = video.description.length > DESC_LIMIT;
        const shown = descExpanded || !isLong ? video.description : video.description.slice(0, DESC_LIMIT).trimEnd();
        const bg = video.bgColor && video.mediaType==='text';
        return (
          <div style={{ marginBottom:12 }}>
            <div onClick={()=>isLong && setDescExpanded(v=>!v)} style={bg ? {
              background:video.bgColor, borderRadius:16, padding:'28px 18px',
              display:'flex', alignItems:'center', justifyContent:'center', textAlign:'center', minHeight:120,
              color:'#fff', fontSize:18, fontWeight:700, lineHeight:1.4, whiteSpace:'pre-wrap', wordBreak:'break-word',
              cursor: isLong ? 'pointer' : 'default',
            } : { color:COLORS.textPrimary, fontSize:14, lineHeight:1.5, whiteSpace:'pre-wrap', wordBreak:'break-word', cursor: isLong ? 'pointer' : 'default' }}>
              {shown}{isLong && !descExpanded && '…'}
              {isLong && (
                <span onClick={e=>{ e.stopPropagation(); setDescExpanded(v=>!v); }} style={{ color:bg?'rgba(255,255,255,0.85)':COLORS.textTertiary, fontWeight:700, cursor:'pointer', marginLeft:5 }}>
                  {descExpanded ? 'Show less' : 'See more'}
                </span>
              )}
            </div>
          </div>
        );
      })()}
      {mediaSrc && (
        <div
          ref={mediaWrapRef}
          onDoubleClick={handleMediaDoubleClick}
          onMouseDown={startMediaPress}
          onMouseUp={cancelMediaPress}
          onMouseLeave={cancelMediaPress}
          onTouchStart={startMediaPress}
          onTouchEnd={cancelMediaPress}
          onTouchMove={cancelMediaPress}
          onContextMenu={e=>{ e.preventDefault(); haptic('medium'); setShowMediaActions(true); }}
          style={{ position:'relative', borderRadius:16, overflow:'hidden', marginBottom:10, background:'#000', boxShadow:SHADOW.sm }}
        >
          {isAudioPost ? (
            <AudioHeroCard src={mediaSrc} duration={video.duration} seed={video.id || mediaSrc} authorName={displayName} authorAvatar={author?.avatarUrl || video.avatarUrl} authorAvatarColor={video.avatarColor} />
          ) : isVideo ? (
            <>
              <div onClick={()=>{
                  if (mediaPressFired.current) { mediaPressFired.current = false; return; }
                  const el = videoElRef.current; if (!el) return;
                  if (el.paused) { el.play().then(()=>setVideoPaused(false)).catch(()=>{}); }
                  else { el.pause(); setVideoPaused(true); }
                }} style={{ cursor:'pointer', width:'100%', maxHeight:520, overflow:'hidden', display:'flex', alignItems:'center', justifyContent:'center' }}>
                <video
                  ref={videoElRef}
                  src={mediaSrc}
                  loop
                  playsInline
                  muted={muted}
                  style={{ width:'100%', maxHeight:520, display:'block', objectFit:'cover', background:'#000' }}
                />
              </div>
              {/* Bottom progress line — draggable to seek, mirrors TikTok/Reels scrubbing */}
              <VideoProgressBar videoRef={videoElRef} isActive={isVisible} isImage={false} />
              {/* Caption text overlay — sits just above the bottom progress bar. No button here
                  by design: whether this shows, and in what language, is decided once in
                  Settings → Video Captions, TikTok/Facebook-style, not per video. */}
              {captionsWanted && activeCaptionText && (
                <div style={{
                  position:'absolute', left:0, right:0, bottom:22, zIndex:20,
                  display:'flex', justifyContent:'center', padding:'0 16px', pointerEvents:'none',
                }}>
                  <span style={{
                    background:'rgba(0,0,0,0.65)', color:'#fff', fontSize:14, fontWeight:700,
                    lineHeight:1.35, padding:'5px 10px', borderRadius:8, textAlign:'center',
                    maxWidth:'100%', boxShadow:'0 2px 8px rgba(0,0,0,0.25)',
                  }}>
                    {activeCaptionText}
                  </span>
                </div>
              )}
              {videoPaused && (
                <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', pointerEvents:'none' }}>
                  <div style={{ width:56, height:56, borderRadius:'50%', background:'rgba(0,0,0,0.45)', display:'flex', alignItems:'center', justifyContent:'center' }}>
                    <svg width="22" height="22" viewBox="0 0 24 24" fill="white"><polygon points="5 3 19 12 5 21 5 3"/></svg>
                  </div>
                </div>
              )}
            </>
          ) : galleryImages ? (
            <MediaCarousel images={galleryImages} maxHeight={420} />
          ) : (
            <img loading="lazy" decoding="async" src={mediaSrc} alt="" style={{ width:'100%', maxHeight:420, display:'block', objectFit:'cover' }} />
          )}
          {/* Double-tap heart burst — Instagram's signature like gesture, purely visual
              (the actual like state/count is handled by handleMediaDoubleClick). */}
          {burstKey > 0 && (
            <div key={burstKey} style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', pointerEvents:'none' }}>
              <svg width="90" height="90" viewBox="0 0 24 24" fill="#fff" style={{ filter:'drop-shadow(0 4px 18px rgba(0,0,0,0.35))', animation:'heartBurst 0.7s cubic-bezier(0.2,0.8,0.3,1) forwards' }}>
                <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
              </svg>
            </div>
          )}
        </div>
      )}
      {/* ── Action bar — one unified row, laid out directly on the post's own
          white surface (no separate pill/background/border of its own), so it
          reads as part of the same card instead of a bolted-on widget. Each
          icon carries its own count beside it (Instagram/TikTok-style) instead
          of duplicating the same stats in a separate row above. Post options
          (•••) live only in the header — not repeated here too. ── */}
      <div style={{ marginTop:10, display:'flex', alignItems:'center', justifyContent:'space-between', borderTop:`1px solid ${COLORS.border}`, paddingTop:10 }}>
        {/* Read Aloud — replaces the old view-count display. Text-to-speech for the
            post's caption (browser SpeechSynthesis, no server cost). The language
            chip opens a picker covering every language in CAPTION_LANGUAGES (not just
            Amharic), translating the caption first via liveTranslate if it isn't
            already written in the chosen language. Icon-only — no "Read"/"Reading"
            text label, just the speaker glyph with an aria-label for accessibility.
            The whole control is only rendered when the post actually has caption
            text to read — posts with no text render nothing here at all (no greyed
            out placeholder taking up space in the action bar). */}
        {video.description && (
        <div style={{ position:'relative', display:'flex', alignItems:'center', gap:6 }}>
          <button
            onClick={(e)=>{ e.stopPropagation(); setShowReadLangMenu(v=>!v); }}
            aria-label={readLang === 'auto' ? 'Choose read-aloud language' : `Reading in ${CAPTION_LANGUAGES.find(l=>l[2]===readLang)?.[1] || readLang} — tap to change language`}
            title="Read-aloud language"
            style={{
              height:24, padding:'0 8px', borderRadius:12, border:'none', cursor:'pointer',
              display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0,
              fontSize:10.5, fontWeight:800, letterSpacing:0.2,
              background: readLang !== 'auto' ? COLORS.brand : COLORS.surfaceAlt,
              color: readLang !== 'auto' ? '#fff' : COLORS.textTertiary,
              transition:TRANSITION.fast,
            }}>
            {readLang === 'auto' ? 'Aa' : (CAPTION_LANGUAGES.find(l=>l[2]===readLang)?.[2] || readLang).toUpperCase()}
          </button>
          <AnimatePresence>{showReadLangMenu && (
            <>
              <div onClick={(e)=>{ e.stopPropagation(); setShowReadLangMenu(false); }} style={{ position:'fixed', inset:0, zIndex:Z.popover-1 }} />
              <motion.div
                initial={{ opacity:0, y:-6, scale:0.97 }} animate={{ opacity:1, y:0, scale:1 }} exit={{ opacity:0, y:-6, scale:0.97 }} transition={{ duration:0.14 }}
                onClick={e=>e.stopPropagation()}
                style={{ position:'absolute', top:'calc(100% + 6px)', left:0, width:200, maxHeight:280, overflowY:'auto', background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:14, boxShadow:SHADOW.raised, zIndex:Z.popover, padding:6 }}>
                <button onClick={(e)=>selectReadLang('auto', e)} style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', gap:8, background: readLang==='auto' ? COLORS.surfaceAlt : 'none', border:'none', borderRadius:10, padding:'8px 10px', cursor:'pointer', textAlign:'left', fontSize:13, fontWeight:600, color:COLORS.textPrimary }}>
                  Original (auto)
                  {readLang==='auto' && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={COLORS.brand} strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>}
                </button>
                {CAPTION_LANGUAGES.map(([native, english, code]) => (
                  <button key={code} onClick={(e)=>selectReadLang(code, e)} style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', gap:8, background: readLang===code ? COLORS.surfaceAlt : 'none', border:'none', borderRadius:10, padding:'8px 10px', cursor:'pointer', textAlign:'left', fontSize:13, fontWeight:600, color:COLORS.textPrimary }}>
                    <span>{native} <span style={{ color:COLORS.textTertiary, fontWeight:500 }}>· {english}</span></span>
                    {readLang===code && <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={COLORS.brand} strokeWidth="3"><polyline points="20 6 9 17 4 12"/></svg>}
                  </button>
                ))}
              </motion.div>
            </>
          )}</AnimatePresence>
          <motion.button
            whileTap={tapScale}
            onClick={toggleReadAloud}
            disabled={isTranslatingRead}
            aria-label={isReading ? 'Stop reading' : (isTranslatingRead ? 'Translating…' : 'Read post aloud')}
            style={{
              background:'none', border:'none', padding:8, margin:-8, display:'flex', alignItems:'center',
              cursor: isTranslatingRead ? 'default' : 'pointer', transition:TRANSITION.fast, borderRadius:10,
            }}>
            {isTranslatingRead ? (
              <div style={{ width:15, height:15, border:`2px solid ${COLORS.border}`, borderTop:`2px solid ${COLORS.brand}`, borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
            ) : (
              <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={isReading?COLORS.brand:COLORS.textSecondary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ animation: isReading ? 'pulseGlow 1.2s ease-in-out infinite' : 'none' }}>
                <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"/>
                {isReading ? <rect x="15" y="9" width="3" height="6" rx="1"/> : <path d="M15.54 8.46a5 5 0 010 7.07"/>}
              </svg>
            )}
          </motion.button>
        </div>
        )}

        {/* Like */}
        <motion.button whileTap={tapScale} onClick={toggleLike} onDoubleClick={()=>setShowLikes(true)} style={{ background:'none', border:'none', padding:8, margin:-8, display:'flex', alignItems:'center', gap:6, cursor:'pointer', transition:TRANSITION.fast, borderRadius:10 }}>
          <svg width="19" height="19" viewBox="0 0 24 24" fill={liked?COLORS.brand:'none'} stroke={liked?COLORS.brand:COLORS.textSecondary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ animation: liked ? 'likeHeart 0.35s ease' : 'none' }}>
            <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
          </svg>
          <span onClick={e=>{ e.stopPropagation(); likeCount>0 && setShowLikes(true); }} style={{ fontSize:13, color: liked?COLORS.brand:COLORS.textSecondary, cursor: likeCount>0 ? 'pointer' : 'default' }}>{formatNumber(likeCount)}</span>
        </motion.button>

        {/* Comment */}
        <motion.button whileTap={tapScale} onClick={()=>{ setShowComments(true); onOpenComments?.(video); }} style={{ background:'none', border:'none', padding:8, margin:-8, display:'flex', alignItems:'center', gap:6, cursor:'pointer', transition:TRANSITION.fast, borderRadius:10 }}>
          <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 11.5a8.38 8.38 0 01-.9 3.8 8.5 8.5 0 01-7.6 4.7 8.38 8.38 0 01-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 01-.9-3.8 8.5 8.5 0 014.7-7.6 8.38 8.38 0 013.8-.9h.5a8.48 8.48 0 018 8v.5z"/></svg>
          <span style={{ fontSize:13, color:COLORS.textSecondary }}>{formatNumber(video.comments||0)}</span>
        </motion.button>

        {/* Share — tapping this should behave the way every other app's share button
            does: it hands off straight to the device's own native share sheet (the
            OS-drawn one with the user's real contacts and installed apps — nothing
            here fakes or hardcodes that UI, the OS renders it). No extra "are you
            sure you want to share" screen first. The in-app ShareSheet (with
            repost/save/download/report) only opens as a fallback on browsers that
            don't support navigator.share at all (mainly older/desktop browsers). */}
        <motion.button whileTap={tapScale} onClick={handleShareTap} style={{ background:'none', border:'none', padding:8, margin:-8, display:'flex', alignItems:'center', gap:6, cursor:'pointer', transition:TRANSITION.fast, borderRadius:10 }}>
          <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
          <span style={{ fontSize:13, color:COLORS.textSecondary }}>{formatNumber(video.shares||0)}</span>
        </motion.button>
      </div>
    </div>
    </>
  );
};

// Tracks which users are currently broadcasting, so their avatar can show a LIVE
// badge wherever it already appears (Stories, their post in the feed) instead of
// duplicating that avatar in a separate floating strip.
// A live stream's `active: true` flag was previously only ever cleared by the host's own
// cleanup running on clean component unmount (see the LiveStream effect below). If the
// host's tab crashed, lost network, force-quit the app, or the OS just killed it in the
// background, that cleanup never ran and the doc stayed `active: true` forever — so the
// red LIVE ring kept showing on that user's avatar/profile even though they weren't
// streaming anymore. The host now also writes a `lastHeartbeat` timestamp every ~15s
// while genuinely live (see the host effect), and this hook additionally requires that
// heartbeat to be recent before it treats someone as live, re-checked on an interval so a
// stream doesn't have to wait for another Firestore event to be recognized as stale.
const LIVE_STALE_MS = 45000;
const useLiveStreamerIds = (currentUser) => {
  const [liveIds, setLiveIds] = useState(() => new Set());
  const docsRef = useRef([]);
  useEffect(()=>{
    const recompute = () => {
      const now = Date.now();
      const ids = new Set(
        docsRef.current
          .filter(d => {
            const hb = tsToMillis(d.lastHeartbeat) || tsToMillis(d.createdAt);
            return hb && (now - hb) < LIVE_STALE_MS;
          })
          .map(d=>d.streamerId)
          .filter(id=>id && id!==currentUser?.id)
      );
      setLiveIds(ids);
    };
    const q = query(collection(db,'liveStreams'), where('active','==',true));
    const unsub = onSnapshot(q, snap=>{
      docsRef.current = snap.docs.map(d=>d.data());
      recompute();
    });
    const interval = setInterval(recompute, 10000);
    return ()=>{ unsub(); clearInterval(interval); };
  },[currentUser?.id]);
  return liveIds;
};
// Placeholder card shown while the feed's first snapshot is still loading, so the user
// sees skeleton content instead of a flash of "No posts yet" before real data arrives.
const FeedSkeletonCard = () => (
  <div style={{ background:COLORS.card, borderRadius:RADIUS.lg, padding:14, marginBottom:12 }} aria-hidden="true">
    <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:12 }}>
      <div className="skeleton-shimmer" style={{ width:38, height:38, borderRadius:'50%' }} />
      <div style={{ flex:1 }}>
        <div className="skeleton-shimmer" style={{ width:'40%', height:12, borderRadius:6, marginBottom:6 }} />
        <div className="skeleton-shimmer" style={{ width:'25%', height:10, borderRadius:6 }} />
      </div>
    </div>
    <div className="skeleton-shimmer" style={{ width:'100%', height:14, borderRadius:6, marginBottom:6 }} />
    <div className="skeleton-shimmer" style={{ width:'80%', height:14, borderRadius:6, marginBottom:12 }} />
    <div className="skeleton-shimmer" style={{ width:'100%', height:180, borderRadius:10 }} />
  </div>
);

/* PeopleYouMayKnow: considered adding a suggestions carousel into the Home feed, but the
   app already has a suggestions feature in the Friends tab (Smart Suggestions below) —
   so the Facebook-style card design went there instead, in place, rather than duplicating
   the feature across tabs. */

const HomeFeed = ({ t, videos, videosLoading, videosError, onLike, onComment, onShare, onFollow, onMessage, onVoiceCall, onVideoCall, onDuet, onStitch, onSaveSound, followed, showToast, onWatchLive, currentUser, onViewProfile, onOpenSearch, onOpenNotifications, onOpenStories, onCreateStory, onViewStory, blockedUsers, onBlock, users, onOpenProfileDrawer, onFeedScroll, onOpenCamera, onOpenComposer, navVisible, onRefresh }) => {
  const liveUserIds = useLiveStreamerIds(currentUser);
  // Inline "quick search" — filters users/posts in place instead of navigating to Discover.
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const searchResults = useMemo(()=>{
    const q = searchQuery.trim().toLowerCase();
    if(!q) return { users:[], posts:[] };
    const matchedUsers = (users||[]).filter(u=>u.id!==currentUser?.id && (u.username?.toLowerCase().includes(q) || u.fullName?.toLowerCase().includes(q))).slice(0,5);
    const matchedPosts = (videos||[]).filter(v=>v.description?.toLowerCase().includes(q)).slice(0,5);
    return { users:matchedUsers, posts:matchedPosts };
  },[searchQuery, users, videos, currentUser?.id]);

  // Inline quick composer — Photo/Video/Poll/Feeling/Live all act directly on this card
  // (single tap, no separate page). Mirrors CreateScreen's post-submission logic.
  const [composerText, setComposerText] = useState('');
  const [composerMedia, setComposerMedia] = useState([]);
  const [composerPosting, setComposerPosting] = useState(false);
  const [showFeelingPicker, setShowFeelingPicker] = useState(false);
  const [feeling, setFeeling] = useState(null);
  const [showPollBuilder, setShowPollBuilder] = useState(false);
  const [pollQuestion, setPollQuestion] = useState('');
  const [pollOptions, setPollOptions] = useState(['', '']);
  const composerFileInputRef = useRef(null);

  const pickComposerFiles = e => {
    const files = Array.from(e.target.files||[]);
    setComposerMedia(m => [...m, ...files.map(f=>({ url:URL.createObjectURL(f), file:f, type:f.type }))].slice(0,4));
    e.target.value = '';
  };
  const removeComposerMedia = idx => setComposerMedia(m => m.filter((_,i)=>i!==idx));
  const setPollOption = (idx, val) => setPollOptions(opts => opts.map((o,i)=>i===idx?val:o));
  const addPollOption = () => setPollOptions(opts => [...opts, '']); // unlimited options — poll length is only naturally bounded by what fits Firestore/UI
  const removePollOption = idx => setPollOptions(opts => opts.length>2 ? opts.filter((_,i)=>i!==idx) : opts);
  const closePollBuilder = () => { setShowPollBuilder(false); setPollQuestion(''); setPollOptions(['','']); };
  const pollIsValid = pollQuestion.trim() && pollOptions.filter(o=>o.trim()).length>=2;
  const composerHasContent = composerText.trim() || composerMedia.length || pollIsValid || feeling;

  const submitQuickPost = async () => {
    if(!composerHasContent || composerPosting) return;
    setComposerPosting(true);
    try {
      let uploadedUrls = [];
      // Previously each upload failure was swallowed by an empty `catch {}`, so a
      // broken/rejected photo or video upload just silently vanished — the post still
      // went through as a text-only post with no indication anything had failed. Now a
      // failed upload stops the whole post and tells the user, instead of quietly
      // publishing something they didn't intend to send.
      for (const m of composerMedia) {
        try {
          uploadedUrls.push(await uploadToCloudinary(m.file));
        } catch (uploadErr) {
          console.error('Media upload failed:', uploadErr);
          showToast?.(uploadErr?.message || 'Failed to upload photo/video — please try again', 'error');
          setComposerPosting(false);
          return;
        }
      }
      const payload = { description: composerText, ...buildMediaFields(composerMedia, uploadedUrls), hashtags: (composerText||'').match(/#\w+/g) || [] };
      if (pollIsValid) payload.poll = { question: pollQuestion.trim(), options: pollOptions.map(o=>o.trim()).filter(Boolean), votes:{}, voters:{} };
      if (feeling) payload.feeling = feeling;
      const data = await apiFetch('/api/videos/create', { method:'POST', body: JSON.stringify(payload) });
      showToast?.(data.moderationStatus === 'pending' ? 'Posted — under review' : 'Posted!', 'success');
      setComposerText(''); setComposerMedia([]); setFeeling(null); setShowFeelingPicker(false); closePollBuilder();
    } catch (e) { showToast?.(e?.message || 'Failed to post', 'error'); }
    setComposerPosting(false);
  };

  // Feed order is strictly reverse-chronological (newest on top, oldest at bottom) —
  // no engagement-based re-ranking.
  const filteredVideos = useMemo(()=>{
    return sortByNewest(videos.filter(v=>!(blockedUsers||[]).includes(v.userId)));
  },[videos, blockedUsers]);

  // ── Pull-to-refresh — standard mobile-feed gesture (Instagram/TikTok/X-style).
  // Only engages when the scroll container is already at the very top (scrollTop
  // === 0), so it never fights with normal scrolling further down the feed. Tracks
  // the raw touch distance, applies resistance past the trigger threshold so it
  // doesn't feel like it's pulling forever, and calls the real onRefresh (which
  // re-fetches from Firestore) once released past the threshold.
  const feedScrollRef = useRef(null);
  const [pullDistance, setPullDistance] = useState(0);
  const [refreshing, setRefreshing] = useState(false);
  const pullStartY = useRef(null);
  const PULL_TRIGGER = 64;
  const handlePullStart = (e) => {
    if (refreshing || (feedScrollRef.current?.scrollTop || 0) > 0) { pullStartY.current = null; return; }
    pullStartY.current = e.touches[0].clientY;
  };
  const handlePullMove = (e) => {
    if (pullStartY.current == null || refreshing) return;
    const delta = e.touches[0].clientY - pullStartY.current;
    if (delta <= 0) { setPullDistance(0); return; }
    // Resistance curve — the further you pull, the less additional distance you get,
    // so it feels elastic rather than a 1:1 linear drag.
    setPullDistance(Math.min(100, delta * 0.5));
  };
  const handlePullEnd = async () => {
    if (pullStartY.current == null) return;
    pullStartY.current = null;
    if (pullDistance >= PULL_TRIGGER && !refreshing) {
      setRefreshing(true);
      haptic?.('light');
      try { await onRefresh?.(); } finally {
        setTimeout(() => { setRefreshing(false); setPullDistance(0); }, 350);
      }
    } else {
      setPullDistance(0);
    }
  };

  return (
    <div ref={feedScrollRef} data-main-scroll="true" onScroll={onFeedScroll}
      onTouchStart={handlePullStart} onTouchMove={handlePullMove} onTouchEnd={handlePullEnd}
      style={{ height:'100%', overflowY:'auto', background:COLORS.bg, padding:'10px 14px max(74px, calc(58px + env(safe-area-inset-bottom)))' }}>
      {/* Pull-to-refresh indicator — grows/rotates with pull distance, then spins
          in place once refreshing (real re-fetch via onRefresh, not decorative). */}
      {(pullDistance > 0 || refreshing) && (
        <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height: refreshing ? 44 : Math.min(44, pullDistance), overflow:'hidden', transition: refreshing ? 'height 0.2s ease' : 'none', marginBottom: (refreshing || pullDistance > 0) ? 6 : 0 }}>
          <div style={{
            width:24, height:24, borderRadius:'50%', border:`2.5px solid ${COLORS.border}`, borderTopColor:COLORS.brand,
            opacity: Math.min(1, (refreshing ? 1 : pullDistance / PULL_TRIGGER)),
            transform: refreshing ? 'none' : `rotate(${pullDistance * 3}deg)`,
            animation: refreshing ? 'spin 0.7s linear infinite' : 'none',
          }} />
        </div>
      )}
      {/* Sticky header — masthead + search + notifications stay pinned while the feed
          scrolls beneath, instead of disappearing off the top like a page section.
          Solid COLORS.bg (not a translucent blur) so it reads correctly in both
          light and dark mode without needing a separate alpha token. Slides away on
          scroll-down and back on scroll-up, mirroring the bottom nav's behavior
          (same navVisible flag, same transform/transition), so scrolling through the
          feed gets the full screen instead of a header stuck in place forever. */}
      <div style={{ position:'sticky', top:0, zIndex:Z.stickyHeader, background:COLORS.bg, margin:'-10px -14px 0', padding:'10px 14px 8px', transform: navVisible ? 'translateY(0)' : 'translateY(-100%)', transition:'transform 0.25s cubic-bezier(0.4,0,0.2,1)' }}>
        {/* Masthead — the app's wordmark, top-left, the way Instagram/Facebook/Threads
            anchor their brand at the top of the main feed. Rendered in the same brand
            gradient used everywhere else (nav active state, buttons) so it reads as
            part of one cohesive identity rather than a bolted-on label. */}
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:10, padding:'2px 2px 0' }}>
          <div style={{ display:'flex', alignItems:'center', gap:5 }}>
            <span style={{ fontSize:15 }}>♾️</span>
            <span style={{ fontSize:20, fontWeight:900, letterSpacing:-0.6, background:COLORS.gradient, WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text' }}>Infinity</span>
          </div>
        </div>

        {/* Top search bar — expands and filters in place; tapping a result acts immediately,
            nothing here navigates to a separate search page. */}
        <div style={{ position:'relative' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10 }}>
            <button onClick={onOpenProfileDrawer} aria-label="Open profile menu" style={{ width:40, height:40, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center', background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:14, cursor:'pointer' }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.textPrimary} strokeWidth="2" strokeLinecap="round"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg>
          </button>
          <div style={{ flex:1, display:'flex', alignItems:'center', gap:8, background:COLORS.surface, border:`1px solid ${searchOpen?COLORS.brand:COLORS.border}`, borderRadius:20, padding:'10px 14px' }}>
            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2" style={{flexShrink:0}}><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
            <input
              value={searchQuery}
              onFocus={()=>setSearchOpen(true)}
              onChange={e=>{ setSearchQuery(e.target.value); setSearchOpen(true); }}
              placeholder="Search"
              style={{ flex:1, minWidth:0, background:'none', border:'none', outline:'none', color:COLORS.textPrimary, fontSize:13, fontFamily:'inherit' }}
            />
            {searchOpen && (
              <span onClick={()=>{ setSearchOpen(false); setSearchQuery(''); }} style={{ cursor:'pointer', color:COLORS.textTertiary, fontSize:12, flexShrink:0 }}>✕</span>
            )}
          </div>
          <NotificationBellButton onOpenNotifications={onOpenNotifications} currentUser={currentUser} />
        </div>


        {searchOpen && searchQuery.trim() && (
          <div style={{ position:'absolute', top:'calc(100% + 6px)', left:50, right:0, background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:16, boxShadow:SHADOW.raised, zIndex:Z.popover, maxHeight:320, overflowY:'auto', padding:8 }}>
            {!searchResults.users.length && !searchResults.posts.length && (
              <div style={{ padding:'14px 10px', color:COLORS.textTertiary, fontSize:12.5, textAlign:'center' }}>No matches for "{searchQuery}"</div>
            )}
            {searchResults.users.map(u=>(
              <div key={u.id} onClick={()=>{ onViewProfile?.(u.id); setSearchOpen(false); setSearchQuery(''); }} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 6px', borderRadius:10, cursor:'pointer' }}>
                <div style={{ width:32, height:32, borderRadius:'50%', background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:13, overflow:'hidden', flexShrink:0 }}>
                  {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt=""/> : (u.username||'?')[0]?.toUpperCase()}
                </div>
                <div style={{ minWidth:0 }}>
                  <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>@{u.username}</div>
                  {u.fullName && <div style={{ color:COLORS.textTertiary, fontSize:11 }}>{u.fullName}</div>}
                </div>
              </div>
            ))}
            {searchResults.posts.map(v=>(
              <div key={v.id} onClick={()=>{ onViewProfile?.(v.userId); setSearchOpen(false); setSearchQuery(''); }} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 6px', borderRadius:10, cursor:'pointer' }}>
                <div style={{ width:32, height:32, borderRadius:8, background:COLORS.surfaceAlt, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><rect x="3" y="5" width="18" height="14" rx="2"/><circle cx="8.5" cy="10" r="1.5"/><path d="M21 15l-5-5L5 19"/></svg>
                </div>
                <div style={{ color:COLORS.textSecondary, fontSize:12.5, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{v.description}</div>
              </div>
            ))}
          </div>
        )}
        </div>
      </div>

      {/* Stories row — reuses the same Stories component as the Friends feed, so
          tapping an avatar actually opens that user's story instead of their profile,
          and the "+" actually opens the story composer instead of doing nothing. */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:2 }}>
        <span style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:14 }}>Stories</span>
        <span onClick={onOpenStories} style={{ color:COLORS.brand, fontSize:12, fontWeight:700, cursor:'pointer' }}>See all</span>
      </div>
      <div style={{ margin:'0 -14px 6px' }}>
        <Stories users={users} currentUser={currentUser} onViewStory={onViewStory} onCreateStory={onCreateStory} followed={followed} liveUserIds={liveUserIds} />
      </div>

      {/* Post composer — fully inline: typing, attaching a photo, building a poll and
          picking a feeling all happen right here in one tap each, nothing navigates away. */}
      <div style={{ background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:RADIUS.lg, padding:14, marginBottom:0 }}>
        <input ref={composerFileInputRef} type="file" accept="image/*,video/*" multiple onChange={pickComposerFiles} style={{ display:'none' }} />
        <div style={{ display:'flex', alignItems:'flex-start', gap:10, marginBottom:12 }}>
          <div style={{ width:38, height:38, borderRadius:'50%', background:currentUser?.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, overflow:'hidden', flexShrink:0 }}>
            {currentUser?.avatarUrl ? <img loading="lazy" decoding="async" src={currentUser.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt=""/> : (currentUser?.username||'?')[0]?.toUpperCase()}
          </div>
          <textarea
            value={composerText}
            onChange={e=>setComposerText(e.target.value)}
            placeholder="What's on your mind?"
            rows={1}
            style={{ flex:1, minWidth:0, background:'none', border:'none', outline:'none', resize:'none', color:COLORS.textPrimary, fontSize:13.5, fontFamily:'inherit', paddingTop:8 }}
          />
        </div>

        {feeling && (
          <div style={{ display:'inline-flex', alignItems:'center', gap:6, background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, borderRadius:12, padding:'5px 10px', fontSize:12, fontWeight:600, color:COLORS.textSecondary, marginBottom:10 }}>
            feeling {feeling.emoji} {feeling.text}
            <span onClick={()=>setFeeling(null)} style={{ cursor:'pointer', color:COLORS.textTertiary, fontWeight:800 }}>✕</span>
          </div>
        )}

        {composerMedia.length>0 && (
          <div style={{ display:'flex', gap:8, marginBottom:12, overflowX:'auto' }}>
            {composerMedia.map((m,i)=>(
              <div key={i} style={{ position:'relative', width:64, height:64, borderRadius:12, overflow:'hidden', background:COLORS.surfaceAlt, flexShrink:0 }}>
                {m.type?.startsWith('video') ? <video src={m.url} style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : <img loading="lazy" decoding="async" src={m.url} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} />}
                <button onClick={()=>removeComposerMedia(i)} aria-label="Remove media" style={{ position:'absolute', top:3, right:3, width:18, height:18, borderRadius:'50%', background:'rgba(0,0,0,0.55)', color:'#fff', border:'none', cursor:'pointer', fontSize:11, display:'flex', alignItems:'center', justifyContent:'center' }}>✕</button>
              </div>
            ))}
          </div>
        )}

        {showFeelingPicker && (
          <div style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, borderRadius:14, padding:12, marginBottom:12 }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:8 }}>
              <span style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:12.5 }}>How are you feeling?</span>
              <span onClick={()=>setShowFeelingPicker(false)} style={{ cursor:'pointer', color:COLORS.textTertiary }}>✕</span>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:8 }}>
              {FEELINGS.map(f=>(
                <button key={f.text} onClick={()=>{ setFeeling(f); setShowFeelingPicker(false); }} style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:4, background:feeling?.text===f.text?COLORS.surface2:COLORS.surface, border:`1px solid ${feeling?.text===f.text?COLORS.brand:COLORS.border}`, borderRadius:12, padding:'8px 4px', cursor:'pointer' }}>
                  <span style={{ fontSize:18 }}>{f.emoji}</span>
                  <span style={{ fontSize:9.5, color:COLORS.textSecondary, fontWeight:600 }}>{f.text}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {showPollBuilder && (
          <div style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, borderRadius:14, padding:12, marginBottom:12 }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:8 }}>
              <span style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:12.5 }}>📊 Create a poll</span>
              <span onClick={closePollBuilder} style={{ cursor:'pointer', color:COLORS.textTertiary }}>✕</span>
            </div>
            <input value={pollQuestion} onChange={e=>setPollQuestion(e.target.value)} placeholder="Ask a question…" style={{ width:'100%', background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:12, padding:'9px 12px', color:COLORS.textPrimary, outline:'none', fontSize:13, marginBottom:8, boxSizing:'border-box' }} />
            {pollOptions.map((opt,i)=>(
              <div key={i} style={{ display:'flex', alignItems:'center', gap:8, marginBottom:8 }}>
                <input value={opt} onChange={e=>setPollOption(i,e.target.value)} placeholder={`Option ${i+1}`} style={{ flex:1, background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:12, padding:'8px 12px', color:COLORS.textPrimary, outline:'none', fontSize:12.5, boxSizing:'border-box' }} />
                {pollOptions.length>2 && (
                  <span onClick={()=>removePollOption(i)} style={{ cursor:'pointer', color:COLORS.textTertiary, fontSize:13, padding:4 }}>✕</span>
                )}
              </div>
            ))}
            <button onClick={addPollOption} style={{ background:'none', border:'none', color:COLORS.brand, fontWeight:700, fontSize:12, cursor:'pointer', padding:'2px 0' }}>+ Add option</button>
          </div>
        )}

        <div style={{ display:'flex', alignItems:'center', gap:8, flexWrap:'wrap' }}>
          {[
            {icon:(<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.info} strokeWidth="2"><rect x="3" y="5" width="18" height="14" rx="2"/><circle cx="8.5" cy="10" r="1.5"/><path d="M21 15l-5-5L5 19"/></svg>), label:'Photo', active:false, color:COLORS.info, action:()=>composerFileInputRef.current?.click()},
            {icon:(<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.brand} strokeWidth="2"><path d="M4 20V10M12 20V4M20 20v-7"/></svg>), label:'Poll', active:showPollBuilder, color:COLORS.brand, action:()=>setShowPollBuilder(v=>!v)},
            {icon:(<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.warning} strokeWidth="2"><circle cx="12" cy="12" r="9"/><path d="M9 10h.01M15 10h.01M8 15s1.5 2 4 2 4-2 4-2"/></svg>), label:'Feeling', active:showFeelingPicker, color:COLORS.warning, action:()=>setShowFeelingPicker(v=>!v)},
            {icon:(<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.live} strokeWidth="2"><path d="M23 7l-7 5 7 5V7z"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>), label:'Live', active:false, color:COLORS.live, action:()=>onWatchLive?.(currentUser)},
          ].map(btn=>(
            <motion.button key={btn.label} whileHover={{ y:-1 }} whileTap={{ scale:0.96 }} onClick={e=>{ e.stopPropagation(); btn.action(); }} style={{ display:'flex', alignItems:'center', gap:7, background:btn.active?`${btn.color}14`:COLORS.surfaceAlt, border:`1px solid ${btn.active?`${btn.color}40`:COLORS.border}`, borderRadius:RADIUS.md, padding:'6px 12px 6px 6px', color:btn.active?btn.color:COLORS.textSecondary, fontSize:12, fontWeight:700, cursor:'pointer', transition:TRANSITION.fast }}>
              <span style={{ width:22, height:22, borderRadius:8, background:`${btn.color}1A`, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{btn.icon}</span>
              {btn.label}
            </motion.button>
          ))}
          {composerHasContent && (
            <button onClick={submitQuickPost} disabled={composerPosting} style={{ marginLeft:'auto', background:COLORS.gradient, border:'none', borderRadius:14, padding:'8px 16px', color:'white', fontSize:12.5, fontWeight:700, cursor:composerPosting?'default':'pointer', opacity:composerPosting?0.7:1, boxShadow:SHADOW.glow(COLORS.brand) }}>
              {composerPosting ? 'Posting…' : 'Post'}
            </button>
          )}
        </div>
      </div>

      {videosLoading && !filteredVideos.length && (
        <>
          <FeedSkeletonCard />
          <FeedSkeletonCard />
          <FeedSkeletonCard />
        </>
      )}

      {!videosLoading && videosError && !filteredVideos.length && (
        <div style={{ textAlign:'center', padding:'60px 20px', color:COLORS.textTertiary }}>
          <div style={{ fontSize:44, marginBottom:10 }}>⚠️</div>
          <div style={{ marginBottom:14 }}>Couldn't load your feed. Check your connection and try again.</div>
          <button onClick={()=>window.location.reload()} style={{ background:COLORS.gradient, border:'none', borderRadius:14, padding:'9px 20px', color:'white', fontSize:13, fontWeight:700, cursor:'pointer' }}>
            Retry
          </button>
        </div>
      )}

      {!videosLoading && !videosError && !filteredVideos.length && (
        <div style={{ textAlign:'center', padding:'60px 20px', color:COLORS.textTertiary }}>
          <div style={{ fontSize:44, marginBottom:10 }}>📭</div>
          <div>{t?.noVideos||'No posts yet. Be the first to post!'}</div>
        </div>
      )}

      <motion.div variants={listContainerVariants} initial="hidden" animate="visible">
        {filteredVideos.map(video=>(
          <motion.div key={video.id} variants={listItemVariants}>
            <FeedPostCard
              video={video}
              currentUser={currentUser}
              onViewProfile={onViewProfile}
              onOpenComments={onComment}
              onShare={onShare}
              users={users}
              onFollow={onFollow}
              followed={followed}
              showToast={showToast}
              onBlock={onBlock}
              isLive={liveUserIds?.has(video.userId)}
            />
          </motion.div>
        ))}
      </motion.div>
    </div>
  );
};

/* FriendsFeed removed — dead code, fully replaced by FriendsDiscoveryPage below. */
/* ─────────────── FRIENDS PAGE (real mutual friend-request system) ───────────────
   Rebuilt around a genuine, bidirectional friends graph (`friends`, `friendRequestsSent`,
   `friendRequestsReceived`, `closeFriends` on each user doc — see toggleFollow's siblings
   in InfinityV1app: sendFriendRequest/acceptFriendRequest/declineFriendRequest/removeFriend/
   toggleCloseFriend) instead of treating "who I follow" as "my friends". Follow stays exactly
   as it was everywhere else in the app (feed personalization, profile follow button); this
   page layers a separate, mutual relationship on top — the same way Instagram's Follow and
   Close Friends, or Facebook's Follow and Friend Request, coexist without one standing in
   for the other.
   Unique features added here: real mutual-connections ranking for suggestions, an Online Now
   strip driven by live presence, a Requests tab with real Received/Sent state (accept/decline/
   cancel), and Close Friends as a genuine starred list rather than "first 5 people you follow". */
// Great-circle distance in km — used by the "Nearby" explore feature below.
const haversineKm = (lat1, lon1, lat2, lon2) => {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
};

const INTEREST_OPTIONS = ['Music','Gaming','Sports','Art','Tech','Travel','Fashion','Food','Fitness','Movies','Photography','Books','Comedy','Business','Nature','Cars'];

/* ─────────── EXPLORE SHEET (Contacts / Interests / Nearby) ───────────────
   Previously "Contacts", "Interests" and "Nearby" in Friends → Explore More
   were dead buttons with no onClick at all. Each now opens a real bottom
   sheet backed by real, working functionality:
   - Contacts: uses the real Contact Picker API where the browser supports it
     (matches picked contacts against actual Infinity users by name), and
     falls back everywhere else to a working "send invite link" flow built on
     the same shareToDevice() used across the rest of the app.
   - Interests: a genuine interests graph — pick tags once (saved to your
     profile), then see other users ranked by real shared-interest overlap,
     not a placeholder list.
   - Nearby: opt-in real geolocation (your coordinates are only stored if you
     explicitly enable this), matched against other opted-in users via actual
     haversine distance, with a one-tap way to turn it back off. */
const ExploreSheet = ({ mode, currentUser, setCurrentUser, users, friendsArr, sentArr, receivedArr, onSendFriendRequest, onCancelFriendRequest, onViewProfile, showToast, onClose }) => {
  const others = useMemo(()=>(users||[]).filter(u=>u.id!==currentUser?.id), [users, currentUser?.id]);
  const titles = { contacts:'Find Contacts', interests:'Interests', nearby:'Nearby' };

  const MiniActionButton = ({ u }) => {
    const isFriend = friendsArr.includes(u.id);
    const iSent = sentArr.includes(u.id);
    const iReceived = receivedArr.includes(u.id);
    if (isFriend) return <span style={{ color:COLORS.textTertiary, fontSize:11.5, fontWeight:700 }}>✓ Friends</span>;
    if (iReceived) return <span style={{ color:COLORS.brand, fontSize:11.5, fontWeight:700 }}>Respond in Requests</span>;
    if (iSent) return <RippleButton onClick={e=>{ e.stopPropagation(); onCancelFriendRequest?.(u.id); }} style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:12, padding:'6px 12px', fontSize:11.5, fontWeight:700, cursor:'pointer' }}>Requested</RippleButton>;
    return <RippleButton onClick={e=>{ e.stopPropagation(); onSendFriendRequest?.(u.id); }} style={{ background:COLORS.gradient, border:'none', color:'white', borderRadius:12, padding:'6px 12px', fontSize:11.5, fontWeight:700, cursor:'pointer' }}>+ Add</RippleButton>;
  };

  /* ── Contacts ─────────────────────────────────────────────────────────── */
  const [contactsPicked, setContactsPicked] = useState(null); // null = not tried yet
  const [contactsBusy, setContactsBusy] = useState(false);
  const contactPickerSupported = typeof navigator !== 'undefined' && !!navigator.contacts?.select;
  const inviteUrl = 'https://infinity-now.vercel.app';

  const pickContacts = async () => {
    setContactsBusy(true);
    try {
      const picked = await navigator.contacts.select(['name','tel'], { multiple:true });
      const matches = [];
      const unmatched = [];
      for (const c of picked) {
        const name = (c.name?.[0] || '').toLowerCase().trim();
        if (!name) continue;
        const found = others.find(u => u.fullName?.toLowerCase() === name || u.username?.toLowerCase() === name || u.fullName?.toLowerCase().includes(name));
        if (found) matches.push(found); else unmatched.push(c.name?.[0] || 'Contact');
      }
      setContactsPicked({ matches, unmatched });
    } catch (e) {
      if (e?.name !== 'SecurityError' && e?.name !== 'AbortError') showToast?.('Could not read contacts', 'error');
    }
    setContactsBusy(false);
  };

  const inviteContact = (name) => shareToDevice({
    url: inviteUrl,
    title: 'Infinity',
    text: `Hey ${name}, join me on Infinity!`,
    showToast,
    copiedMessage: 'Invite link copied!',
  });

  /* ── Interests ────────────────────────────────────────────────────────── */
  const [pickingInterests, setPickingInterests] = useState(!(currentUser?.interests?.length));
  const [draftInterests, setDraftInterests] = useState(currentUser?.interests || []);
  const toggleDraftInterest = (tag) => setDraftInterests(list => list.includes(tag) ? list.filter(t=>t!==tag) : [...list, tag]);
  const saveInterests = async () => {
    try {
      await updateDoc(doc(db, 'users', currentUser.id), { interests: draftInterests });
      setCurrentUser?.(u => u ? { ...u, interests: draftInterests } : u);
      setPickingInterests(false);
      showToast?.('Interests saved', 'success');
    } catch { showToast?.('Could not save interests', 'error'); }
  };
  const interestMatches = useMemo(()=>{
    const mine = new Set(currentUser?.interests || []);
    if (!mine.size) return [];
    return others
      .map(u => ({ u, shared: (u.interests||[]).filter(t=>mine.has(t)) }))
      .filter(x => x.shared.length > 0)
      .sort((a,b)=>b.shared.length-a.shared.length)
      .slice(0, 20);
  }, [others, currentUser?.interests]);

  /* ── Nearby ───────────────────────────────────────────────────────────── */
  const [nearbyBusy, setNearbyBusy] = useState(false);
  const shareLocationOn = !!currentUser?.shareLocation && !!currentUser?.geo;

  const enableNearby = () => {
    if (!navigator.geolocation) { showToast?.('Location not supported on this device', 'error'); return; }
    setNearbyBusy(true);
    navigator.geolocation.getCurrentPosition(async (pos) => {
      const geo = { lat: pos.coords.latitude, lng: pos.coords.longitude };
      try {
        await updateDoc(doc(db, 'users', currentUser.id), { geo, shareLocation: true });
        setCurrentUser?.(u => u ? { ...u, geo, shareLocation: true } : u);
        showToast?.('Nearby enabled', 'success');
      } catch { showToast?.('Could not enable Nearby', 'error'); }
      setNearbyBusy(false);
    }, () => {
      showToast?.('Location permission denied', 'error');
      setNearbyBusy(false);
    }, { timeout: 10000 });
  };

  const disableNearby = async () => {
    try {
      await updateDoc(doc(db, 'users', currentUser.id), { shareLocation: false });
      setCurrentUser?.(u => u ? { ...u, shareLocation: false } : u);
      showToast?.('Nearby turned off', 'info');
    } catch { showToast?.('Could not update Nearby', 'error'); }
  };

  const nearbyUsers = useMemo(()=>{
    if (!shareLocationOn) return [];
    const { lat, lng } = currentUser.geo;
    return others
      .filter(u => u.shareLocation && u.geo)
      .map(u => ({ u, km: haversineKm(lat, lng, u.geo.lat, u.geo.lng) }))
      .sort((a,b)=>a.km-b.km)
      .slice(0, 30);
  }, [others, shareLocationOn, currentUser?.geo]);

  return (
    <motion.div variants={backdropVariants} initial="hidden" animate="visible" exit="hidden"
      style={{ position:'fixed', inset:0, zIndex:Z.modal, background:'rgba(20,15,35,0.45)', display:'flex', alignItems:'flex-end' }} onClick={onClose}>
      <motion.div variants={sheetVariants} initial="hidden" animate="visible" exit="exit"
        onClick={e=>e.stopPropagation()} style={{ width:'100%', maxHeight:'82vh', overflowY:'auto', background:COLORS.surface, borderTopLeftRadius:22, borderTopRightRadius:22, paddingBottom:'max(16px, env(safe-area-inset-bottom))' }}>
        <SheetBackHeader title={titles[mode]} onClose={onClose} />
        <div style={{ padding:'0 16px 16px' }}>

          {mode === 'contacts' && (
            <>
              {!contactsPicked ? (
                <div style={{ textAlign:'center', padding:'20px 8px' }}>
                  <div style={{ fontSize:38, marginBottom:10 }}>📇</div>
                  <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:14, marginBottom:6 }}>Find friends from your contacts</div>
                  <div style={{ color:COLORS.textTertiary, fontSize:12.5, marginBottom:16, lineHeight:1.5 }}>
                    {contactPickerSupported
                      ? "We'll only read the contacts you choose to share, once — nothing is uploaded."
                      : "Your browser doesn't support picking contacts directly, but you can still invite people with a link."}
                  </div>
                  {contactPickerSupported ? (
                    <RippleButton onClick={pickContacts} disabled={contactsBusy} style={{ background:COLORS.gradient, border:'none', borderRadius:14, padding:'12px 24px', color:'white', fontWeight:700, fontSize:13.5, cursor:contactsBusy?'default':'pointer', opacity:contactsBusy?0.7:1 }}>
                      {contactsBusy ? 'Reading contacts…' : 'Choose Contacts'}
                    </RippleButton>
                  ) : (
                    <RippleButton onClick={()=>inviteContact('there')} style={{ background:COLORS.gradient, border:'none', borderRadius:14, padding:'12px 24px', color:'white', fontWeight:700, fontSize:13.5, cursor:'pointer' }}>
                      Send Invite Link
                    </RippleButton>
                  )}
                </div>
              ) : (
                <>
                  {contactsPicked.matches.length > 0 && (
                    <>
                      <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13, margin:'12px 0 8px' }}>Already on Infinity</div>
                      {contactsPicked.matches.map(u=>(
                        <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'9px 0', cursor:'pointer' }}>
                          <AvatarChipSmall u={u} />
                          <div style={{ flex:1, minWidth:0 }}>
                            <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13 }}>{u.fullName || u.username}</div>
                            <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>@{u.username}</div>
                          </div>
                          <MiniActionButton u={u} />
                        </div>
                      ))}
                    </>
                  )}
                  {contactsPicked.unmatched.length > 0 && (
                    <>
                      <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13, margin:'16px 0 8px' }}>Not on Infinity yet</div>
                      {contactsPicked.unmatched.map((name,i)=>(
                        <div key={i} style={{ display:'flex', alignItems:'center', gap:12, padding:'9px 0' }}>
                          <div style={{ width:40, height:40, borderRadius:'50%', background:COLORS.surfaceAlt, display:'flex', alignItems:'center', justifyContent:'center', color:COLORS.textTertiary, fontWeight:700, flexShrink:0 }}>{name[0]?.toUpperCase()}</div>
                          <div style={{ flex:1, minWidth:0, color:COLORS.textPrimary, fontWeight:600, fontSize:13, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{name}</div>
                          <RippleButton onClick={()=>inviteContact(name)} style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:12, padding:'6px 12px', fontSize:11.5, fontWeight:700, cursor:'pointer' }}>Invite</RippleButton>
                        </div>
                      ))}
                    </>
                  )}
                  {contactsPicked.matches.length===0 && contactsPicked.unmatched.length===0 && (
                    <div style={{ textAlign:'center', padding:30, color:COLORS.textTertiary, fontSize:12.5 }}>No named contacts found in that selection.</div>
                  )}
                </>
              )}
            </>
          )}

          {mode === 'interests' && (
            pickingInterests ? (
              <>
                <div style={{ color:COLORS.textTertiary, fontSize:12.5, margin:'12px 0 12px' }}>Pick a few things you're into — we'll match you with people who share them.</div>
                <div style={{ display:'flex', flexWrap:'wrap', gap:8, marginBottom:16 }}>
                  {INTEREST_OPTIONS.map(tag=>{
                    const on = draftInterests.includes(tag);
                    return (
                      <button key={tag} onClick={()=>toggleDraftInterest(tag)} style={{ background:on?COLORS.gradient:COLORS.surfaceAlt, border:`1px solid ${on?'transparent':COLORS.border}`, borderRadius:16, padding:'8px 14px', color:on?'#fff':COLORS.textSecondary, fontSize:12.5, fontWeight:700, cursor:'pointer' }}>
                        {tag}
                      </button>
                    );
                  })}
                </div>
                <RippleButton onClick={saveInterests} disabled={!draftInterests.length} style={{ width:'100%', background:COLORS.gradient, border:'none', borderRadius:14, padding:'13px 0', color:'white', fontWeight:700, fontSize:13.5, cursor:draftInterests.length?'pointer':'default', opacity:draftInterests.length?1:0.5 }}>
                  Save Interests
                </RippleButton>
              </>
            ) : (
              <>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', margin:'12px 0 4px' }}>
                  <div style={{ display:'flex', flexWrap:'wrap', gap:6 }}>
                    {(currentUser?.interests||[]).map(tag=>(
                      <span key={tag} style={{ background:COLORS.surfaceAlt, borderRadius:12, padding:'4px 10px', color:COLORS.textSecondary, fontSize:11, fontWeight:700 }}>{tag}</span>
                    ))}
                  </div>
                  <span onClick={()=>{ setDraftInterests(currentUser?.interests||[]); setPickingInterests(true); }} style={{ color:COLORS.brand, fontSize:12, fontWeight:700, cursor:'pointer', flexShrink:0, marginLeft:8 }}>Edit</span>
                </div>
                <div style={{ color:COLORS.textTertiary, fontSize:11.5, margin:'8px 0 14px' }}>{interestMatches.length} {interestMatches.length===1?'person shares':'people share'} your interests</div>
                {interestMatches.length===0 && <div style={{ textAlign:'center', padding:30, color:COLORS.textTertiary, fontSize:12.5 }}>No matches yet — check back as more people join.</div>}
                {interestMatches.map(({u, shared})=>(
                  <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'9px 0', cursor:'pointer' }}>
                    <AvatarChipSmall u={u} />
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13 }}>{u.fullName || u.username}</div>
                      <div style={{ color:COLORS.textTertiary, fontSize:11 }}>{shared.join(', ')}</div>
                    </div>
                    <MiniActionButton u={u} />
                  </div>
                ))}
              </>
            )
          )}

          {mode === 'nearby' && (
            !shareLocationOn ? (
              <div style={{ textAlign:'center', padding:'20px 8px' }}>
                <div style={{ fontSize:38, marginBottom:10 }}>📍</div>
                <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:14, marginBottom:6 }}>See people near you</div>
                <div style={{ color:COLORS.textTertiary, fontSize:12.5, marginBottom:16, lineHeight:1.5 }}>Your location is only shared if you turn this on, and only with other people who've also opted in. Turn it off any time.</div>
                <RippleButton onClick={enableNearby} disabled={nearbyBusy} style={{ background:COLORS.gradient, border:'none', borderRadius:14, padding:'12px 24px', color:'white', fontWeight:700, fontSize:13.5, cursor:nearbyBusy?'default':'pointer', opacity:nearbyBusy?0.7:1 }}>
                  {nearbyBusy ? 'Locating…' : 'Enable Nearby'}
                </RippleButton>
              </div>
            ) : (
              <>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', margin:'12px 0 14px' }}>
                  <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>{nearbyUsers.length} {nearbyUsers.length===1?'person':'people'} nearby</div>
                  <span onClick={disableNearby} style={{ color:COLORS.danger||'#FF453A', fontSize:12, fontWeight:700, cursor:'pointer' }}>Turn off Nearby</span>
                </div>
                {nearbyUsers.length===0 && <div style={{ textAlign:'center', padding:30, color:COLORS.textTertiary, fontSize:12.5 }}>No one nearby has Nearby turned on yet.</div>}
                {nearbyUsers.map(({u, km})=>(
                  <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'9px 0', cursor:'pointer' }}>
                    <AvatarChipSmall u={u} />
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13 }}>{u.fullName || u.username}</div>
                      <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>{km < 1 ? `${Math.round(km*1000)} m away` : `${km.toFixed(1)} km away`}</div>
                    </div>
                    <MiniActionButton u={u} />
                  </div>
                ))}
              </>
            )
          )}
        </div>
      </motion.div>
    </motion.div>
  );
};

const AvatarChipSmall = ({ u }) => (
  <div style={{ width:40, height:40, borderRadius:'50%', background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:15, overflow:'hidden', flexShrink:0 }}>
    {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt=""/> : (u.avatar||u.username?.[0]||'?')}
  </div>
);

const FriendsDiscoveryPage = ({
  currentUser, setCurrentUser, users, followed, onFollow,
  friends, friendRequestsSent, friendRequestsReceived, closeFriends,
  onSendFriendRequest, onCancelFriendRequest, onAcceptFriendRequest, onDeclineFriendRequest, onRemoveFriend, onToggleCloseFriend,
  onViewProfile, onOpenSearch, onFeedScroll, onCreateStory, onViewStory, onOpenStories, onMessage, showToast,
}) => {
  const [tab, setTab] = useState('discover');
  const [requestsSubTab, setRequestsSubTab] = useState('received');
  const [search, setSearch] = useState('');
  const [openMenuId, setOpenMenuId] = useState(null);
  const [exploreSheet, setExploreSheet] = useState(null); // null | 'contacts' | 'interests' | 'nearby'

  const friendsArr = friends || [];
  const sentArr = friendRequestsSent || [];
  const receivedArr = friendRequestsReceived || [];
  const closeArr = closeFriends || [];

  const others = useMemo(()=>(users||[]).filter(u=>u.id!==currentUser?.id), [users, currentUser?.id]);

  // Real mutual-connections count: intersection of everyone *I* follow/friend with
  // everyone *they* follow/friend — not the old `followerCount % 20` placeholder.
  const myConnections = useMemo(()=>new Set([...(followed||[]), ...friendsArr]), [followed, friendsArr]);
  const mutualCount = useCallback((u)=>{
    const theirs = new Set([...(u.following||[]), ...(u.friends||[])]);
    let n = 0;
    myConnections.forEach(id => { if (theirs.has(id)) n++; });
    return n;
  }, [myConnections]);

  const yourFriends = useMemo(()=>
    others.filter(u=>friendsArr.includes(u.id)).sort((a,b)=>mutualCount(b)-mutualCount(a))
  , [others, friendsArr, mutualCount]);

  const closeFriendUsers = useMemo(()=>
    others.filter(u=>closeArr.includes(u.id))
  , [others, closeArr]);

  const receivedUsers = useMemo(()=>others.filter(u=>receivedArr.includes(u.id)), [others, receivedArr]);
  const sentUsers = useMemo(()=>others.filter(u=>sentArr.includes(u.id)), [others, sentArr]);

  const suggestions = useMemo(()=>
    others
      .filter(u=>!friendsArr.includes(u.id) && !sentArr.includes(u.id) && !receivedArr.includes(u.id))
      .sort((a,b)=> (mutualCount(b)-mutualCount(a)) || ((b.followers?.length||0)-(a.followers?.length||0)))
      .slice(0,8)
  ,[others, friendsArr, sentArr, receivedArr, mutualCount]);

  const filteredList = search
    ? others.filter(u=>u.username?.toLowerCase().includes(search.toLowerCase()) || u.fullName?.toLowerCase().includes(search.toLowerCase()))
    : null;

  const AvatarCircle = ({ u, size=44 }) => (
    <div style={{ width:size, height:size, borderRadius:'50%', background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:size*0.4, overflow:'hidden', flexShrink:0 }}>
      {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt=""/> : (u.avatar||u.username?.[0]||'?')}
    </div>
  );

  // One relationship button that reflects the *real* friend-request state machine:
  // none → Add Friend, sent → Requested (tap to cancel), received → Accept/Decline,
  // friends → Friends ✓ (tap opens a small actions menu: message / close friend / remove).
  const FriendActionButton = ({ u, compact=false }) => {
    const isFriend = friendsArr.includes(u.id);
    const iSent = sentArr.includes(u.id);
    const iReceived = receivedArr.includes(u.id);
    const pad = compact ? '6px 14px' : '7px 16px';
    const fontSize = compact ? 11.5 : 12;

    if (isFriend) {
      const isClose = closeArr.includes(u.id);
      return (
        <div style={{ position:'relative' }}>
          <RippleButton onClick={e=>{ e.stopPropagation(); setOpenMenuId(openMenuId===u.id?null:u.id); }}
            style={{ display:'flex', alignItems:'center', gap:4, background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:14, padding:pad, fontSize, fontWeight:700, cursor:'pointer' }}>
            {isClose && <span style={{fontSize:11}}>⭐</span>} Friends <span style={{fontSize:9}}>▾</span>
          </RippleButton>
          {openMenuId===u.id && (
            <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', top:'110%', right:0, zIndex:20, background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:14, boxShadow:SHADOW.card, minWidth:170, overflow:'hidden' }}>
              {onMessage && <div onClick={()=>{ setOpenMenuId(null); onMessage(u.id); }} style={{ padding:'11px 14px', fontSize:13, color:COLORS.textPrimary, cursor:'pointer', fontWeight:600 }}>💬 Message</div>}
              <div onClick={()=>{ setOpenMenuId(null); onToggleCloseFriend?.(u.id); }} style={{ padding:'11px 14px', fontSize:13, color:COLORS.textPrimary, cursor:'pointer', fontWeight:600, borderTop:`1px solid ${COLORS.border}` }}>{isClose ? '⭐ Remove Close Friend' : '⭐ Add to Close Friends'}</div>
              <div onClick={()=>{ setOpenMenuId(null); onRemoveFriend?.(u.id); }} style={{ padding:'11px 14px', fontSize:13, color:COLORS.danger||'#FF453A', cursor:'pointer', fontWeight:600, borderTop:`1px solid ${COLORS.border}` }}>✕ Remove Friend</div>
            </div>
          )}
        </div>
      );
    }
    if (iReceived) {
      return (
        <div style={{ display:'flex', gap:6 }}>
          <RippleButton onClick={e=>{ e.stopPropagation(); onAcceptFriendRequest?.(u.id); }} style={{ background:COLORS.gradient, border:'none', color:'white', borderRadius:14, padding:pad, fontSize, fontWeight:700, cursor:'pointer', boxShadow:SHADOW.glow(COLORS.brand) }}>Accept</RippleButton>
          <RippleButton onClick={e=>{ e.stopPropagation(); onDeclineFriendRequest?.(u.id); }} style={{ background:'none', border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:14, padding:pad, fontSize, fontWeight:700, cursor:'pointer' }}>Decline</RippleButton>
        </div>
      );
    }
    if (iSent) {
      return (
        <RippleButton onClick={e=>{ e.stopPropagation(); onCancelFriendRequest?.(u.id); }} style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:14, padding:pad, fontSize, fontWeight:700, cursor:'pointer' }}>Requested</RippleButton>
      );
    }
    return (
      <RippleButton onClick={e=>{ e.stopPropagation(); onSendFriendRequest?.(u.id); }} style={{ background:COLORS.gradient, border:'none', color:'white', borderRadius:14, padding:pad, fontSize, fontWeight:700, cursor:'pointer', boxShadow:SHADOW.glow(COLORS.brand) }}>+ Add Friend</RippleButton>
    );
  };

  const requestsBadgeCount = receivedArr.length;

  return (
    <div data-main-scroll="true" onScroll={e=>{ onFeedScroll?.(e); setOpenMenuId(null); }} style={{ height:'100%', overflowY:'auto', background:COLORS.bg, padding:'10px 16px max(74px, calc(58px + env(safe-area-inset-bottom)))' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:10 }}>
        <div style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:18 }}>Friends</div>
        {friendsArr.length > 0 && <div style={{ color:COLORS.textTertiary, fontSize:12, fontWeight:600 }}>{friendsArr.length} friend{friendsArr.length!==1?'s':''}</div>}
      </div>
      <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:12 }}>
        <div style={{ flex:1, display:'flex', alignItems:'center', gap:8, background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:20, padding:'10px 14px' }}>
          <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke={COLORS.textTertiary} strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search friends" style={{ flex:1, background:'none', border:'none', outline:'none', color:COLORS.textPrimary, fontSize:13 }} />
        </div>
        <button onClick={onOpenSearch} aria-label="Add friend" style={{ width:38, height:38, borderRadius:'50%', background:COLORS.surfaceAlt, border:'none', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', flexShrink:0 }}>
          <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
        </button>
      </div>

      {!search && (
        <>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:2 }}>
            <span style={{ color:COLORS.textPrimary, fontWeight:800, fontSize:14 }}>Stories</span>
            {onOpenStories && <span onClick={onOpenStories} style={{ color:COLORS.brand, fontSize:12, fontWeight:700, cursor:'pointer' }}>See all</span>}
          </div>
          <div style={{ margin:'0 -16px 6px' }}>
            <Stories users={users} currentUser={currentUser} onViewStory={onViewStory} onCreateStory={onCreateStory} followed={followed} />
          </div>
        </>
      )}

      {search ? (
        <div>
          {filteredList.length===0 && <div style={{ textAlign:'center', padding:40, color:COLORS.textTertiary }}>No results for "{search}"</div>}
          {filteredList.map(u=>(
            <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
              <AvatarCircle u={u} />
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{u.fullName || u.username}</div>
                <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}</div>
              </div>
              <FriendActionButton u={u} compact />
            </div>
          ))}
        </div>
      ) : (
      <>
      <div style={{ display:'flex', gap:22, marginBottom:14, overflowX:'auto' }}>
        {[
          ['discover','Discover'],
          ['friends',`Friends${friendsArr.length?` (${friendsArr.length})`:''}`],
          ['requests','Requests'],
          ['close','Close Friends'],
          ['groups','Groups'],
        ].map(([id,label])=>(
          <button key={id} onClick={()=>{ setTab(id); setOpenMenuId(null); }} style={{ position:'relative', flexShrink:0, background:'none', border:'none', borderBottom:tab===id?`2px solid ${COLORS.brand}`:'2px solid transparent', padding:'0 0 10px', color:tab===id?COLORS.brand:COLORS.textTertiary, fontSize:13.5, fontWeight:700, cursor:'pointer', whiteSpace:'nowrap' }}>
            {label}
            {id==='requests' && requestsBadgeCount > 0 && (
              <span style={{ position:'absolute', top:-4, right:-14, background:COLORS.danger||'#FF453A', color:'white', fontSize:9.5, fontWeight:800, borderRadius:8, minWidth:16, height:16, padding:'0 3px', display:'flex', alignItems:'center', justifyContent:'center' }}>{requestsBadgeCount}</span>
            )}
          </button>
        ))}
      </div>

      {tab==='discover' && (
        <>
          <div style={{ display:'flex', alignItems:'flex-start', gap:10, marginBottom:12 }}>
            <div style={{ width:34, height:34, borderRadius:10, background:COLORS.surfaceAlt, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
              <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke={COLORS.brand} strokeWidth="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>
            </div>
            <div style={{ flex:1 }}>
              <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>Smart Suggestions</div>
              <div style={{ color:COLORS.textTertiary, fontSize:11.5, marginTop:2 }}>Ranked by real mutual connections — people you and your friends both know</div>
            </div>
          </div>
          {suggestions.length===0 && <div style={{ color:COLORS.textTertiary, fontSize:12.5, padding:'8px 0 18px' }}>No new suggestions right now — check back later.</div>}
          <div style={{ display:'flex', gap:10, overflowX:'auto', paddingBottom:16, marginBottom:6 }}>
            {suggestions.map(u=>{
              const mc = mutualCount(u);
              return (
                <div key={u.id} style={{ position:'relative', flexShrink:0, width:132, background:COLORS.surfaceAlt, borderRadius:14, overflow:'hidden', border:`1px solid ${COLORS.border}`, boxShadow:SHADOW.card, transition:TRANSITION.base }}>
                  <div onClick={()=>onViewProfile?.(u.id)} style={{ height:110, background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', overflow:'hidden' }}>
                    {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{ width:'100%', height:'100%', objectFit:'cover' }} alt="" /> : <span style={{ color:'white', fontWeight:800, fontSize:32 }}>{u.avatar||u.username?.[0]?.toUpperCase()}</span>}
                  </div>
                  <div style={{ padding:'8px 10px 10px' }}>
                    <div onClick={()=>onViewProfile?.(u.id)} style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:12.5, cursor:'pointer', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{u.fullName || u.username}</div>
                    <div style={{ color:COLORS.textTertiary, fontSize:11, marginBottom:8 }}>{mc > 0 ? `${mc} mutual` : 'New to Infinity'}</div>
                    <RippleButton onClick={()=>onSendFriendRequest?.(u.id)} style={{ width:'100%', background:COLORS.gradient, border:'none', borderRadius:8, padding:'7px 0', color:'white', fontSize:12, fontWeight:700, cursor:'pointer' }}>+ Add Friend</RippleButton>
                  </div>
                </div>
              );
            })}
          </div>

          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
            <div>
              <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>Close Friends</div>
              <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>Your starred inner circle</div>
            </div>
            <span onClick={()=>setTab('close')} style={{ color:COLORS.brand, fontSize:12, fontWeight:700, cursor:'pointer' }}>See all</span>
          </div>
          {closeFriendUsers.length===0 && (
            <div style={{ padding:'14px 0' }}>
              <div style={{ color:COLORS.textTertiary, fontSize:12.5, marginBottom:8 }}>Star a friend to add them here.</div>
              <RippleButton onClick={()=>setTab('friends')} style={{ background:COLORS.surfaceAlt, border:`1px solid ${COLORS.border}`, borderRadius:12, padding:'8px 16px', color:COLORS.textPrimary, fontSize:12, fontWeight:700, cursor:'pointer' }}>Go to Friends list →</RippleButton>
            </div>
          )}
          {closeFriendUsers.slice(0,5).map(u=>(
            <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
              <AvatarCircle u={u} size={40} />
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13 }}>{u.fullName || u.username}</div>
                <div style={{ color:COLORS.textTertiary, fontSize:11.5 }}>@{u.username}</div>
              </div>
              <span style={{fontSize:14}}>⭐</span>
            </div>
          ))}

          <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5, margin:'18px 0 10px' }}>Explore More</div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:8 }}>
            {[
              {label:'Contacts', icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>), action:()=>setExploreSheet('contacts')},
              {label:'Interests', icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg>), action:()=>setExploreSheet('interests')},
              {label:'Nearby', icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z"/><circle cx="12" cy="9" r="2.5"/></svg>), action:()=>setExploreSheet('nearby')},
              {label:'Groups', icon:(<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={COLORS.textSecondary} strokeWidth="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87M16 3.13a4 4 0 010 7.75"/></svg>), action:()=>setTab('groups')},
            ].map(item=>(
              <motion.button key={item.label} whileTap={tapScale} onClick={item.action}
                style={{ background:COLORS.surface, border:`1px solid ${COLORS.border}`, borderRadius:16, padding:'14px 6px', display:'flex', flexDirection:'column', alignItems:'center', gap:6, cursor:'pointer', boxShadow:SHADOW.xs, transition:TRANSITION.fast }}>
                {item.icon}
                <span style={{ color:COLORS.textSecondary, fontSize:10.5, fontWeight:600 }}>{item.label}</span>
              </motion.button>
            ))}
          </div>
        </>
      )}

      {tab==='friends' && (
        <>
          {yourFriends.length > 0 && (
            <div style={{ margin:'0 -16px 14px' }}>
              <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13, margin:'0 16px 8px' }}>Online Now</div>
              <div style={{ display:'flex', gap:14, overflowX:'auto', padding:'0 16px 4px' }}>
                {yourFriends.map(u=><OnlineFriendChip key={u.id} u={u} onClick={()=>onViewProfile?.(u.id)} />)}
              </div>
            </div>
          )}
          {yourFriends.length===0 ? (
            <div style={{ textAlign:'center', padding:48, color:COLORS.textTertiary }}>
              <div style={{ fontSize:44, marginBottom:12 }}>👥</div>
              <div>No friends yet — send a request from Discover or Search</div>
            </div>
          ) : yourFriends.map(u=>{
            const mc = mutualCount(u);
            return (
              <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
                <AvatarCircle u={u} />
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{u.fullName || u.username}</div>
                  <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}{mc>0 ? ` · ${mc} mutual` : ''}</div>
                </div>
                <FriendActionButton u={u} compact />
              </div>
            );
          })}
        </>
      )}

      {tab==='close' && (
        closeFriendUsers.length===0 ? (
          <div style={{ textAlign:'center', padding:48, color:COLORS.textTertiary }}>
            <div style={{ fontSize:44, marginBottom:12 }}>⭐</div>
            <div>No close friends yet</div>
            <div style={{ fontSize:12, marginTop:6 }}>Open a friend's "Friends ▾" menu to star them</div>
          </div>
        ) : closeFriendUsers.map(u=>(
          <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
            <AvatarCircle u={u} />
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{u.fullName || u.username}</div>
              <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}</div>
            </div>
            <RippleButton onClick={e=>{ e.stopPropagation(); onToggleCloseFriend?.(u.id); }} style={{ background:'none', border:`1px solid ${COLORS.border}`, color:COLORS.textSecondary, borderRadius:14, padding:'6px 14px', fontSize:11.5, fontWeight:700, cursor:'pointer' }}>⭐ Starred</RippleButton>
          </div>
        ))
      )}

      {tab==='requests' && (
        <>
          <div style={{ display:'flex', gap:8, marginBottom:14 }}>
            {[['received',`Received${receivedUsers.length?` (${receivedUsers.length})`:''}`],['sent',`Sent${sentUsers.length?` (${sentUsers.length})`:''}`]].map(([id,label])=>(
              <button key={id} onClick={()=>setRequestsSubTab(id)} style={{ flex:1, background:requestsSubTab===id?COLORS.gradient:COLORS.surfaceAlt, border:'none', borderRadius:12, padding:'9px 0', color:requestsSubTab===id?'white':COLORS.textSecondary, fontSize:12.5, fontWeight:700, cursor:'pointer', transition:TRANSITION.fast }}>{label}</button>
            ))}
          </div>
          {requestsSubTab==='received' ? (
            receivedUsers.length===0 ? (
              <div style={{ textAlign:'center', padding:48, color:COLORS.textTertiary }}>
                <div style={{ fontSize:44, marginBottom:12 }}>📬</div>
                <div>No pending friend requests</div>
              </div>
            ) : receivedUsers.map(u=>(
              <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
                <AvatarCircle u={u} />
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{u.fullName || u.username}</div>
                  <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}{mutualCount(u)>0 ? ` · ${mutualCount(u)} mutual` : ''}</div>
                </div>
                <FriendActionButton u={u} compact />
              </div>
            ))
          ) : (
            sentUsers.length===0 ? (
              <div style={{ textAlign:'center', padding:48, color:COLORS.textTertiary }}>
                <div style={{ fontSize:44, marginBottom:12 }}>📤</div>
                <div>You haven't sent any requests</div>
              </div>
            ) : sentUsers.map(u=>(
              <div key={u.id} onClick={()=>onViewProfile?.(u.id)} style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 0', cursor:'pointer' }}>
                <AvatarCircle u={u} />
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ color:COLORS.textPrimary, fontWeight:700, fontSize:13.5 }}>{u.fullName || u.username}</div>
                  <div style={{ color:COLORS.textTertiary, fontSize:12 }}>@{u.username}</div>
                </div>
                <FriendActionButton u={u} compact />
              </div>
            ))
          )}
        </>
      )}

      {tab==='groups' && (
        <div style={{ margin:'0 -16px', height:'calc(100vh - 260px)', minHeight:420 }}>
          <GroupChatPage currentUser={currentUser} users={users} showToast={showToast} onBack={()=>setTab('discover')} />
        </div>
      )}
      </>
      )}
      <AnimatePresence>
        {exploreSheet && (
          <ExploreSheet
            mode={exploreSheet}
            currentUser={currentUser}
            setCurrentUser={setCurrentUser}
            users={users}
            friendsArr={friendsArr}
            sentArr={sentArr}
            receivedArr={receivedArr}
            onSendFriendRequest={onSendFriendRequest}
            onCancelFriendRequest={onCancelFriendRequest}
            onViewProfile={onViewProfile}
            showToast={showToast}
            onClose={()=>setExploreSheet(null)}
          />
        )}
      </AnimatePresence>
    </div>
  );
};

// Small avatar chip with a real presence dot (from /presence/{uid}) — used for the
// "Online Now" strip in the Friends tab. Pulled into its own component so each chip
// owns its own presence subscription instead of one listener per whole list re-render.
const OnlineFriendChip = ({ u, onClick }) => {
  const presence = usePresence(u.id);
  const isOnline = !!presence?.online;
  return (
    <div onClick={onClick} style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:5, flexShrink:0, width:56, cursor:'pointer' }}>
      <div style={{ position:'relative', width:48, height:48 }}>
        <div style={{ width:48, height:48, borderRadius:'50%', background:u.avatarColor||COLORS.brand, display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:700, fontSize:18, overflow:'hidden' }}>
          {u.avatarUrl ? <img loading="lazy" decoding="async" src={u.avatarUrl} style={{width:'100%',height:'100%',objectFit:'cover'}} alt=""/> : (u.avatar||u.username?.[0]||'?')}
        </div>
        {isOnline && <div style={{ position:'absolute', bottom:0, right:0, width:13, height:13, borderRadius:'50%', background:'#2ED573', border:`2.5px solid ${COLORS.bg}` }} />}
      </div>
      <div style={{ color:COLORS.textTertiary, fontSize:10.5, fontWeight:600, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis', maxWidth:56 }}>{isOnline ? 'Online' : (u.username||'').slice(0,8)}</div>
    </div>
  );
};


